### 3. The Core Logic: Fetching Products and Facets

In e-commerce, facets should update based on the current search results (e.g., if I search "Laptop," the "Brand" filter should only show laptop brands).

```typescript
// lib/products.ts
import { prisma } from "./prisma";

export async function getProducts(params: {
  query?: string;
  category?: string;
  brand?: string;
  minPrice?: number;
  maxPrice?: number;
  sort?: string;
}) {
  const { query, category, brand, minPrice, maxPrice, sort } = params;

  // 1. Build the Where clause
  const where: any = {
    AND: [
      query ? { name: { contains: query, mode: 'insensitive' } } : {},
      category ? { category } : {},
      brand ? { brand } : {},
      { price: { gte: minPrice || 0 } },
      maxPrice ? { price: { lte: maxPrice } } : {},
    ],
  };

  // 2. Execute Product Fetch and Facet Aggregation in parallel
  const [products, brands, categories, priceRange] = await Promise.all([
    prisma.product.findMany({
      where,
      orderBy: sort === 'price_asc' ? { price: 'asc' } : { createdAt: 'desc' },
    }),
    // Get unique brands and their counts based on current filters
    prisma.product.groupBy({
      by: ['brand'],
      where: { ...where, brand: undefined }, // Don't filter by brand for the brand list
      _count: true,
    }),
    prisma.product.groupBy({
      by: ['category'],
      where: { ...where, category: undefined },
      _count: true,
    }),
    prisma.product.aggregate({
      where,
      _min: { price: true },
      _max: { price: true },
    })
  ]);

  return { products, brands, categories, priceRange };
}
```

