### 4. The Frontend: Faceted Navigation

We'll use a **Client Component** for the sidebar interactions and a **Server Component** for data fetching.

#### The Filter Sidebar (Client Component)
This component updates the URL when users click filters.

```tsx
// components/FilterSidebar.tsx
'use client';

import { useRouter, useSearchParams } from 'next/navigation';
import { useCallback } from 'react';

export function FilterSidebar({ facets }: { facets: any }) {
  const router = useRouter();
  const searchParams = useSearchParams();

  const createQueryString = useCallback(
    (name: string, value: string) => {
      const params = new URLSearchParams(searchParams.toString());
      if (value) params.set(name, value);
      else params.delete(name);
      return params.toString();
    },
    [searchParams]
  );

  return (
    <aside className="w-64 space-y-8">
      <div>
        <h3 className="font-bold mb-4">Categories</h3>
        {facets.categories.map((cat: any) => (
          <label key={cat.category} className="flex items-center gap-2 mb-2 cursor-pointer">
            <input
              type="checkbox"
              checked={searchParams.get('category') === cat.category}
              onChange={() => router.push(`?${createQueryString('category', cat.category)}`)}
            />
            {cat.category} <span className="text-gray-400">({cat._count})</span>
          </label>
        ))}
      </div>

      {/* Repeat for Brands and Price Range Slider */}
    </aside>
  );
}
```

#### The Main Page (Server Component)
This is the entry point. Because it's a Server Component, it fetches data on the server and generates HTML, which is perfect for SEO.

```tsx
// app/products/page.tsx
