import { ProductGrid } from "@/components/ProductGrid";
import { FilterSidebar } from "@/components/FilterSidebar";
import { SearchBar } from "@/components/SearchBar";

export default async function ProductsPage({
  searchParams,
}: {
  searchParams: { [key: string]: string | string[] | undefined };
}) {
  const { products, brands, categories, priceRange } = await getProducts({
    query: searchParams.q as string,
    category: searchParams.category as string,
    brand: searchParams.brand as string,
    minPrice: Number(searchParams.minPrice),
    maxPrice: Number(searchParams.maxPrice),
  });

  return (
    <main className="max-w-7xl mx-auto p-6">
      <div className="flex gap-4 mb-8">
        <SearchBar />
      </div>

      <div className="flex gap-10">
        <FilterSidebar facets={{ brands, categories, priceRange }} />
        <div className="flex-1">
          <h1 className="text-2xl font-bold mb-6">{products.length} Products Found</h1>
          <ProductGrid products={products} />
        </div>
      </div>
    </main>
  );
}
