### 3. The Frontend: Faceted Navigation Component
We will use **Next.js SearchParams** to drive the state. This ensures the "Back" button works and the UI is bookmarkable.

#### The Filter Sidebar
```tsx
// components/search/FilterSidebar.tsx
'use client';

import { useRouter, useSearchParams, usePathname } from 'next/navigation';

interface Props {
  facets: Record<string, Record<string, number>>;
}

export default function FilterSidebar({ facets }: Props) {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();

  const toggleFilter = (key: string, value: string) => {
    const params = new URLSearchParams(searchParams.toString());
    const existingValues = params.getAll(key);

    if (existingValues.includes(value)) {
      // Remove filter if already exists
      const newValues = existingValues.filter((v) => v !== value);
      params.delete(key);
      newValues.forEach((v) => params.append(key, v));
    } else {
      // Add filter
      params.append(key, value);
    }

    router.push(`${pathname}?${params.toString()}`);
  };

  return (
    <aside className="w-64 space-y-8 p-4 border-r">
      {Object.entries(facets).map(([facetKey, values]) => (
        <div key={facetKey} className="space-y-2">
          <h3 className="font-bold capitalize">{facetKey}</h3>
          <ul className="space-y-1">
            {Object.entries(values).map(([value, count]) => (
              <li key={value} className="flex items-center gap-2">
                <input
                  type="checkbox"
                  checked={searchParams.getAll(facetKey).includes(value)}
                  onChange={() => toggleFilter(facetKey, value)}
                  id={`${facetKey}-${value}`}
                  className="rounded border-gray-300"
                />
                <label htmlFor={`${facetKey}-${value}`} className="text-sm cursor-pointer">
                  {value} <span className="text-gray-400">({count})</span>
                </label>
              </li>
            ))}
          </ul>
        </div>
      ))}
    </aside>
  );
}
```

