### 4. Search Results Page (The Orchestrator)
This is a **Server Component** that fetches data based on the current URL.

```tsx
// app/search/page.tsx
import { getProducts } from '@/lib/search-service';
import FilterSidebar from '@/components/search/FilterSidebar';
import ProductGrid from '@/components/search/ProductGrid';
import SearchBar from '@/components/search/SearchBar';

export default async function SearchPage({
  searchParams,
}: {
  searchParams: { [key: string]: string | string[] | undefined };
}) {
  // Convert URL params into a format the search engine understands
  // e.g., brand=Nike&brand=Adidas -> "brand = Nike OR brand = Adidas"
  const filterString = Object.entries(searchParams)
    .filter(([key]) => key !== 'q')
    .map(([key, val]) => {
      const values = Array.isArray(val) ? val : [val];
      return `(${values.map((v) => `${key} = "${v}"`).join(' OR ')})`;
    })
    .join(' AND ');

  const { hits, facetDistribution } = await getProducts({
    query: searchParams.q as string,
    filters: filterString,
  });

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <SearchBar initialQuery={searchParams.q as string} />

      <div className="flex gap-8 mt-8">
        <FilterSidebar facets={facetDistribution} />

        <main className="flex-1">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-xl font-semibold">Results ({hits.length})</h2>
            {/* Sort Dropdown would go here */}
          </div>

          <ProductGrid products={hits} />
        </main>
      </div>
    </div>
  );
}
