#### Step 2: The Search API (`app/api/search/route.ts`)
This is the core logic that builds the OpenSearch query.

```typescript
import { Client } from '@opensearch-project/opensearch';
import { NextResponse } from 'next/server';

const client = new Client({ node: 'http://localhost:9200' });

export async function POST(request: Request) {
  const { query, filters, sort } = await request.json();

  // 1. Build the Search Query
  const esQuery: any = {
    bool: {
      must: query ? [{ multi_match: { query, fields: ['name', 'description'] } }] : [{ match_all: {} }],
      filter: [],
    },
  };

  // 2. Add Filters (Facets)
  if (filters.brand?.length) {
    esQuery.bool.filter.push({ terms: { 'brand.keyword': filters.brand } });
  }
  if (filters.category?.length) {
    esQuery.bool.filter.push({ terms: { 'category.keyword': filters.category } });
  }
  if (filters.priceRange) {
    esQuery.bool.filter.push({
      range: { price: { gte: filters.priceRange[0], lte: filters.priceRange[1] } },
    });
  }

  try {
    const response = await client.search({
      index: 'products',
      body: {
        query: esQuery,
        // 3. Aggregations (Faceting)
        aggs: {
          all_brands: { terms: { field: 'brand.keyword', size: 10 } },
          all_categories: { terms: { field: 'category.keyword', size: 10 } },
          price_stats: { stats: { field: 'price' } },
        },
        sort: sort === 'price_asc' ? [{ price: 'asc' }] : sort === 'price_desc' ? [{ price: 'desc' }] : ['_score'],
      },
    });

    return NextResponse.json({
      products: response.body.hits.hits.map((hit: any) => ({ id: hit._id, ...hit._source })),
      facets: response.body.aggregations,
      total: response.body.hits.total.value,
    });
  } catch (error) {
    console.error(error);
    return NextResponse.json({ error: 'Search failed' }, { status: 500 });
  }
}
```

#### Step 3: The Frontend Components

**The Store Hook (`hooks/useSearch.ts`)**
Using `URLSearchParams` to keep the UI state in the URL (for shareable links).

```typescript
import { useRouter, useSearchParams } from 'next/navigation';

export function useSearch() {
  const router = useRouter();
  const searchParams = useSearchParams();

  const updateFilters = (key: string, value: any) => {
    const params = new URLSearchParams(searchParams.toString());
    if (Array.isArray(value)) {
      params.delete(key);
      value.forEach(v => params.append(key, v));
    } else {
      params.set(key, value);
    }
    router.push(`?${params.toString()}`);
  };

  return { searchParams, updateFilters };
}
