### 3. The Calculator Engine (`components/Calculator.tsx`)

This component handles the UI and logic for performing calculations.

```tsx
"use client";

import React, { useState } from 'react';
import { create, all } from 'mathjs';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { saveCalculation } from '@/app/actions';
import { Loader2 } from 'lucide-react';

const math = create(all);

export default function Calculator() {
  const [display, setDisplay] = useState("");
  const [serverName, setServerName] = useState("Production-Main");
  const [isSaving, setIsSaving] = useState(false);

  const calculate = async () => {
    try {
      const result = math.evaluate(display).toString();
      setIsSaving(true);
      await saveCalculation(serverName, display, result);
      setDisplay(result);
    } catch (error) {
      alert("Invalid expression");
    } finally {
      setIsSaving(false);
    }
  };

  const buttons = [
    "7", "8", "9", "/", 
    "4", "5", "6", "*", 
    "1", "2", "3", "-", 
    "0", ".", "C", "+"
  ];

  return (
    <Card className="w-full max-w-md mx-auto shadow-xl">
      <CardHeader>
        <CardTitle className="text-sm font-medium text-muted-foreground uppercase tracking-widest">
          Server Context
        </CardTitle>
        <Input 
          value={serverName} 
          onChange={(e) => setServerName(e.target.value)}
          placeholder="Enter Server Name..."
          className="font-bold text-lg"
        />
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="bg-slate-900 text-white p-6 rounded-lg text-right text-3xl font-mono min-h-[80px] break-all">
          {display || "0"}
        </div>

        <div className="grid grid-cols-4 gap-2">
          {buttons.map((btn) => (
            <Button
              key={btn}
              variant={btn === "C" ? "destructive" : "secondary"}
              onClick={() => btn === "C" ? setDisplay("") : setDisplay(prev => prev + btn)}
              className="h-14 text-xl"
            >
              {btn}
            </Button>
          ))}
          <Button 
            className="col-span-4 h-16 text-2xl bg-primary" 
            onClick={calculate}
            disabled={isSaving}
          >
            {isSaving ? <Loader2 className="animate-spin" /> : "="}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}
```

