Now, the main application:

```tsx
import React, { useState, useEffect, useMemo } from 'react';
import { Trash2, History, Save, X, Calculator as CalcIcon } from 'lucide-react';

// --- Types ---
interface Calculation {
  id: string;
  expression: string;
  result: string;
  label: string;
  timestamp: number;
}

const CalculatorApp: React.FC = () => {
  // State
  const [display, setDisplay] = useState('0');
  const [history, setHistory] = useState<Calculation[]>([]);
  const [currentLabel, setCurrentLabel] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Load history from LocalStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('calc_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  // Save history to LocalStorage whenever it changes
  useEffect(() => {
    localStorage.setItem('calc_history', JSON.stringify(history));
  }, [history]);

  // --- Logic ---
  const handleNumber = (num: string) => {
    setDisplay(prev => (prev === '0' ? num : prev + num));
  };

  const handleOperator = (op: string) => {
    const lastChar = display.slice(-1);
    if (['+', '-', '*', '/'].includes(lastChar)) {
      setDisplay(display.slice(0, -1) + op);
    } else {
      setDisplay(display + op);
    }
  };

  const calculate = () => {
    try {
      // Using Function constructor as a safer alternative to eval() 
      // for simple arithmetic expressions
      const result = new Function(`return ${display}`)().toString();

      const newEntry: Calculation = {
        id: Date.now().toString(),
        expression: display,
        result,
        label: currentLabel || 'Untitled Calculation',
        timestamp: Date.now()
      };

      setHistory([newEntry, ...history]);
      setDisplay(result);
      setCurrentLabel('');
    } catch (error) {
      setDisplay('Error');
      setTimeout(() => setDisplay('0'), 1500);
    }
  };

  const clear = () => {
    setDisplay('0');
    setCurrentLabel('');
  };

  const deleteHistoryItem = (id: string) => {
    setHistory(history.filter(item => item.id !== id));
  };

  return (
    <div className="flex h-screen bg-slate-900 text-white font-sans overflow-hidden">
      {/* Sidebar - History */}
      <div className={`fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} transition-transform duration-300 w-80 bg-slate-800 border-r border-slate-700 z-50 p-4 shadow-2xl lg:relative lg:translate-x-0`}>
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <History size={20} /> History
          </h2>
          <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden">
            <X size={24} />
          </button>
        </div>

        <div className="space-y-3 overflow-y-auto h-[calc(100vh-100px)] pr-2 custom-scrollbar">
          {history.length === 0 && (
            <p className="text-slate-500 text-center mt-10 italic">No saved calculations</p>
          )}
          {history.map((item) => (
            <div key={item.id} className="p-3 bg-slate-700/50 rounded-lg border border-slate-600 hover:border-blue-500 transition-colors group">
              <div className="flex justify-between items-start mb-1">
                <span className="text-xs font-semibold text-blue-400 uppercase tracking-wider">{item.label}</span>
                <button onClick={() => deleteHistoryItem(item.id)} className="opacity-0 group-hover:opacity-100 text-slate-400 hover:text-red-400 transition-opacity">
                  <Trash2 size={14} />
                </button>
              </div>
              <div className="text-sm text-slate-400 truncate">{item.expression}</div>
              <div className="text-lg font-mono font-bold text-white">= {item.result}</div>
              <div className="text-[10px] text-slate-500 mt-2">
                {new Date(item.timestamp).toLocaleString()}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Main Calculator Area */}
      <div className="flex-1 flex flex-col items-center justify-center p-4 relative">
        <button 
          onClick={() => setIsSidebarOpen(true)}
          className="lg:hidden absolute top-4 left-4 p-2 bg-slate-800 rounded-md"
        >
          <History size={24} />
        </button>

        <div className="w-full max-w-md bg-slate-800 p-6 rounded-3xl shadow-2xl border border-slate-700">
          {/* Label Input */}
          <div className="mb-4 relative">
            <input
              type="text"
              placeholder="Name this calculation (e.g. Server RAM)..."
              value={currentLabel}
              onChange={(e) => setCurrentLabel(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
            />
            <Save className="absolute right-3 top-2.5 text-slate-600" size={16} />
          </div>

          {/* Display */}
          <div className="bg-slate-900 p-6 rounded-2xl mb-6 text-right shadow-inner min-h-[100px] flex flex-col justify-end border border-slate-700">
            <div className="text-slate-500 text-sm mb-1 h-6">{currentLabel}</div>
            <div className="text-4xl font-mono font-bold truncate tracking-tighter">
              {display}
            </div>
          </div>

          {/* Keypad */}
          <div className="grid grid-cols-4 gap-3">
            {['AC', '(', ')', '/'].map(btn => (
              <button key={btn} onClick={btn === 'AC' ? clear : () => handleOperator(btn)} className="p-4 rounded-xl font-bold bg-slate-700 hover:bg-slate-600 text-blue-400 transition-all active:scale-95">
                {btn}
              </button>
            ))}
            {['7', '8', '9', '*'].map(btn => (
              <button key={btn} onClick={() => isNaN(Number(btn)) ? handleOperator(btn) : handleNumber(btn)} className="p-4 rounded-xl font-bold bg-slate-700 hover:bg-slate-600 transition-all active:scale-95">
                {btn}
              </button>
            ))}
            {['4', '5', '6', '-'].map(btn => (
              <button key={btn} onClick={() => isNaN(Number(btn)) ? handleOperator(btn) : handleNumber(btn)} className="p-4 rounded-xl font-bold bg-slate-700 hover:bg-slate-600 transition-all active:scale-95">
                {btn}
              </button>
            ))}
            {['1', '2', '3', '+'].map(btn => (
              <button key={btn} onClick={() => isNaN(Number(btn)) ? handleOperator(btn) : handleNumber(btn)} className="p-4 rounded-xl font-bold bg-slate-700 hover:bg-slate-600 transition-all active:scale-95">
                {btn}
              </button>
            ))}
            <button onClick={() => handleNumber('0')} className="col-span-2 p-4 rounded-xl font-bold bg-slate-700 hover:bg-slate-600 transition-all active:scale-95">0</button>
            <button onClick={() => handleNumber('.')} className="p-4 rounded-xl font-bold bg-slate-700 hover:bg-slate-600 transition-all active:scale-95">.</button>
            <button onClick={calculate} className="p-4 rounded-xl font-bold bg-blue-600 hover:bg-blue-500 text-white transition-all active:scale-95 shadow-lg shadow-blue-900/20">
              =
            </button>
          </div>
        </div>

        <p className="mt-8 text-slate-500 text-sm flex items-center gap-2">
          <CalcIcon size={14} /> Built for Server/Infrastructure Planning
        </p>
      </div>
    </div>
  );
};

export default CalculatorApp;
```

### Technical Decisions Explained

1.  **Safety vs. Convenience (`new Function`)**: Using `eval()` is generally dangerous because it can execute arbitrary code. In a production environment, I would typically use a library like `mathjs`. However, for this demo, `new Function()` scoped to the return of a string is a standard step up from `eval()` that handles basic arithmetic without external dependencies.
2.  **State Synchronization**: We use a "Side Effect" pattern with `useEffect`. Every time the `history` state changes, it pushes to `localStorage`. This ensures that even if the user accidentally closes the tab mid-calculation, their history is safe.
3.  **Responsive Design**: The history sidebar uses a "Drawer" pattern on mobile. It hides behind a hamburger/history icon on small screens but stays pinned on large screens (desktops), making it optimized for "Top Calculator" usage on high-res monitors.
4.  **UX Details**:
    *   **Active Scale**: Buttons use `active:scale-95` to provide haptic-like visual feedback.
    *   **Timestamping**: Every calculation is stored with a UNIX timestamp, allowing users to see *when* they calculated a specific server cost or spec.
    *   **Labels**: The naming field is positioned right above the display, encouraging users to "Document as they calculate."

