### 3. Server Actions (The Backend Logic)

Create `src/lib/actions.ts`. These functions run securely on the server.

```typescript
"use server"

import { revalidatePath } from "next/cache";
import { prisma } from "@/lib/db"; // Initialize prisma client in a separate file

export async function createMessage(formData: FormData) {
  const name = formData.get("name") as string;
  const content = formData.get("content") as string;

  await prisma.message.create({
    data: { name, content, status: "PENDING" },
  });

  revalidatePath("/");
}

export async function updateMessageStatus(id: string, status: "APPROVED" | "REJECTED") {
  await prisma.message.update({
    where: { id },
    data: { status },
  });
  revalidatePath("/admin");
  revalidatePath("/");
}
```

