### 3. Server Actions (`lib/actions.ts`)

Next.js Server Actions allow us to handle form submissions and moderation directly in the server environment.

```typescript
"use server";

import { revalidatePath } from "next/cache";
import prisma from "@/lib/prisma"; // Standard prisma client singleton
import { GuestbookSchema } from "./validations";

// Public: Submit a message
export async function submitEntry(data: unknown) {
  const result = GuestbookSchema.safeParse(data);
  if (!result.success) return { error: "Invalid input" };

  await prisma.guestbookEntry.create({
    data: {
      name: result.data.name,
      message: result.data.message,
      isApproved: false, // Moderation required
    },
  });

  revalidatePath("/");
  return { success: true };
}

// Admin: Toggle approval status
export async function toggleApproval(id: string, currentStatus: boolean) {
  // In production, add a check here: if (!session) throw Error
  await prisma.guestbookEntry.update({
    where: { id },
    data: { isApproved: !currentStatus },
  });
  revalidatePath("/admin");
  revalidatePath("/");
}

// Admin: Delete entry
export async function deleteEntry(id: string) {
  await prisma.guestbookEntry.delete({ where: { id } });
  revalidatePath("/admin");
}
```

