### 3. Customer View: Menu & Checkout
This page allows customers to browse and order.

```tsx
// app/page.tsx
'use client';
import { supabase } from '@/lib/supabase';
import { useCart } from '@/store/useCart';

export default function MenuPage() {
  const { addItem, items, clearCart } = useCart();

  const placeOrder = async () => {
    const total = items.reduce((acc, item) => acc + item.price * item.quantity, 0);

    // 1. Create Order
    const { data: order, error } = await supabase
      .from('orders')
      .insert([{ total_price: total, table_number: "5" }])
      .select()
      .single();

    if (order) {
      // 2. Create Order Items
      const lineItems = items.map(item => ({
        order_id: order.id,
        product_id: item.id,
        quantity: item.quantity
      }));
      await supabase.from('order_items').insert(lineItems);
      alert("Order placed!");
      clearCart();
    }
  };

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-8">Our Menu</h1>
      {/* List products here with "Add to Cart" buttons */}
      <button 
        onClick={placeOrder}
        className="fixed bottom-4 right-4 bg-green-600 text-white px-6 py-3 rounded-full shadow-lg"
      >
        Checkout (${items.reduce((a, b) => a + (b.price * b.quantity), 0)})
      </button>
    </div>
  );
}
