#### C. Kitchen Real-time Dashboard
`app/kitchen/page.tsx` - Where the restaurant sees orders.

```tsx
'use client'
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

export default function KitchenDashboard() {
  const [orders, setOrders] = useState<any[]>([]);

  useEffect(() => {
    // 1. Initial Fetch
    const fetchOrders = async () => {
      const { data } = await supabase
        .from('orders')
        .select('*')
        .neq('status', 'completed')
        .order('created_at', { ascending: false });
      setOrders(data || []);
    };
    fetchOrders();

    // 2. Real-time Subscription
    const channel = supabase
      .channel('order-updates')
      .on('postgres_changes', { event: '*', table: 'orders' }, (payload) => {
        if (payload.eventType === 'INSERT') {
          setOrders(prev => [payload.new, ...prev]);
          new Audio('/notification.mp3').play(); // Optional sound alert
        } else if (payload.eventType === 'UPDATE') {
          setOrders(prev => prev.map(o => o.id === payload.new.id ? payload.new : o));
        }
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const updateStatus = async (id: string, status: string) => {
    await supabase.from('orders').update({ status }).eq('id', id);
  };

  return (
    <div className="p-8 bg-gray-100 min-h-screen">
      <h1 className="text-3xl font-bold mb-8">Kitchen Orders</h1>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {orders.map(order => (
          <div key={order.id} className={`p-6 rounded-xl shadow-md bg-white border-l-8 ${
            order.status === 'pending' ? 'border-red-500' : 'border-yellow-500'
          }`}>
            <div className="flex justify-between mb-4">
              <h2 className="text-xl font-bold">{order.customer_name}</h2>
              <span className="text-sm text-gray-400">{new Date(order.created_at).toLocaleTimeString()}</span>
            </div>
            <ul className="mb-4">
              {order.items.map((item: any) => (
                <li key={item.id} className="flex justify-between">
                  <span>{item.quantity}x {item.name}</span>
                </li>
              ))}
            </ul>
            <div className="flex gap-2">
              {order.status === 'pending' && (
                <button onClick={() => updateStatus(order.id, 'preparing')} className="bg-yellow-500 text-white px-4 py-2 rounded">Start Preparing</button>
              )}
              {order.status === 'preparing' && (
                <button onClick={() => updateStatus(order.id, 'ready')} className="bg-green-500 text-white px-4 py-2 rounded">Mark Ready</button>
              )}
              <button onClick={() => updateStatus(order.id, 'completed')} className="text-gray-400 text-sm">Dismiss</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
```

---

### 3. Key Technical Implementation Details

1.  **Real-time via PostgreSQL Replication**: The `supabase.channel` code listens to the Write-Ahead Log (WAL) of the database. This means as soon as the `orders` table changes, the data is pushed to the client via WebSockets.
2.  **Optimistic UI (Bonus)**: For a production app, you would add an "Optimistic Update" where the kitchen UI updates immediately before the database confirms, making the app feel instantaneous.
3.  **JSONB Storage**: We store the items ordered as a `JSONB` column. This allows the order structure to be flexible (e.g., adding "no onions" notes) without needing a complex relational join every time we load the dashboard.

### 4. Next Steps for Production
1.  **Authentication**: Use Supabase Auth to protect the `/kitchen` route so only employees can access it.
2.  **Payments**: Integrate the **Stripe API**. The customer would pay on the frontend, and only after a successful webhook from Stripe would the order be inserted into the `orders` table.
3.  **Printing**: Use a library like `react-to-print` to allow the kitchen to print physical tickets to a thermal printer.
4.  **Deployment**: Push the code to **Vercel**. It's built by the same team behind Next.js and handles scaling automatically.

