#### C. The Image Upload Component (`/components/UploadModal.tsx`)
This component handles the file selection and uploading to the "images" bucket.

```tsx
'use client';
import { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { Camera } from 'lucide-react';

export default function UploadModal({ onUploadComplete }: { onUploadComplete: () => void }) {
  const [uploading, setUploading] = useState(false);

  async function uploadPhoto(event: React.ChangeEvent<HTMLInputElement>) {
    try {
      setUploading(true);
      const file = event.target.files?.[0];
      if (!file) return;

      const fileExt = file.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const filePath = `${fileName}`;

      // 1. Upload to Supabase Storage
      let { error: uploadError } = await supabase.storage
        .from('community-photos')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      // 2. Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('community-photos')
        .getPublicUrl(filePath);

      // 3. Save to Database
      const { error: dbError } = await supabase
        .from('posts')
        .insert([{ image_url: publicUrl, caption: 'New community photo!' }]);

      if (dbError) throw dbError;
      onUploadComplete();
    } catch (error) {
      alert('Error uploading photo!');
    } finally {
      setUploading(false);
    }
  }

  return (
    <div className="flex items-center justify-center p-4">
      <label className="cursor-pointer bg-blue-600 text-white px-4 py-2 rounded-full flex items-center gap-2 hover:bg-blue-700 transition">
        <Camera size={20} />
        <span>{uploading ? 'Uploading...' : 'Share a Photo'}</span>
        <input 
          type="file" 
          accept="image/*" 
          onChange={uploadPhoto} 
          disabled={uploading} 
          className="hidden" 
        />
      </label>
    </div>
  );
}
```

