### 6. The Post Upload Component
This component handles selecting a file, uploading to Supabase Storage, and saving the record to the database.

```tsx
// components/UploadPost.tsx
"use client";
import { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useUser } from '@clerk/nextjs';

export default function UploadPost({ onUploadComplete }: { onUploadComplete: () => void }) {
  const { user } = useUser();
  const [uploading, setUploading] = useState(false);
  const [caption, setCaption] = useState('');

  const upload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    try {
      setUploading(true);
      const file = e.target.files?.[0];
      if (!file || !user) return;

      // 1. Upload image to Supabase Bucket
      const fileExt = file.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const { data, error } = await supabase.storage
        .from('photos')
        .upload(fileName, file);

      if (error) throw error;

      // 2. Get Public URL
      const { data: { publicUrl } } = supabase.storage.from('photos').getPublicUrl(fileName);

      // 3. Save to Database
      await supabase.from('posts').insert({
        user_id: user.id,
        user_name: user.fullName || user.username,
        user_image: user.imageUrl,
        caption,
        image_url: publicUrl
      });

      setCaption('');
      onUploadComplete();
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="p-4 border rounded-xl bg-white shadow-sm mb-8">
      <textarea 
        placeholder="What's on your mind?" 
        className="w-full p-2 border-none focus:ring-0 text-lg"
        value={caption}
        onChange={(e) => setCaption(e.target.value)}
      />
      <input type="file" accept="image/*" onChange={upload} disabled={uploading} />
      {uploading && <p className="text-sm text-blue-500 mt-2">Posting...</p>}
    </div>
  );
}
```

