      // 2. Insert record into DB
      await supabase.from('posts').insert({
        user_id: user?.id,
        image_url: publicUrl,
        caption: caption
      });

      onComplete();
    }
    setLoading(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
