### 1. Database Schema (Prisma)

We define a composite index on `(companyId, slug)` to ensure that lookups are lightning-fast and that category names are unique *per company*, not globally.

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Company {
  id                String             @id @default(uuid())
  name              String
  domain            String             @unique
  createdAt         DateTime           @default(now())
  categoryTemplates CategoryTemplate[]

  @@index([domain])
}

model CategoryTemplate {
  id        String   @id @default(uuid())
  name      String
  slug      String
  companyId String
  company   Company  @relation(fields: [companyId], references: [id])
  createdAt DateTime @default(now())

  // Crucial for performance and multi-tenant integrity
  @@unique([companyId, slug])
  @@index([companyId])
}
```

