### 2. Tenant Onboarding Service

We use an event-driven approach. When a company is created, we emit a `CompanyCreatedEvent`. This allows the signup request to complete without waiting for the database seeding to finish.

#### The DTO (Data Transfer Object)
```typescript
// src/companies/dto/create-company.dto.ts
import { IsString, IsNotEmpty } from 'class-validator';

export class CreateCompanyDto {
  @IsString()
  @IsNotEmpty()
  name: string;

  @IsString()
  @IsNotEmpty()
  domain: string;
}
```

#### The Service
```typescript
// src/companies/companies.service.ts
import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { CreateCompanyDto } from './dto/create-company.dto';

@Injectable()
export class CompaniesService {
  private readonly logger = new Logger(CompaniesService.name);

  constructor(
    private prisma: PrismaService,
    private eventEmitter: EventEmitter2,
  ) {}

  async create(dto: CreateCompanyDto) {
    this.logger.log(`Creating company: ${dto.name}`);

    const company = await this.prisma.company.create({
      data: {
        name: dto.name,
        domain: dto.domain,
      },
    });

    // Emit event to trigger background seeding
    this.eventEmitter.emit('company.created', company.id);

    return company;
  }
}
```

