### 1. Database Schema (`prisma/schema.prisma`)

We will use a **Shared Database, Shared Schema** approach (Column-based isolation). This is the most cost-effective and common pattern for SaaS. We use a `companyId` to partition data.

```prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Company {
  id                String             @id @default(uuid())
  name              String
  slug              String             @unique
  createdAt         DateTime           @default(now())
  categories        CategoryTemplate[]

  // Indexing the company ID is crucial for multi-tenant performance
  @@index([id])
}

model CategoryTemplate {
  id        String   @id @default(uuid())
  name      String
  type      String   // e.g., "Accounting", "Inventory", "HR"
  companyId String
  company   Company  @relation(fields: [companyId], references: [id])

  // Compound index for fast lookups per tenant
  @@index([companyId, type])
}
```

