### 2. The Tenant Onboarding Service

The core of this feature is the `TenantService`. It uses a **Database Transaction**. If the category seeding fails, the company creation is rolled back, preventing "zombie tenants" in your database.

```typescript
// src/tenant/tenant.service.ts
import { Injectable, InternalServerErrorException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class TenantService {
  constructor(private prisma: PrismaService) {}

  // Default templates to be seeded for every new company
  private readonly DEFAULT_CATEGORIES = [
    { name: 'General Expenses', type: 'FINANCE' },
    { name: 'Marketing Material', type: 'MARKETING' },
    { name: 'Onboarding Flow', type: 'HR' },
    { name: 'Technical Support', type: 'OPERATIONS' },
  ];

  async registerNewCompany(dto: { name: string; slug: string }) {
    return this.prisma.$transaction(async (tx) => {
      // 1. Create the Company
      const company = await tx.company.create({
        data: {
          name: dto.name,
          slug: dto.slug,
        },
      });

      // 2. Dynamic Index Management (Optional/Advanced)
      // While Prisma handles standard indexes via migrations, 
      // sometimes you need specific BRIN or GIN indexes for new tenants.
      // Example: Creating a concurrent index if it doesn't exist.
      await tx.$executeRawUnsafe(
        `CREATE INDEX IF NOT EXISTS "idx_category_lookup_${company.id.replace(/-/g, '_')}" 
         ON "CategoryTemplate" ("companyId") WHERE "companyId" = '${company.id}';`
      );

      // 3. Seed default categories specific to this Company ID
      const seedData = this.DEFAULT_CATEGORIES.map((cat) => ({
        ...cat,
        companyId: company.id,
      }));

      await tx.categoryTemplate.createMany({
        data: seedData,
      });

      return {
        company,
        categoriesCreated: seedData.length,
      };
    }).catch((err) => {
      // Log error and throw a user-friendly exception
      console.error('Onboarding Failed:', err);
      throw new InternalServerErrorException('Failed to provision tenant resources.');
    });
  }
}
```

