### 2. The Onboarding Service (`src/services/tenant.service.ts`)

This service handles the business logic. We use a **Database Transaction** to ensure that if seeding the categories fails, the company creation is rolled back (Atomicity).

```typescript
import { PrismaClient, Company, Category } from '@prisma/client';

const prisma = new PrismaClient();

// Default templates to seed for every new company
const DEFAULT_CATEGORIES = [
  { name: 'Marketing' },
  { name: 'Sales' },
  { name: 'Engineering' },
  { name: 'Human Resources' }
];

export class TenantService {
  /**
   * Onboards a new company and seeds initial data.
   */
  async onboardCompany(name: string, slug: string): Promise<Company> {
    return prisma.$transaction(async (tx) => {
      // 1. Create the Company
      const company = await tx.company.create({
        data: {
          name,
          slug,
        },
      });

      // 2. Seed Default Categories specific to this Company ID
      const seedData = DEFAULT_CATEGORIES.map(cat => ({
        name: cat.name,
        companyId: company.id,
      }));

      await tx.category.createMany({
        data: seedData,
      });

      // Note: In a shared-schema model, indexes are pre-defined in the Prisma schema.
      // They are automatically maintained by PostgreSQL as new rows are inserted.

      return company;
    });
  }
}
```

