### 3. The API Controller (`src/controllers/tenant.controller.ts`)

We use `zod` to validate the input before it ever touches our database service.

```typescript
import { Request, Response } from 'express';
import { z } from 'zod';
import { TenantService } from '../services/tenant.service';

const tenantService = new TenantService();

const OnboardSchema = z.object({
  name: z.string().min(2).max(100),
  slug: z.string().lowercase().regex(/^[a-z0-9-]+$/),
});

export const onboardTenant = async (req: Request, res: Response) => {
  try {
    const { name, slug } = OnboardSchema.parse(req.body);

    const company = await tenantService.onboardCompany(name, slug);

    return res.status(201).json({
      message: 'Company onboarded successfully',
      data: company,
    });
  } catch (error: any) {
    if (error instanceof z.ZodError) {
      return res.status(400).json({ errors: error.errors });
    }

    // Handle unique constraint violations (e.g., duplicate slug)
    if (error.code === 'P2002') {
      return res.status(409).json({ error: 'Company slug or name already exists' });
    }

    console.error('Onboarding Error:', error);
    return res.status(500).json({ error: 'Internal Server Error' });
  }
};
```

