### 3. Secure Implementation: Server Actions

By using Next.js Server Actions, we perform data fetching and mutation on the server. We pull the `userId` directly from the auth session, never trusting the client to provide it.

```typescript
// lib/actions/patients.ts
"use server"

import { auth } from "@clerk/nextjs";
import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function createPatient(formData: FormData) {
  const { userId } = auth();

  if (!userId) throw new Error("Unauthorized");

  const firstName = formData.get("firstName") as string;
  const lastName = formData.get("lastName") as string;
  const phone = formData.get("phone") as string;

  // We explicitly hardcode the doctor_id from the AUTH session
  await prisma.patient.create({
    data: {
      firstName,
      lastName,
      phone,
      doctor_id: userId, // Tenant Isolation
      dateOfBirth: new Date(formData.get("dob") as string),
    },
  });

  revalidatePath("/patients");
}

export async function getMyPatients() {
  const { userId } = auth();
  if (!userId) return [];

  return await prisma.patient.findMany({
    where: { doctor_id: userId }, // Double-layer protection
    orderBy: { lastName: 'asc' }
  });
}
```

