### 1. Database Schema & Security Policy

The most critical part of your requirement is the **Data Isolation**. We will use a `doctor_id` column on every table and a Postgres policy to enforce isolation.

```sql
-- Create a table for Patients
CREATE TABLE patients (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  doctor_id UUID REFERENCES auth.users(id) NOT NULL DEFAULT auth.uid(),
  full_name TEXT NOT NULL,
  email TEXT,
  phone TEXT,
  date_of_birth DATE,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Create a table for Appointments
CREATE TABLE appointments (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  doctor_id UUID REFERENCES auth.users(id) NOT NULL DEFAULT auth.uid(),
  patient_id UUID REFERENCES patients(id) ON DELETE CASCADE NOT NULL,
  appointment_date TIMESTAMPTZ NOT NULL,
  notes TEXT,
  status TEXT DEFAULT 'scheduled',
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ENABLE ROW LEVEL SECURITY
ALTER TABLE patients ENABLE ROW LEVEL SECURITY;
ALTER TABLE appointments ENABLE ROW LEVEL SECURITY;

-- CREATE POLICIES (The "Secret Sauce")
-- This ensures a doctor can ONLY see/edit rows where their UID matches doctor_id
CREATE POLICY "Doctors can only access their own patients" 
ON patients FOR ALL 
USING (auth.uid() = doctor_id);

CREATE POLICY "Doctors can only access their own appointments" 
ON appointments FOR ALL 
USING (auth.uid() = doctor_id);
```

