### 2. Database Schema

The relational structure is key to ensuring votes and photo ownership are tracked correctly.

```sql
-- Profiles: Link to Auth users
create table profiles (
  id uuid references auth.users on delete cascade primary key,
  username text unique,
  avatar_url text
);

-- Events: The core container
create table events (
  id uuid default uuid_generate_v4() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  description text,
  creator_id uuid references profiles(id) not null,
  status text check (status in ('voting', 'confirmed', 'archived')) default 'voting'
);

-- Event Options: Specific times or places to vote on
create table event_options (
  id uuid default uuid_generate_v4() primary key,
  event_id uuid references events(id) on delete cascade,
  type text check (type in ('time', 'place')),
  value text not null -- e.g., "7:00 PM" or "Joe's Pizza"
);

-- Votes: Many-to-many relationship
create table votes (
  id uuid default uuid_generate_v4() primary key,
  option_id uuid references event_options(id) on delete cascade,
  user_id uuid references profiles(id) on delete cascade,
  unique(option_id, user_id)
);

-- Messages: Event-specific chat
create table messages (
  id uuid default uuid_generate_v4() primary key,
  event_id uuid references events(id) on delete cascade,
  user_id uuid references profiles(id),
  content text not null,
  created_at timestamp with time zone default timezone('utc'::text, now())
);

-- Photos: Shared album
create table photos (
  id uuid default uuid_generate_v4() primary key,
  event_id uuid references events(id) on delete cascade,
  user_id uuid references profiles(id),
  storage_path text not null,
  created_at timestamp with time zone default timezone('utc'::text, now())
);
