### 3. Key Feature Implementation

#### A. Real-time Chat Hook
Using Supabase Realtime, we can subscribe to new messages for a specific event ID.

```typescript
// hooks/useChat.ts
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

export function useChat(eventId: string) {
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    // 1. Fetch existing messages
    const fetchMessages = async () => {
      const { data } = await supabase
        .from('messages')
        .select('*, profiles(username, avatar_url)')
        .eq('event_id', eventId)
        .order('created_at', { ascending: true });
      if (data) setMessages(data);
    };

    fetchMessages();

    // 2. Subscribe to new messages
    const channel = supabase
      .channel(`event_chat:${eventId}`)
      .on('postgres_changes', { 
        event: 'INSERT', 
        schema: 'public', 
        table: 'messages',
        filter: `event_id=eq.${eventId}` 
      }, (payload) => {
        setMessages((prev) => [...prev, payload.new]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [eventId]);

  const sendMessage = async (content: string, userId: string) => {
    await supabase.from('messages').insert({ event_id: eventId, user_id: userId, content });
  };

  return { messages, sendMessage };
}
```

#### B. The Voting System
Friends can vote on multiple options. We calculate the counts in real-time.

```tsx
// components/VotingSection.tsx
export function VotingSection({ options, eventId, userId }) {
  const handleVote = async (optionId: string) => {
    // If vote exists, remove it (unvote), else add it
    const { data: existing } = await supabase
      .from('votes')
      .select()
      .eq('option_id', optionId)
      .eq('user_id', userId)
      .single();

    if (existing) {
      await supabase.from('votes').delete().eq('id', existing.id);
    } else {
      await supabase.from('votes').insert({ option_id: optionId, user_id: userId });
    }
  };

  return (
    <div className="space-y-4">
      {options.map((option) => (
        <button 
          key={option.id}
          onClick={() => handleVote(option.id)}
          className="w-full p-4 border rounded-lg flex justify-between items-center hover:bg-slate-50"
        >
          <span>{option.value}</span>
          <span className="bg-blue-100 px-3 py-1 rounded-full text-blue-600 font-bold">
            {option.votes_count}
          </span>
        </button>
      ))}
    </div>
  );
}
```

