Handling image uploads to the event bucket.

```typescript
// lib/uploadPhoto.ts
export async function uploadPhoto(eventId: string, userId: string, file: File) {
  const fileExt = file.name.split('.').pop();
  const fileName = `${Math.random()}.${fileExt}`;
