### 2. Implementation: The Voting Logic
In a production app, voting must feel instant. We use TanStack Query for "Optimistic Updates."

```tsx
// components/VotingSection.tsx
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';

export function VotingOption({ option, eventId }) {
  const queryClient = useQueryClient();

  const voteMutation = useMutation({
    mutationFn: async () => {
      const { data, error } = await supabase
        .from('votes')
        .insert({ option_id: option.id, user_id: currentUser.id });
      if (error) throw error;
    },
    onMutate: async () => {
      // Optimistically update the UI before the server responds
      await queryClient.cancelQueries(['options', eventId]);
      const previousOptions = queryClient.getQueryData(['options', eventId]);

      // Manually increment count in cache
      queryClient.setQueryData(['options', eventId], (old) => 
        old.map(opt => opt.id === option.id ? { ...opt, votes_count: opt.votes_count + 1 } : opt)
      );

      return { previousOptions };
    },
    onError: (err, newVote, context) => {
      queryClient.setQueryData(['options', eventId], context.previousOptions);
    }
  });

  return (
    <button onClick={() => voteMutation.mutate()} className="p-4 border rounded-lg flex justify-between">
      <span>{option.value}</span>
      <span className="font-bold">{option.votes_count}</span>
    </button>
  );
}
```

