### 3. Real-time Chat Component
Supabase Realtime allows us to listen for new inserts on the `messages` table and update the UI instantly.

```tsx
// components/EventChat.tsx
'use client';
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';

export default function EventChat({ eventId }) {
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    // 1. Fetch existing messages
    const fetchMessages = async () => {
      const { data } = await supabase
        .from('messages')
        .select('*')
        .eq('event_id', eventId)
        .order('created_at', { ascending: true });
      setMessages(data || []);
    };

    fetchMessages();

    // 2. Subscribe to new messages
    const channel = supabase
      .channel(`event-chat-${eventId}`)
      .on('postgres_changes', { 
          event: 'INSERT', 
          schema: 'public', 
          table: 'messages',
          filter: `event_id=eq.${eventId}` 
      }, (payload) => {
        setMessages((prev) => [...prev, payload.new]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [eventId]);

  return (
    <div className="flex flex-col h-[400px]">
      <div className="overflow-y-auto flex-1 p-4 space-y-2">
        {messages.map((m) => (
          <div key={m.id} className="bg-muted p-2 rounded max-w-[80%]">
            {m.content}
          </div>
        ))}
      </div>
      {/* Input component here */}
    </div>
  );
}
```

