### 4. Shared Photo Album
For the photo album, we use Supabase Storage. This requires a two-step process: uploading the file and saving the URL to the database.

```tsx
// lib/upload.ts
export async function uploadEventPhoto(file: File, eventId: string, userId: string) {
  const filePath = `${eventId}/${Date.now()}-${file.name}`;

  // 1. Upload to Storage Bucket
  const { data, error: uploadError } = await supabase.storage
    .from('event-photos')
    .upload(filePath, file);

  if (uploadError) return { error: uploadError };

  // 2. Get Public URL
  const { data: { publicUrl } } = supabase.storage
    .from('event-photos')
    .getPublicUrl(filePath);

  // 3. Save to Photos table
  const { error: dbError } = await supabase
    .from('photos')
    .insert({ event_id: eventId, user_id: userId, storage_url: publicUrl });

  return { error: dbError };
}
