### 2. Business Logic: The Availability Engine

This is the most critical part: calculating which slots are free by subtracting existing bookings from the general availability.

```typescript
// lib/availability-engine.ts
import { prisma } from "@/lib/db";
import { addMinutes, format, parse, startOfDay, isBefore } from "date-fns";

export async function getAvailableSlots(resourceId: string, date: Date) {
  const dayOfWeek = date.getDay();

  // 1. Get general availability for this day
  const rules = await prisma.availability.findMany({
    where: { resourceId, dayOfWeek }
  });

  // 2. Get existing bookings for this day
  const bookings = await prisma.booking.findMany({
    where: {
      resourceId,
      startTime: { gte: startOfDay(date) },
      endTime: { lte: addMinutes(startOfDay(date), 1440) },
      status: "CONFIRMED"
    }
  });

  const slots: Date[] = [];

  rules.forEach(rule => {
    let current = parse(rule.startTime, "HH:mm", date);
    const end = parse(rule.endTime, "HH:mm", date);

    while (isBefore(current, end)) {
      const slotEnd = addMinutes(current, 30); // 30-min increments

      // Check if this slot overlaps with any booking
      const isBooked = bookings.some(b => 
        (current >= b.startTime && current < b.endTime) ||
        (slotEnd > b.startTime && slotEnd <= b.endTime)
      );

      if (!isBooked) slots.push(new Date(current));
      current = slotEnd;
    }
  });

  return slots;
}
```

