### 3. The API Route: Secure Booking

When a user submits a booking, we must use a **Database Transaction** to prevent "Race Conditions" (where two users book the same slot simultaneously).

```typescript
// app/api/bookings/route.ts
import { prisma } from "@/lib/db";
import { Resend } from 'resend';

const resend = new Resend(process.env.RESEND_API_KEY);

export async function POST(req: Request) {
  const { resourceId, startTime, customerName, customerEmail } = await req.json();
  const endTime = addMinutes(new Date(startTime), 30);

  try {
    const result = await prisma.$transaction(async (tx) => {
      // 1. Check if the slot is still free (Double check)
      const existing = await tx.booking.findFirst({
        where: {
          resourceId,
          startTime: { lt: endTime },
          endTime: { gt: new Date(startTime) },
          status: "CONFIRMED"
        }
      });

      if (existing) throw new Error("Slot already taken");

      // 2. Create the booking
      return await tx.booking.create({
        data: { resourceId, startTime, endTime, customerName, customerEmail }
      });
    });

    // 3. Send Confirmation Email
    await resend.emails.send({
      from: 'bookings@yourdomain.com',
      to: customerEmail,
      subject: 'Booking Confirmed!',
      text: `Hi ${customerName}, your appointment is set for ${startTime}.`
    });

    return Response.json(result);
  } catch (error) {
    return Response.json({ error: "Booking failed" }, { status: 400 });
  }
}
```

