### 3. Core Logic: Availability Engine

The most complex part of a booking system is determining which slots are actually free. We calculate this by:
1.  Taking the base availability for a specific day.
2.  Splitting that day into chunks based on the service duration.
3.  Filtering out chunks that overlap with existing bookings.

```typescript
// lib/availability-engine.ts
import { addMinutes, format, parse, isWithinInterval, startOfDay, endOfDay } from "date-fns";

export async function getAvailableSlots(serviceId: string, date: Date) {
  const dayOfWeek = date.getDay();

  // 1. Fetch Service Rules and Existing Bookings
  const service = await db.service.findUnique({
    where: { id: serviceId },
    include: {
      availability: { where: { dayOfWeek } },
      bookings: {
        where: {
          startTime: { gte: startOfDay(date) },
          endTime: { lte: endOfDay(date) },
          status: "CONFIRMED"
        }
      }
    }
  });

  if (!service || service.availability.length === 0) return [];

  const slots: Date[] = [];

  // 2. Generate potential slots based on availability rules
  service.availability.forEach((rule) => {
    const start = parse(rule.startTime, "HH:mm", date);
    const end = parse(rule.endTime, "HH:mm", date);

    let currentSlot = start;
    while (addMinutes(currentSlot, service.duration) <= end) {
      const slotEnd = addMinutes(currentSlot, service.duration);

      // 3. Check for collisions
      const isOverlapping = service.bookings.some(booking => {
        return (
          isWithinInterval(currentSlot, { start: booking.startTime, end: booking.endTime }) ||
          isWithinInterval(slotEnd, { start: booking.startTime, end: booking.endTime })
        );
      });

      if (!isOverlapping) {
        slots.push(currentSlot);
      }
      currentSlot = addMinutes(currentSlot, service.duration);
    }
  });

  return slots;
}
```

