### 3. Core Logic: Preventing Double Bookings

In a production system, two users might try to book the last available slot at the exact same millisecond. We use a **Database Transaction** to ensure data integrity.

```typescript
// lib/actions/booking.ts
"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function createBooking(userId: string, slotId: string) {
  try {
    return await prisma.$transaction(async (tx) => {
      // 1. Get the slot and count current bookings with a row-level lock
      const slot = await tx.slot.findUnique({
        where: { id: slotId },
        include: { _count: { select: { bookings: true } } },
      });

      if (!slot) throw new Error("Slot not found");

      // 2. Check capacity
      if (slot._count.bookings >= slot.capacity) {
        throw new Error("This slot is already fully booked");
      }

      // 3. Create the booking
      const booking = await tx.booking.create({
        data: {
          slotId,
          userId,
          status: "CONFIRMED",
        },
      });

      revalidatePath("/bookings");
      return { success: true, booking };
    });
  } catch (error) {
    return { success: false, error: (error as Error).message };
  }
}
```

