### 4. Availability Logic (The "Schedule" Generator)

Hardcoding slots is inefficient. We generate slots dynamically based on a resource's working hours but filter them against existing bookings.

```typescript
// lib/availability.ts
import { addMinutes, format, isAfter, startOfDay } from "date-fns";

export async function getAvailableSlots(resourceId: string, date: Date) {
  // 1. Fetch existing bookings for this day
  const bookings = await prisma.booking.findMany({
    where: {
      slot: {
        resourceId,
        startTime: {
          gte: startOfDay(date),
          lt: addMinutes(startOfDay(date), 1440),
        },
      },
      status: "CONFIRMED",
    },
    include: { slot: true },
  });

  // 2. Define business hours (e.g., 9 AM - 5 PM)
  const slots = [];
  let currentPos = new Date(date.setHours(9, 0, 0, 0));
  const endPos = new Date(date.setHours(17, 0, 0, 0));

  while (isAfter(endPos, currentPos)) {
    const slotEnd = addMinutes(currentPos, 30); // 30 min slots

    // Check if any booking overlaps with this generated slot
    const isBooked = bookings.some(b => 
      b.slot.startTime.getTime() === currentPos.getTime()
    );

    if (!isBooked) {
      slots.push(new Date(currentPos));
    }
    currentPos = slotEnd;
  }

  return slots;
}
```

