CREATE TABLE events (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  title TEXT NOT NULL,
  description TEXT,
  event_date TIMESTAMP WITH TIME ZONE NOT NULL,
  capacity INTEGER NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- RSVPs table
CREATE TABLE rsvps (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  event_id UUID REFERENCES events(id) ON DELETE CASCADE,
  user_id UUID REFERENCES auth.users(id),
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  UNIQUE(event_id, user_id) -- Prevent duplicate RSVPs
);

-- A view to calculate remaining spots
CREATE VIEW event_details AS
SELECT 
  e.*,
  (SELECT COUNT(*) FROM rsvps r WHERE r.event_id = e.id) as rsvp_count,
  e.capacity - (SELECT COUNT(*) FROM rsvps r WHERE r.event_id = e.id) as spots_left
FROM events e;
```

