```tsx
'use client';

import { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Users, MapPin, Calendar, CheckCircle } from 'lucide-react';

interface EventProps {
  event: any;
  user: any;
}

export default function EventCard({ event, user }: EventProps) {
  const queryClient = useQueryClient();

  // Fetch real-time stats for this event
  const { data: stats } = useQuery({
    queryKey: ['event-stats', event.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('event_stats')
        .select('*')
        .eq('event_id', event.id)
        .single();
      if (error) throw error;
      return data;
    },
    initialData: event.event_stats,
    refetchInterval: 5000, // Poll every 5s for live updates
  });

  // Check if current user has already RSVP'd
  const { data: userRsvp } = useQuery({
    queryKey: ['user-rsvp', event.id, user?.id],
    queryFn: async () => {
      if (!user) return null;
      const { data } = await supabase
        .from('rsvps')
        .select('*')
        .eq('event_id', event.id)
        .eq('user_id', user.id)
        .single();
      return data;
    },
    enabled: !!user,
  });

  const rsvpMutation = useMutation({
    mutationFn: async () => {
      if (!user) throw new Error("Must be logged in");
      if (stats.spots_left <= 0) throw new Error("Event is full");

      const { error } = await supabase
        .from('rsvps')
        .insert([{ event_id: event.id, user_id: user.id }]);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['event-stats', event.id] });
      queryClient.invalidateQueries({ queryKey: ['user-rsvp', event.id] });
    },
    onError: (error: any) => {
      alert(error.message || "Failed to RSVP");
    }
  });

  const isFull = stats?.spots_left <= 0;
  const hasJoined = !!userRsvp;

  return (
    <div className="bg-white border rounded-xl overflow-hidden shadow-sm hover:shadow-md transition-shadow">
      <img 
        src={event.image_url || 'https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?w=800&q=80'} 
        alt={event.title}
        className="w-full h-48 object-cover"
      />
      <div className="p-5">
        <h3 className="text-xl font-bold mb-2">{event.title}</h3>

        <div className="space-y-2 mb-4 text-gray-600 text-sm">
          <div className="flex items-center gap-2">
            <Calendar size={16} />
            {new Date(event.date).toLocaleDateString()}
          </div>
          <div className="flex items-center gap-2">
            <MapPin size={16} />
            {event.location}
          </div>
          <div className="flex items-center gap-2 font-medium">
            <Users size={16} className={isFull ? "text-red-500" : "text-green-600"} />
            <span className={isFull ? "text-red-500" : "text-green-600"}>
              {stats?.spots_left} spots left (out of {event.capacity})
            </span>
          </div>
        </div>

        <button
          onClick={() => rsvpMutation.mutate()}
          disabled={isFull || hasJoined || !user || rsvpMutation.isPending}
          className={`w-full py-2 rounded-lg font-semibold transition-colors flex items-center justify-center gap-2 ${
            hasJoined 
              ? "bg-green-100 text-green-700 cursor-default" 
              : isFull 
              ? "bg-gray-100 text-gray-400 cursor-not-allowed"
              : "bg-indigo-600 text-white hover:bg-indigo-700"
          }`}
        >
          {hasJoined ? (
            <><CheckCircle size={18} /> You're going!</>
          ) : isFull ? (
            "Fully Booked"
          ) : rsvpMutation.isPending ? (
            "Processing..."
          ) : (
            "RSVP Now"
          )}
        </button>
        {!user && <p className="text-xs text-center mt-2 text-gray-400">Sign in to RSVP</p>}
      </div>
    </div>
  );
}
```

