### 2. The Logic: Handling Concurrent RSVPs

This is the most critical part of the app. We use a **Prisma Transaction** to:
1.  Check the current count of attendees.
2.  Compare it against capacity.
3.  Create the attendee record only if there is room.

Create a file: `app/actions/rsvp.ts`

```typescript
"use server"

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function rsvpToEvent(formData: FormData) {
  const eventId = formData.get("eventId") as string;
  const email = formData.get("email") as string;
  const name = formData.get("name") as string;

  try {
    const result = await prisma.$transaction(async (tx) => {
      // 1. Get event and current attendee count
      const event = await tx.event.findUnique({
        where: { id: eventId },
        include: { _count: { select: { attendees: true } } }
      });

      if (!event) throw new Error("Event not found");

      // 2. Check capacity
      if (event._count.attendees >= event.capacity) {
        throw new Error("Event is fully booked!");
      }

      // 3. Check for existing RSVP
      const existing = await tx.attendee.findUnique({
        where: { eventId_email: { eventId, email } }
      });
      if (existing) throw new Error("You already RSVP'd!");

      // 4. Create RSVP
      return await tx.attendee.create({
        data: { eventId, email, name }
      });
    });

    revalidatePath("/"); // Refresh the UI
    return { success: true };
  } catch (error: any) {
    return { success: false, error: error.message };
  }
}
```

