```tsx
// app/page.tsx
import { supabase } from '@/lib/supabase';
import BusinessCard from '@/components/BusinessCard';
import SearchBar from '@/components/SearchBar';
import CategoryFilter from '@/components/CategoryFilter';

export default async function DirectoryPage({
  searchParams,
}: {
  searchParams: { query?: string; category?: string };
}) {
  const query = searchParams.query || '';
  const category = searchParams.category || '';

  let dbQuery = supabase
    .from('businesses')
    .select('*, categories(name, slug)');

  // Apply Category Filter
  if (category) {
    dbQuery = dbQuery.eq('categories.slug', category);
  }

  // Apply Full-Text Search
  if (query) {
    dbQuery = dbQuery.textSearch('search_vector', query);
  }

  const { data: businesses, error } = await dbQuery;
  const { data: categories } = await supabase.from('categories').select('*');

  return (
    <main className="max-w-6xl mx-auto px-4 py-8">
      <header className="mb-10 text-center">
        <h1 className="text-4xl font-bold tracking-tight text-gray-900">Local Directory</h1>
        <p className="mt-4 text-lg text-gray-600">Find the best shops and services in town.</p>
      </header>

      <div className="flex flex-col md:flex-row gap-4 mb-8">
        <SearchBar />
        <CategoryFilter categories={categories || []} />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {businesses?.map((biz) => (
          <BusinessCard key={biz.id} business={biz} />
        ))}
        {businesses?.length === 0 && (
          <p className="col-span-full text-center py-10 text-gray-500">No businesses found.</p>
        )}
      </div>
    </main>
  );
}
