        {businesses?.map((biz) => (
          <BusinessCard key={biz.id} business={biz} />
        ))}
        {businesses?.length === 0 && (
          <p className="col-span-full text-center py-12 text-gray-500">
            No businesses found matching your criteria.
          </p>
        )}
      </div>
    </main>
  );
}
