### 3. Server Action: Send Follow-up (`app/actions/send-followup.ts`)

Server Actions allow us to call backend code (like sending emails) directly from our UI buttons.

```typescript
"use server"

import { Resend } from 'resend';
import { prisma } from '@/lib/prisma';
import FollowUpEmail from '@/emails/FollowUpEmail';

const resend = new Resend(process.env.RESEND_API_KEY);

export async function sendFollowUp(orderId: string) {
  const order = await prisma.order.findUnique({
    where: { id: orderId },
    include: { customer: true }
  });

  if (!order) throw new Error("Order not found");

  try {
    await resend.emails.send({
      from: 'Orders <orders@yourbusiness.com>',
      to: order.customer.email,
      subject: `How was order #${order.orderNumber}?`,
      react: FollowUpEmail({ 
        customerName: order.customer.name, 
        orderNumber: order.orderNumber 
      }),
    });

    await prisma.order.update({
      where: { id: orderId },
      data: { followUpSent: true }
    });

    return { success: true };
  } catch (error) {
    return { success: false, error };
  }
}
```

