#### Step 3: Order Action & Email Trigger (`src/app/actions.ts`)

This is a **Server Action** that creates an order and sends the email immediately (or you can trigger this via a cron job later).

```typescript
"use server"

import { prisma } from "@/lib/prisma";
import { Resend } from "resend";
import FollowUpEmail from "@/emails/FollowUpEmail";

const resend = new Resend(process.env.RESEND_API_KEY);

export async function createOrder(formData: FormData) {
  const email = formData.get("email") as string;
  const name = formData.get("name") as string;
  const amount = parseFloat(formData.get("amount") as string);

  // 1. Find or Create Customer
  const customer = await prisma.customer.upsert({
    where: { email },
    update: { name },
    create: { email, name },
  });

  // 2. Create Order
  const order = await prisma.order.create({
    data: {
      amount,
      customerId: customer.id,
    },
  });

  // 3. Send Follow-up Email
  try {
    await resend.emails.send({
      from: "orders@yourbusiness.com",
      to: email,
      subject: "Thanks for your order!",
      react: FollowUpEmail({ customerName: name, orderId: order.id }),
    });

    await prisma.order.update({
      where: { id: order.id },
      data: { followUpSent: true },
    });
  } catch (error) {
    console.error("Email failed to send", error);
  }
}
```

