### 3. Authentication Configuration (`src/lib/auth.ts`)

We'll use the **Credentials Provider** (Email/Password). In a real production app, you should also add Google/GitHub providers.

```typescript
import NextAuth from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import { PrismaAdapter } from "@auth/prisma-adapter";
import { db } from "@/lib/db"; // Simple file exporting new PrismaClient()
import bcrypt from "bcryptjs";

export const { handlers, auth, signIn, signOut } = NextAuth({
  adapter: PrismaAdapter(db),
  session: { strategy: "jwt" },
  providers: [
    CredentialsProvider({
      name: "Credentials",
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" }
      },
      async authorize(credentials) {
        if (!credentials?.email || !credentials?.password) return null;

        const user = await db.user.findUnique({
          where: { email: credentials.email as string }
        });

        if (!user || !user.password) return null;

        const isValid = await bcrypt.compare(credentials.password as string, user.password);
        return isValid ? user : null;
      }
    })
  ],
  callbacks: {
    async session({ session, token }) {
      if (token.sub && session.user) {
        session.user.id = token.sub;
      }
      return session;
    }
  }
});
```

### 4. Preferences API (`src/app/api/preferences/route.ts`)

This endpoint handles saving and fetching user settings.

```typescript
import { auth } from "@/lib/auth";
import { db } from "@/lib/db";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  const session = await auth();
  if (!session?.user) return new NextResponse("Unauthorized", { status: 401 });

  const { theme, newsletter, language } = await req.json();

  const preferences = await db.preference.upsert({
    where: { userId: session.user.id },
    update: { theme, newsletter, language },
    create: {
      userId: session.user.id,
      theme,
      newsletter,
      language
    }
  });

  return NextResponse.json(preferences);
}

export async function GET() {
  const session = await auth();
  if (!session?.user) return new NextResponse("Unauthorized", { status: 401 });

  const prefs = await db.preference.findUnique({
    where: { userId: session.user.id }
  });

  return NextResponse.json(prefs || { theme: "light", newsletter: false, language: "en" });
}
```

