      method: "POST",
      body: JSON.stringify(prefs),
    });
    setLoading(false);
    alert("Preferences saved!");
  };

  if (!session) return <p>Please log in to see preferences.</p>;

  return (
    <div className="p-6 max-w-md mx-auto bg-white rounded-xl shadow-md space-y-4 border">
      <h2 className="text-xl font-bold">User Preferences</h2>

      <div>
        <label className="block text-sm font-medium">Theme</label>
        <select 
          value={prefs.theme}
          onChange={(e) => setPrefs({...prefs, theme: e.target.value})}
          className="w-full p-2 border rounded"
        >
          <option value="light">Light</option>
          <option value="dark">Dark</option>
        </select>
      </div>

      <div className="flex items-center gap-2">
        <input 
          type="checkbox" 
          checked={prefs.newsletter}
          onChange={(e) => setPrefs({...prefs, newsletter: e.target.checked})}
        />
        <label className="text-sm">Subscribe to newsletter</label>
      </div>

      <button 
        onClick={handleSave}
        disabled={loading}
        className="w-full bg-blue-600 text-white py-2 rounded hover:bg-blue-700 disabled:opacity-50"
      >
        {loading ? "Saving..." : "Save Settings"}
      </button>
    </div>
  );
}
```

### 6. Key Technical Decisions & Production Considerations

1.  **Server Actions vs. API Routes:** For simplicity, I used an API route above. In a production Next.js app, I would recommend **Server Actions**. They eliminate the need for API endpoints and provide end-to-end type safety.
2.  **Upsert Logic:** When saving preferences, I used `db.preference.upsert`. This is crucial because it handles both the first-time creation and subsequent updates in one atomic operation, preventing database race conditions.
3.  **Security (Bcrypt):** We never store raw passwords. We use `bcryptjs` with a salt rounds of 12 (the industry standard) to hash passwords before they hit the database.
4.  **Session Strategy:** I chose `JWT` (JSON Web Tokens) for sessions. 
    *   *Why?* It scales better as it doesn't require a database lookup on every single page load, making the app much faster for the end user.
5.  **Data Validation:** In a production environment, you should use **Zod** to validate the `req.json()` data in the API route. This prevents "over-posting" attacks where a user might try to inject extra fields into your database.

### Next Steps for Deployment
1.  **Environment Variables:** Ensure `NEXTAUTH_SECRET`, `DATABASE_URL`, and `AUTH_TRUST_HOST` are set in your hosting provider (like Vercel).
2.  **Migrations:** Always use `npx prisma migrate deploy` in your CI/CD pipeline to update the database schema safely.
3.  **UI:** Wrap the application in a `SessionProvider` in your `layout.tsx` so all components can access the user's login state.

