### 2. The Core Metering Logic (Redis Lua Script)

To prevent "race conditions" (where two simultaneous requests both see 1 credit left and both proceed), we use a Lua script. This script runs inside Redis atomically.

```typescript
// src/lib/redis.ts
import Redis from 'ioredis';

export const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// Lua Script: 
// 1. Check if usage < limit
// 2. If yes, increment and return new value
// 3. If no, return -1 (blocked)
const METERING_SCRIPT = `
  local current_usage = tonumber(redis.call('GET', KEYS[1]) or "0")
  local limit = tonumber(ARGV[1])

  if current_usage >= limit then
    return -1
  else
    local new_usage = redis.call('INCR', KEYS[1])
    return new_usage
  end
`;

redis.defineCommand('checkAndIncrement', {
  numberOfKeys: 1,
  lua: METERING_SCRIPT,
});

// Extend types for TypeScript
declare module 'ioredis' {
  interface Redis {
    checkAndIncrement(key: string, limit: number): Promise<number>;
  }
}
```

