### 3. High-Performance Middleware

This Fastify middleware intercepts every request to check credits before allowing the request to proceed.

```typescript
// src/middleware/metering.ts
import { FastifyRequest, FastifyReply } from 'fastify';
import { redis } from '../lib/redis';
import { prisma } from '../lib/db';

export async function usageGuard(request: FastifyRequest, reply: FastifyReply) {
  const apiKey = request.headers['x-api-key'] as string;

  if (!apiKey) {
    return reply.status(401).send({ error: 'Missing API Key' });
  }

  // 1. Get Tenant Config (In production, cache this in Redis too)
  // For this demo, we assume the limit is cached in Redis for speed
  const tenantKey = `tenant:usage:${apiKey}`;
  const limitKey = `tenant:limit:${apiKey}`;

  let limit = await redis.get(limitKey);

  if (!limit) {
    // Cache miss: Load from Postgres
    const tenant = await prisma.tenant.findUnique({ where: { apiKey } });
    if (!tenant) return reply.status(403).send({ error: 'Invalid API Key' });

    limit = tenant.creditLimit.toString();
    await redis.set(limitKey, limit, 'EX', 3600); // Cache limit for 1 hour
  }

  // 2. Atomic Check and Increment
  const result = await redis.checkAndIncrement(tenantKey, parseInt(limit));

  if (result === -1) {
    return reply.status(429).send({
      error: 'Credit limit exceeded',
      limit: limit,
    });
  }

  // Add usage info to headers for the client
  reply.header('X-RateLimit-Limit', limit);
  reply.header('X-RateLimit-Remaining', parseInt(limit) - result);
}
```

