#### The Rate Limiter Middleware (`src/middleware/rateLimiter.ts`)
We use a **Lua Script** inside Redis. This is crucial because it ensures the "check-then-set" operation is **atomic**. Without this, two simultaneous requests from the same tenant could bypass the limit (a race condition).

```typescript
import { Request, Response, NextFunction } from 'express';
import Redis from 'ioredis';

const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// Lua script for atomic Token Bucket
// KEYS[1] = tenant_key
// ARGV[1] = refill_rate (tokens per second)
// ARGV[2] = bucket_capacity
// ARGV[3] = now (timestamp in seconds)
// ARGV[4] = cost (usually 1)
const LUA_TOKEN_BUCKET = `
  local bucket = redis.call('hmget', KEYS[1], 'tokens', 'last_refill')
  local tokens = tonumber(bucket[1])
  local last_refill = tonumber(bucket[2])

  local refill_rate = tonumber(ARGV[1])
  local capacity = tonumber(ARGV[2])
  local now = tonumber(ARGV[3])
  local cost = tonumber(ARGV[4])

  if tokens == nil then
    tokens = capacity
    last_refill = now
  else
    local elapsed = math.max(0, now - last_refill)
    tokens = math.min(capacity, tokens + (elapsed * refill_rate))
  end

  if tokens >= cost then
    tokens = tokens - cost
    redis.call('hmset', KEYS[1], 'tokens', tokens, 'last_refill', now)
    return {1, tokens} -- Allowed, remaining tokens
  else
    return {0, tokens} -- Denied, current tokens
  end
`;

interface RateLimitConfig {
  refillRate: number; // tokens per second
  capacity: number;   // max burst
}

// Tiered limits: Premium clients get more throughput
const TENANT_TIERS: Record<string, RateLimitConfig> = {
  'default': { refillRate: 5, capacity: 10 },
  'enterprise-client-1': { refillRate: 100, capacity: 500 },
};

export const rateLimiter = async (req: Request, res: Response, next: NextFunction) => {
  const tenantId = req.headers['x-tenant-id'] as string || 'anonymous';
  const config = TENANT_TIERS[tenantId] || TENANT_TIERS['default'];

  const key = `rate_limit:${tenantId}`;
  const now = Math.floor(Date.now() / 1000);

  try {
    // Execute Lua script
    const [allowed, remaining] = await redis.eval(
      LUA_TOKEN_BUCKET, 
      1, 
      key, 
      config.refillRate, 
      config.capacity, 
      now, 
      1
    ) as [number, number];

    res.setHeader('X-RateLimit-Remaining', remaining);

    if (allowed === 1) {
      next();
    } else {
      res.status(429).json({
        error: 'Too Many Requests',
        message: 'Tenant quota exceeded. Please try again later.',
        tenantId
      });
    }
  } catch (err) {
    console.error('Rate Limiter Error:', err);
    // In production, fail-open to ensure availability if Redis is down
    next();
  }
};
```

