**src/plugins/rateLimiter.ts**
```typescript
import { FastifyPluginCallback } from 'fastify';
import Redis from 'ioredis';

interface RateLimitOptions {
  redisUrl: string;
  limit: number;      // Max requests
  windowMs: number;   // Per time window (ms)
}

const rateLimiter: FastifyPluginCallback<RateLimitOptions> = (fastify, opts, done) => {
  const redis = new Redis(opts.redisUrl);

  // Lua script for Sliding Window Counter
  // KEYS[1] = tenant_key
  // ARGV[1] = window_ms
  // ARGV[2] = current_timestamp
  // ARGV[3] = max_requests
  const luaScript = `
    local window_start = tonumber(ARGV[2]) - tonumber(ARGV[1])
    redis.call('ZREMRANGEBYSCORE', KEYS[1], 0, window_start)
    local current_count = redis.call('ZCARD', KEYS[1])

    if current_count < tonumber(ARGV[3]) then
      redis.call('ZADD', KEYS[1], ARGV[2], ARGV[2])
      redis.call('PEXPIRE', KEYS[1], ARGV[1])
      return {1, current_count + 1}
    else
      return {0, current_count}
    end
  `;

  fastify.addHook('preHandler', async (request, reply) => {
    // 1. Identify the Tenant (In production, get this from a JWT or API Key)
    const tenantId = request.headers['x-tenant-id'] as string;

    if (!tenantId) {
      return reply.code(400).send({ error: 'Missing x-tenant-id header' });
    }

    const key = `ratelimit:tenant:${tenantId}`;
    const now = Date.now();

    // 2. Execute atomic check in Redis
    const [isAllowed, currentCount]: [number, number] = await redis.eval(
      luaScript,
      1,
      key,
      opts.windowMs,
      now,
      opts.limit
    ) as any;

    // 3. Set standard Rate-Limit headers
    reply.header('X-RateLimit-Limit', opts.limit);
    reply.header('X-RateLimit-Remaining', Math.max(0, opts.limit - currentCount));

    if (!isAllowed) {
      fastify.log.warn(`Tenant ${tenantId} exceeded rate limit.`);
      return reply.code(429).send({
        error: 'Too Many Requests',
        message: 'You have exceeded your allocated resource quota.',
        retryAfterMs: opts.windowMs
      });
    }
  });

  done();
};

export default rateLimiter;
```

