### 2. Implementation

#### Step 1: Redis Configuration
We use `ioredis` for its robust support of Lua scripts and promises.

```typescript
// src/services/redis.ts
import Redis from 'ioredis';

const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

// Define the sliding window Lua script
// This script takes: Key, Current Timestamp, Window Size (ms), and Limit
redis.defineCommand('limitRate', {
  numberOfKeys: 1,
  lua: `
    local key = KEYS[1]
    local now = tonumber(ARGV[1])
    local window = tonumber(ARGV[2])
    local limit = tonumber(ARGV[3])
    local clearBefore = now - window

    -- Remove old entries outside the current window
    redis.call('ZREMRANGEBYSCORE', key, 0, clearBefore)

    -- Get current count
    local count = redis.call('ZCARD', key)

    if count < limit then
        -- Add current request
        redis.call('ZADD', key, now, now)
        -- Set expiry to save memory
        redis.call('PEXPIRE', key, window)
        return {1, limit - count - 1}
    else
        return {0, 0}
    end
  `,
});

export default redis;
```

#### Step 2: Per-Tenant Middleware
This middleware identifies the tenant and applies their specific quota.

```typescript
// src/middleware/rateLimiter.ts
import { Request, Response, NextFunction } from 'express';
import redis from '../services/redis';

// In a real app, these would come from a DB or Cache
const TENANT_QUOTAS: Record<string, number> = {
  'company-a': 10,   // Low tier
  'company-b': 1000, // Enterprise tier
};

export const tenantRateLimiter = async (req: Request, res: Response, next: NextFunction) => {
  const tenantId = req.headers['x-tenant-id'] as string;

  if (!tenantId || !TENANT_QUOTAS[tenantId]) {
    return res.status(401).json({ error: 'Valid Tenant ID required' });
  }

  const limit = TENANT_QUOTAS[tenantId];
  const windowMs = 60000; // 1 minute window
  const now = Date.now();
  const key = `rate_limit:${tenantId}`;

  try {
    // Call our atomic Lua script
    // @ts-ignore (dynamic command from defineCommand)
    const [allowed, remaining] = await redis.limitRate(key, now, windowMs, limit);

    // Set standard RateLimit headers
    res.setHeader('X-RateLimit-Limit', limit);
    res.setHeader('X-RateLimit-Remaining', remaining);

    if (allowed === 1) {
      next();
    } else {
      res.status(429).json({
        error: 'Too Many Requests',
        message: `Tenant ${tenantId} has exceeded their quota.`
      });
    }
  } catch (err) {
    console.error('Rate Limiter Error:', err);
    next(); // Fail open in production to ensure availability
  }
};
```

