### 3. Backend Logic: The Safe Feed Query

The most efficient way to filter a feed is during the database fetch. Filtering on the frontend (client-side) is a security risk and causes "jumping" UI as items disappear after loading.

```typescript
// src/services/feed.service.ts
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const getSafeFeed = async (userId: string) => {
  // 1. Get the user's muted IDs and blocked keywords
  const userSettings = await prisma.user.findUnique({
    where: { id: userId },
    include: {
      mutedUsers: { select: { mutedId: true } },
      blockedKeywords: { select: { word: true } },
    },
  });

  if (!userSettings) throw new Error("User not found");

  const mutedIds = userSettings.mutedUsers.map((m) => m.mutedId);
  const keywords = userSettings.blockedKeywords.map((k) => k.word.toLowerCase());

  // 2. Fetch posts with exclusion logic
  return await prisma.post.findMany({
    where: {
      AND: [
        // Filter 1: Exclude muted users
        { authorId: { notIn: mutedIds } },

        // Filter 2: Exclude posts containing blocked keywords
        // Note: For large scale, use PostgreSQL Full-Text Search
        {
          NOT: {
            OR: keywords.map((word) => ({
              content: { contains: word, mode: 'insensitive' },
            })),
          },
        },
      ],
    },
    include: {
      author: { select: { username: true } },
    },
    orderBy: { createdAt: 'desc' },
  });
};
```

