### 2. The Core Logic: Safe Feed Service

This is where the filtering happens. We perform the filtering at the **query level**. This ensures that if a user requests 10 posts, they get 10 *safe* posts, not 10 posts with 4 hidden by the UI.

```typescript
// lib/feed-service.ts
import { prisma } from "@/lib/prisma";

export async function getSafeFeed(userId: string, limit = 20, cursor?: string) {
  // 1. Fetch user's blocked keywords and muted user IDs
  const [blockedKeywords, mutes] = await Promise.all([
    prisma.blockedKeyword.findMany({
      where: { userId },
      select: { word: true },
    }),
    prisma.mute.findMany({
      where: { muterId: userId },
      select: { mutedId: true },
    }),
  ]);

  const keywordList = blockedKeywords.map((k) => k.word);
  const mutedUserIds = mutes.map((m) => m.mutedId);

  // 2. Build the query
  // We exclude posts where:
  // - The author is in the muted list
  // - The content contains any of the keywords (case-insensitive)
  return prisma.post.findMany({
    take: limit,
    skip: cursor ? 1 : 0,
    cursor: cursor ? { id: cursor } : undefined,
    where: {
      AND: [
        // Filter out muted users
        { authorId: { notIn: mutedUserIds } },
        // Filter out keywords
        ...keywordList.map((word) => ({
          content: {
            not: {
              contains: word,
              mode: 'insensitive' as const,
            },
          },
        })),
      ],
    },
    orderBy: { createdAt: "desc" },
    include: {
      author: {
        select: { name: true, id: true },
      },
    },
  });
}
```

