  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id             String           @id @default(cuid())
  username       String           @unique
  posts          Post[]

  // Users this person has muted
  mutes          Mute[]           @relation("Muter")
  // People who have muted this person (internal use only)
  mutedBy        Mute[]           @relation("MutedUser")

  // Keywords this user wants to hide
  blockedKeywords BlockedKeyword[]
}

model Post {
  id        String   @id @default(cuid())
  content   String
  authorId  String
  author    User     @relation(fields: [authorId], references: [id])
  createdAt DateTime @default(now())
}

model Mute {
  id        String @id @default(cuid())
  muterId   String
  mutedId   String
  muter     User   @relation("Muter", fields: [muterId], references: [id])
  mutedUser User   @relation("MutedUser", fields: [mutedId], references: [id])

  @@unique([muterId, mutedId]) // Prevent duplicate mutes
}

model BlockedKeyword {
  id     String @id @default(cuid())
  word   String
  userId String
  user   User   @relation(fields: [userId], references: [id])

  @@unique([userId, word])
