### 2. The Logic: Safe Feed Query

Filtering should happen at the **Database Level**. Fetching all posts and filtering in JavaScript is inefficient (O(n) memory and CPU) and breaks pagination.

We will use Prisma's `NOT` operator to exclude:
1. Posts where the `authorId` is in the user's `mutes` list.
2. Posts where the `content` contains any of the user's `blockedKeywords`.

```typescript
// lib/feed.ts
import { prisma } from "@/lib/prisma";

export async function getSafeFeed(userId: string) {
  // 1. Fetch user settings (mutes and keywords)
  const userSettings = await prisma.user.findUnique({
    where: { id: userId },
    select: {
      mutes: { select: { mutedId: true } },
      blockedKeywords: { select: { word: true } },
    },
  });

  if (!userSettings) throw new Error("User not found");

  const mutedUserIds = userSettings.mutes.map((m) => m.mutedId);
  const keywords = userSettings.blockedKeywords.map((k) => k.word);

  // 2. Query posts with exclusion filters
  return await prisma.post.findMany({
    where: {
      AND: [
        // Exclude muted users
        { authorId: { notIn: mutedUserIds } },

        // Exclude posts containing any blocked keyword
        // Note: For a large number of keywords, consider using a Full-Text Search index
        {
          NOT: keywords.map((word) => ({
            content: {
              contains: word,
              mode: 'insensitive', // Ignore case
            },
          })),
        },
      ],
    },
    include: {
      author: {
        select: { username: true },
      },
    },
    orderBy: { createdAt: "desc" },
  });
}
```

