### 2. The Logic: Atomic Follow Action

In production, you must use a **Database Transaction**. This ensures that we never record a follow without incrementing the counter, or vice versa.

```typescript
// app/actions/follow.ts
import { prisma } from "@/lib/prisma";
import { pusherServer } from "@/lib/pusher";

export async function followUser(targetUserId: string, currentUserId: string) {
  try {
    // 1. Execute DB Transaction
    const updatedUser = await prisma.$transaction(async (tx) => {
      // Create the relationship
      await tx.follows.create({
        data: {
          followerId: currentUserId,
          followingId: targetUserId,
        },
      });

      // Increment the cached count atomically
      return await tx.user.update({
        where: { id: targetUserId },
        data: { followerCount: { increment: 1 } },
      });
    });

    // 2. Trigger Real-time Background Sync via Pusher
    // We don't "await" this if we want maximum speed for the user
    await pusherServer.trigger(`user-${targetUserId}`, "count-update", {
      newCount: updatedUser.followerCount,
    });

    return { success: true };
  } catch (error) {
    console.error("Follow failed", error);
    return { success: false };
  }
}
```

