### 3. The Frontend: Real-time Hook

We use an **Optimistic UI** pattern. The UI updates instantly when the user clicks, but we also subscribe to Pusher to handle updates from *other* users.

```tsx
// hooks/useFollowerCount.ts
"use client";
import { useEffect, useState } from "react";
import { pusherClient } from "@/lib/pusher-client";

export function useFollowerCount(userId: string, initialCount: number) {
  const [count, setCount] = useState(initialCount);

  useEffect(() => {
    // Subscribe to the specific user's channel
    const channel = pusherClient.subscribe(`user-${userId}`);

    channel.bind("count-update", (data: { newCount: number }) => {
      setCount(data.newCount);
    });

    return () => {
      pusherClient.unsubscribe(`user-${userId}`);
    };
  }, [userId]);

  return { count, setCount };
}
```

