// app/api/follow/route.ts
import { prisma } from "@/lib/db";
import { pusherServer } from "@/lib/pusher-server";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  const { followerId, followingId } = await req.json();

  try {
    // 1. Create the follow record
    await prisma.follows.create({
      data: { followerId, followingId }
    });

    // 2. Get the updated count
    const updatedCount = await prisma.follows.count({
      where: { followingId }
    });

    // 3. Trigger Real-time Sync via Pusher
    // Channel name is specific to the user being followed
    await pusherServer.trigger(`user-${followingId}`, "count-update", {
      newCount: updatedCount,
    });

    return NextResponse.json({ success: true });
  } catch (error) {
    return NextResponse.json({ error: "Already following" }, { status: 400 });
  }
}
