### 3. The Follow Button (Optimistic UI)
To make the app feel "Pro," we don't wait for the server. We increment the number locally, then sync.

```tsx
// components/FollowButton.tsx
'use client';

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';

export default function FollowButton({ targetUserId, currentUserId }: { targetUserId: string, currentUserId: string }) {
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: async (isFollowing: boolean) => {
      if (isFollowing) {
        await supabase.from('follows').delete().match({ follower_id: currentUserId, following_id: targetUserId });
      } else {
        await supabase.from('follows').insert({ follower_id: currentUserId, following_id: targetUserId });
      }
    },
    // OPTIMISTIC UPDATE:
    onMutate: async () => {
      // Cancel outgoing refetches so they don't overwrite our optimistic update
      await queryClient.cancelQueries({ queryKey: ['profile', targetUserId] });
      // This is where you'd manually tweak the local cache if needed
    },
    onError: (err) => {
      // Rollback or show toast
      console.error("Follow failed", err);
    }
  });

  return (
    <button 
      onClick={() => mutation.mutate(false)}
      className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
    >
      Follow
    </button>
  );
}
```

