Putting it all together in a Server Component.

```tsx
// app/profile/[id]/page.tsx
import { useFollowerCount } from '@/hooks/useFollowerCount';
import FollowButton from '@/components/FollowButton';

export default async function ProfilePage({ params }: { params: { id: string } }) {
  // Fetch initial data on the server
  const { data: profile } = await supabase
    .from('profiles')
    .select('*')
    .eq('id', params.id)
    .single();

  return <ProfileClientView profile={profile} />;
}

// Client component to handle the live state
function ProfileClientView({ profile }) {
  // This hook keeps the count in sync with the DB Trigger via WebSockets
  const liveCount = useFollowerCount(profile.id, profile.follower_count);

  return (
    <div className="p-8 max-w-md mx-auto border rounded-xl shadow-sm">
