**`src/App.tsx`**
```tsx
import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import axios from 'axios';
import { Calculator, Database, History, Server, Trash2 } from 'lucide-react';

const API_URL = 'http://localhost:3001/api';

export default function App() {
  const [display, setDisplay] = useState('');
  const [serverName, setServerName] = useState('Production-Node-01');
  const queryClient = useQueryClient();

  // Fetch History
  const { data: history } = useQuery({
    queryKey: ['history'],
    queryFn: () => axios.get(`${API_URL}/history`).then(res => res.data)
  });

  // Save Mutation
  const mutation = useMutation({
    mutationFn: (newCalc: any) => axios.post(`${API_URL}/calculate`, newCalc),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['history'] })
  });

  const handleCalculate = () => {
    try {
      // Use Function constructor for a safe evaluation of simple math
      const result = Function(`'use strict'; return (${display})`)();
      const payload = { expression: display, result: String(result), serverName };

      mutation.mutate(payload);
      setDisplay(String(result));
    } catch (e) {
      alert("Invalid expression");
    }
  };

  const addToDisplay = (val: string) => setDisplay(prev => prev + val);

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 p-8 font-sans">
      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left: Calculator UI */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-slate-800 p-6 rounded-2xl shadow-2xl border border-slate-700">
            <div className="flex items-center gap-2 mb-6 text-blue-400">
              <Calculator size={24} />
              <h1 className="text-xl font-bold tracking-tight">CloudCalc Pro</h1>
            </div>

            {/* Server Selector */}
            <div className="mb-4">
              <label className="text-xs font-semibold text-slate-400 uppercase mb-1 block">Context / Server Name</label>
              <div className="relative">
                <Server className="absolute left-3 top-2.5 text-slate-500" size={16} />
                <input 
                  value={serverName}
                  onChange={(e) => setServerName(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 pl-10 pr-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                />
              </div>
            </div>

            {/* Calculator Display */}
            <div className="bg-slate-950 p-4 rounded-lg mb-4 text-right">
              <div className="text-slate-500 text-sm h-6">{serverName}</div>
              <div className="text-3xl font-mono overflow-hidden">{display || '0'}</div>
            </div>

            {/* Buttons */}
            <div className="grid grid-cols-4 gap-2">
              {['7','8','9','/','4','5','6','*','1','2','3','-','0','.','C','+'].map(btn => (
                <button
                  key={btn}
                  onClick={() => btn === 'C' ? setDisplay('') : addToDisplay(btn)}
                  className={`p-4 rounded-lg font-bold transition-all ${
                    ['/','*','-','+'].includes(btn) 
                    ? 'bg-blue-600 hover:bg-blue-500' 
                    : btn === 'C' ? 'bg-red-900 hover:bg-red-800' : 'bg-slate-700 hover:bg-slate-600'
                  }`}
                >
                  {btn}
                </button>
              ))}
              <button 
                onClick={handleCalculate}
                className="col-span-4 bg-green-600 hover:bg-green-500 p-4 rounded-lg font-bold mt-2 transition-colors"
              >
                EXECUTE & SAVE
              </button>
            </div>
          </div>
        </div>

        {/* Right: History & Logs */}
        <div className="lg:col-span-2 bg-slate-800 rounded-2xl p-6 border border-slate-700 shadow-2xl">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-2 text-emerald-400">
              <History size={24} />
              <h2 className="text-xl font-bold tracking-tight">Calculation History</h2>
            </div>
