### 4. The Calculator UI Component

We will build a responsive calculator with a sidebar for history.

#### `components/Calculator.tsx`

```tsx
"use client";

import React, { useState } from 'react';
import { evaluate } from 'mathjs';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { History, Save, Delete } from 'lucide-react';

export default function Calculator() {
  const [display, setDisplay] = useState("");
  const [serverName, setServerName] = useState("Production-US-1");
  const queryClient = useQueryClient();

  // Mutation to save calculation
  const mutation = useMutation({
    mutationFn: async (newCalc: { expression: string, result: string, serverName: string }) => {
      const res = await fetch('/api/calculations', {
        method: 'POST',
        body: JSON.stringify(newCalc),
      });
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['history'] });
    },
  });

  const handleCalculate = () => {
    try {
      const result = evaluate(display).toString();
      mutation.mutate({ expression: display, result, serverName });
      setDisplay(result);
    } catch (error) {
      setDisplay("Error");
      setTimeout(() => setDisplay(""), 1500);
    }
  };

  const appendToDisplay = (value: string) => setDisplay(prev => prev + value);
  const clearDisplay = () => setDisplay("");

  const buttons = [
    '7', '8', '9', '/',
    '4', '5', '6', '*',
    '1', '2', '3', '-',
    '0', '.', '=', '+'
  ];

  return (
    <Card className="w-full max-w-md mx-auto shadow-2xl">
      <CardHeader className="space-y-1">
        <CardTitle className="text-2xl font-bold">TopCalc Pro</CardTitle>
        <div className="flex items-center gap-2">
          <Input 
            placeholder="Server/Project Name" 
            value={serverName}
            onChange={(e) => setServerName(e.target.value)}
            className="text-xs h-8"
          />
        </div>
      </CardHeader>
      <CardContent>
        <div className="bg-slate-100 dark:bg-slate-800 p-4 rounded-lg mb-4 text-right">
          <div className="text-sm text-muted-foreground h-5">{serverName}</div>
          <div className="text-3xl font-mono truncate">{display || "0"}</div>
        </div>

        <div className="grid grid-cols-4 gap-2">
          <Button variant="outline" className="col-span-3" onClick={clearDisplay}>Clear</Button>
          <Button variant="destructive" onClick={() => setDisplay(display.slice(0, -1))}><Delete className="w-4 h-4" /></Button>

          {buttons.map((btn) => (
            <Button
              key={btn}
              variant={isNaN(Number(btn)) && btn !== '.' ? "secondary" : "default"}
              className="text-lg h-14"
              onClick={() => btn === '=' ? handleCalculate() : appendToDisplay(btn)}
            >
              {btn}
            </Button>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}
```

