```typescript
import { create } from 'zustand';

interface CalcState {
  currentServer: string;
  setServer: (name: string) => void;
  history: any[];
  setHistory: (history: any[]) => void;
  addHistoryItem: (item: any) => void;
}

export const useStore = create<CalcState>((set) => ({
  currentServer: 'Default-Server',
  setServer: (name) => set({ currentServer: name }),
  history: [],
  setHistory: (history) => set({ history }),
  addHistoryItem: (item) => set((state) => ({ history: [item, ...state.history] })),
}));
