#### `app/api/history/route.ts` - The Persistence Layer
Using Next.js Route Handlers to interact with the database.

```typescript
import { createClient } from '@supabase/supabase-js';
import { NextResponse } from 'next/server';

const supabase = createClient(
  process.env.SUPABASE_URL!,
  process.env.SUPABASE_ANON_KEY!
);

export async function GET() {
  const { data } = await supabase
    .from('calculations')
    .select('*')
    .order('created_at', { ascending: false });
  return NextResponse.json(data);
}

export async function POST(req: Request) {
  const body = await req.json();
  const { expression, result, server_name } = body;

  const { data, error } = await supabase
    .from('calculations')
    .insert([{ expression, result, server_name }])
    .select();

  if (error) return NextResponse.json({ error: error.message }, { status: 400 });
  return NextResponse.json(data[0]);
}
```

#### `components/Calculator.tsx` - The Core Engine
This component handles the UI and the math logic.

```tsx
"use client";
import React, { useState } from 'react';
import * as math from 'mathjs';
import { useStore } from '@/lib/store';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

export default function Calculator() {
  const [display, setDisplay] = useState('');
  const { currentServer, setServer, addHistoryItem } = useStore();

  const handleCalculate = async () => {
    try {
      const result = math.evaluate(display).toString();

      // Save to DB via API
      const res = await fetch('/api/history', {
        method: 'POST',
        body: JSON.stringify({
          expression: display,
          result: result,
          server_name: currentServer
        })
      });

      const savedItem = await res.json();
      addHistoryItem(savedItem);
      setDisplay(result);
    } catch (err) {
      alert("Invalid Expression");
    }
  };

  return (
    <Card className="w-full max-w-md mx-auto bg-slate-900 text-white border-slate-700">
      <CardHeader>
        <CardTitle className="flex justify-between items-center">
          <span>Calculator</span>
          <Input 
            className="w-32 bg-slate-800 border-slate-600 text-xs" 
            placeholder="Server Name"
            value={currentServer}
            onChange={(e) => setServer(e.target.value)}
          />
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="text-right text-3xl mb-4 p-4 bg-black rounded font-mono h-16 flex items-center justify-end overflow-hidden">
          {display || "0"}
        </div>

        <div className="grid grid-cols-4 gap-2">
          {['7','8','9','/','4','5','6','*','1','2','3','-','0','.','=','+','C'].map((btn) => (
            <Button
              key={btn}
              onClick={() => {
                if (btn === '=') handleCalculate();
                else if (btn === 'C') setDisplay('');
                else setDisplay(prev => prev + btn);
              }}
              variant={['/','*','-','+','='].includes(btn) ? "default" : "secondary"}
              className={btn === '=' ? "col-span-2 bg-blue-600 hover:bg-blue-500" : ""}
            >
              {btn}
            </Button>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}
```

