### 1. The Database Schema (The Foundation)

We will use a "Shared Database, Shared Schema" approach with RLS. Every table will have a `company_id`.

```sql
-- 1. Create a table for Companies
CREATE TABLE companies (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  name TEXT NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 2. Extend the default Supabase Auth profiles
CREATE TABLE profiles (
  id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
  company_id UUID REFERENCES companies(id),
  full_name TEXT,
  role TEXT CHECK (role IN ('admin', 'employee')) DEFAULT 'employee'
);

-- 3. Equipment table
CREATE TABLE equipment (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  company_id UUID REFERENCES companies(id) NOT NULL,
  name TEXT NOT NULL,
  serial_number TEXT,
  status TEXT CHECK (status IN ('available', 'in_use', 'maintenance')) DEFAULT 'available',
  assigned_to UUID REFERENCES profiles(id),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 4. Enable Row Level Security
ALTER TABLE companies ENABLE ROW LEVEL SECURITY;
ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE equipment ENABLE ROW LEVEL SECURITY;

-- 5. Create RLS Policies (The "Magic" part)
-- This policy says: "Users can only see equipment where their company_id matches"
CREATE POLICY "Users can only see their company's equipment" ON equipment
  FOR ALL USING (
    company_id = (SELECT company_id FROM profiles WHERE id = auth.uid())
  );
```

