### 2. Implementation: The Signup Flow

When a user signs up, we need to create the `company` record first, then link the user to it.

```typescript
// app/auth/signup/route.ts
import { createRouteHandlerClient } from '@supabase/auth-helpers-nextjs';
import { cookies } from 'next/headers';

export async function POST(request: Request) {
  const { email, password, companyName } = await request.json();
  const supabase = createRouteHandlerClient({ cookies });

  // 1. Sign up the user
  const { data: authData, error: authError } = await supabase.auth.signUp({
    email,
    password,
  });

  if (authError) return Response.json({ error: authError.message }, { status: 400 });

  // 2. Create the company
  const { data: companyData } = await supabase
    .from('companies')
    .insert({ name: companyName })
    .select()
    .single();

  // 3. Update profile with company_id and admin role
  await supabase
    .from('profiles')
    .insert({
      id: authData.user!.id,
      company_id: companyData.id,
      role: 'admin'
    });

  return Response.json({ success: true });
}
```

