### 4. Admin Feature: Adding Employees

Admins need to invite or add employees. This involves inserting a record into the `profiles` table with the same `company_id` as the admin.

```typescript
// hooks/useAddEmployee.ts
export function useAddEmployee() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (newEmployee: { name: string, email: string }) => {
      // 1. Get current admin's company_id
      const { data: adminProfile } = await supabase
        .from('profiles')
        .select('company_id')
        .single();

      // 2. Insert new employee (In a real app, you'd use Supabase Auth Invites)
      const { error } = await supabase.from('profiles').insert({
        full_name: newEmployee.name,
        company_id: adminProfile.company_id,
        role: 'employee'
      });

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['employees'] });
    }
  });
}
```

