### 1. Database Schema & Security (The Core)

The most critical part of a multi-tenant app is the **Row Level Security (RLS)**. We will use a `company_id` on every table.

```sql
-- 1. Create Companies Table
CREATE TABLE companies (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  name TEXT NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 2. Extend Profiles (links users to companies)
CREATE TABLE profiles (
  id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
  company_id UUID REFERENCES companies(id),
  full_name TEXT,
  role TEXT CHECK (role IN ('admin', 'employee')) DEFAULT 'employee'
);

-- 3. Create Tools Table
CREATE TABLE tools (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  company_id UUID REFERENCES companies(id) NOT NULL,
  name TEXT NOT NULL,
  serial_number TEXT,
  status TEXT DEFAULT 'available', -- 'available', 'in-use', 'maintenance'
  assigned_to UUID REFERENCES profiles(id),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 4. ENABLE ROW LEVEL SECURITY
ALTER TABLE companies ENABLE ROW LEVEL SECURITY;
ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE tools ENABLE ROW LEVEL SECURITY;

-- 5. RLS POLICIES (The "Magic" Isolation)
-- Users can only see tools belonging to their company
CREATE POLICY "Users can only view their company's tools" 
ON tools FOR SELECT 
USING (company_id = (SELECT company_id FROM profiles WHERE id = auth.uid()));

CREATE POLICY "Admins can insert tools" 
ON tools FOR INSERT 
WITH CHECK (
  company_id = (SELECT company_id FROM profiles WHERE id = auth.uid()) 
  AND 
  'admin' = (SELECT role FROM profiles WHERE id = auth.uid())
);
```

