### 3. Handling Multi-Tenant Sign-Up

When a new user signs up, they either create a new company (as an Admin) or are invited to an existing one.

#### Registration Logic (`/app/auth/sign-up/route.ts`)
```typescript
export async function POST(request: Request) {
  const { email, password, companyName } = await request.json();
  const supabase = createRouteHandlerClient({ cookies });

  // 1. Create the Auth User
  const { data: authData, error: authError } = await supabase.auth.signUp({
    email,
    password,
  });

  if (authError) return ErrorResponse(authError.message);

  // 2. Create the Company
  const { data: company } = await supabase
    .from('companies')
    .insert({ name: companyName })
    .select()
    .single();

  // 3. Create the Profile linked to that company
  await supabase
    .from('profiles')
    .insert({
      id: authData.user.id,
      company_id: company.id,
      role: 'admin',
      full_name: 'Company Admin'
    });

  return SuccessResponse();
}
```

