### 2. Data Schema (Prisma)

The foundation of the app is the relationship between lessons, content blocks (text/video/quiz), and reviews.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum Role {
  STUDENT
  TEACHER
}

model User {
  id    String @id @default(cuid())
  clerkId String @unique
  role    Role   @default(STUDENT)
  reviews Review[]
  lessons Lesson[] // Lessons created if Teacher
}

model Lesson {
  id          String   @id @default(cuid())
  title       String
  description String?
  thumbnail   String?
  teacherId   String
  teacher     User     @relation(fields: [teacherId], references: [id])
  blocks      ContentBlock[]
  reviews     Review[]
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt
}

model ContentBlock {
  id        String   @id @default(cuid())
  type      String   // "TEXT", "VIDEO", "QUIZ"
  content   Json     // Stores text content, video URLs, or quiz JSON
  order     Int
  lessonId  String
  lesson    Lesson   @relation(fields: [lessonId], references: [id], onDelete: Cascade)
}

model Review {
  id        String   @id @default(cuid())
  rating    Int      // 1-5
  comment   String?
  studentId String
  student   User     @relation(fields: [studentId], references: [id])
  lessonId  String
  lesson    Lesson   @relation(fields: [lessonId], references: [id], onDelete: Cascade)
  createdAt DateTime @default(now())
}
