### 3. Key Feature: The Dynamic Lesson Renderer

Teachers need to mix content types. We use a "Block" system.

```tsx
// components/lessons/LessonRenderer.tsx
"use client";

import { useState } from "react";
import MuxPlayer from "@mux/mux-player-react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

interface Block {
  type: "TEXT" | "VIDEO" | "QUIZ";
  content: any;
}

export default function LessonRenderer({ blocks }: { blocks: Block[] }) {
  return (
    <div className="max-w-4xl mx-auto space-y-8 py-10">
      {blocks.sort((a, b) => a.order - b.order).map((block, idx) => (
        <div key={idx}>
          {block.type === "TEXT" && (
            <div className="prose prose-lg dark:prose-invert max-w-none" 
                 dangerouslySetInnerHTML={{ __html: block.content.html }} />
          )}

          {block.type === "VIDEO" && (
            <div className="aspect-video rounded-xl overflow-hidden border">
              <MuxPlayer playbackId={block.content.playbackId} />
            </div>
          )}

          {block.type === "QUIZ" && (
            <QuizBlock questions={block.content.questions} />
          )}
        </div>
      ))}
    </div>
  );
}

function QuizBlock({ questions }: { questions: any[] }) {
  const [currentAnswers, setCurrentAnswers] = useState<Record<number, number>>({});
  const [submitted, setSubmitted] = useState(false);

  return (
    <Card className="p-6 bg-slate-50 dark:bg-slate-900">
      <h3 className="text-xl font-bold mb-4">Knowledge Check</h3>
      {questions.map((q, qIdx) => (
        <div key={qIdx} className="mb-6 last:mb-0">
          <p className="font-medium mb-3">{q.question}</p>
          <div className="grid gap-2">
            {q.options.map((opt: string, oIdx: number) => (
              <Button
                key={oIdx}
                variant={currentAnswers[qIdx] === oIdx ? "default" : "outline"}
                className="justify-start"
                onClick={() => setCurrentAnswers({ ...currentAnswers, [qIdx]: oIdx })}
              >
                {opt}
              </Button>
            ))}
          </div>
        </div>
      ))}
      <Button 
        className="w-full mt-4" 
        onClick={() => setSubmitted(true)}
        disabled={Object.keys(currentAnswers).length < questions.length}
      >
        Submit Answers
      </Button>
    </Card>
  );
}
```

