### 2. Data Architecture (PostgreSQL)

To support lessons, quizzes, and reviews, we need a relational structure.

```sql
-- 1. Profiles (Extends Supabase Auth)
create table profiles (
  id uuid references auth.users on delete cascade primary key,
  full_name text,
  role text check (role in ('teacher', 'student')) default 'student'
);

-- 2. Lessons
create table lessons (
  id uuid default uuid_generate_v4() primary key,
  teacher_id uuid references profiles(id),
  title text not null,
  description text,
  content_text text,
  video_url text,
  created_at timestamp with time zone default now()
);

-- 3. Quizzes (Linked to Lessons)
create table quizzes (
  id uuid default uuid_generate_v4() primary key,
  lesson_id uuid references lessons(id) on delete cascade,
  question text not null,
  options jsonb, -- Array of strings: ["Option A", "Option B"...]
  correct_answer_index int not null
);

-- 4. Reviews
create table reviews (
  id uuid default uuid_generate_v4() primary key,
  lesson_id uuid references lessons(id) on delete cascade,
  student_id uuid references profiles(id),
  rating int check (rating >= 1 and rating <= 5),
  comment text,
  unique(lesson_id, student_id) -- Prevents multiple reviews from one student
);
```

