### 3. Core Implementation

#### A. The Lesson Viewer (Student View)
This component handles the mix of video, text, and the interactive quiz.

```tsx
// components/lessons/LessonContent.tsx
'use client'

import { useState } from 'react';
import ReactPlayer from 'react-player';
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

export default function LessonContent({ lesson, quizzes }) {
  const [quizState, setQuizState] = useState({ currentStep: 0, score: 0, finished: false });

  const handleAnswer = (index: number) => {
    const isCorrect = index === quizzes[quizState.currentStep].correct_answer_index;
    const nextStep = quizState.currentStep + 1;

    if (nextStep < quizzes.length) {
      setQuizState({ ...quizState, currentStep: nextStep, score: isCorrect ? quizState.score + 1 : quizState.score });
    } else {
      setQuizState({ ...quizState, finished: true, score: isCorrect ? quizState.score + 1 : quizState.score });
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6 space-y-8">
      {/* 1. Video Section */}
      {lesson.video_url && (
        <div className="aspect-video rounded-xl overflow-hidden shadow-lg">
          <ReactPlayer url={lesson.video_url} width="100%" height="100%" controls />
        </div>
      )}

      {/* 2. Text Content */}
      <article className="prose lg:prose-xl">
        <h1>{lesson.title}</h1>
        <p>{lesson.content_text}</p>
      </article>

      {/* 3. Interactive Quiz */}
      {!quizState.finished ? (
        <Card className="bg-slate-50">
          <CardHeader>
            <CardTitle>Quiz: Question {quizState.currentStep + 1}</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="mb-4 text-lg">{quizzes[quizState.currentStep].question}</p>
            <div className="grid gap-3">
              {quizzes[quizState.currentStep].options.map((opt, i) => (
                <Button key={i} variant="outline" onClick={() => handleAnswer(i)}>
                  {opt}
                </Button>
              ))}
            </div>
          </CardContent>
        </Card>
      ) : (
        <div className="p-6 bg-green-100 rounded-lg text-center">
          <h2 className="text-2xl font-bold">Quiz Complete!</h2>
          <p>You scored {quizState.score} out of {quizzes.length}</p>
        </div>
      )}
    </div>
  );
}
```

