### 3. Key Feature Implementation

#### A. The Countdown Timer Component
Artists need to build hype. This component handles the "Next Concert/Drop" logic.

```tsx
// components/Countdown.tsx
'use client';
import { useEffect, useState } from 'react';

export default function Countdown({ targetDate, label }: { targetDate: string, label: string }) {
  const [timeLeft, setTimeLeft] = useState({ days: 0, hours: 0, mins: 0, secs: 0 });

  useEffect(() => {
    const timer = setInterval(() => {
      const distance = new Date(targetDate).getTime() - new Date().getTime();
      if (distance < 0) {
        clearInterval(timer);
        return;
      }
      setTimeLeft({
        days: Math.floor(distance / (1000 * 60 * 60 * 24)),
        hours: Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        mins: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        secs: Math.floor((distance % (1000 * 60)) / 1000),
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [targetDate]);

  return (
    <div className="p-6 bg-black text-white rounded-xl border border-zinc-800">
      <h3 className="text-sm uppercase tracking-widest text-zinc-400 mb-4">{label}</h3>
      <div className="flex gap-4 text-3xl font-bold">
        <div>{timeLeft.days}d</div>
        <div>{timeLeft.hours}h</div>
        <div>{timeLeft.mins}m</div>
