### 2. The Countdown Component

A reusable, high-precision countdown timer for concerts and content drops.

```tsx
// components/CountdownTimer.tsx
'use client';
import { useState, useEffect } from 'react';

interface TimeLeft {
  days: number; hours: number; minutes: number; seconds: number;
}

export function CountdownTimer({ targetDate, title }: { targetDate: string, title: string }) {
  const [timeLeft, setTimeLeft] = useState<TimeLeft | null>(null);

  useEffect(() => {
    const calculate = () => {
      const difference = +new Date(targetDate) - +new Date();
      if (difference > 0) {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
          minutes: Math.floor((difference / 1000 / 60) % 60),
          seconds: Math.floor((difference / 1000) % 60),
        });
      }
    };

    const timer = setInterval(calculate, 1000);
    return () => clearInterval(timer);
  }, [targetDate]);

  if (!timeLeft) return <div className="animate-pulse bg-gray-200 h-20 rounded-lg" />;

  return (
    <div className="p-6 bg-black text-white rounded-xl shadow-xl text-center">
      <h3 className="text-sm uppercase tracking-widest mb-4 font-bold text-pink-500">{title}</h3>
      <div className="flex justify-center gap-4 text-3xl font-mono">
        {Object.entries(timeLeft).map(([unit, value]) => (
          <div key={unit} className="flex flex-col">
            <span>{value.toString().padStart(2, '0')}</span>
            <span className="text-[10px] uppercase">{unit}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
```

