### 3. Feature: Adding a Review & Tags

Using Next.js Server Actions to handle the logic.

```typescript
// app/actions/reviews.ts
"use server"
import { db } from "@/lib/db";
import { revalidatePath } from "next/cache";

export async function submitReview(formData: FormData) {
  const clubBookId = formData.get("clubBookId") as string;
  const rating = parseInt(formData.get("rating") as string);
  const content = formData.get("content") as string;
  const tags = (formData.get("tags") as string).split(",").map(t => t.trim());

  // 1. Create the Review
  await db.review.create({
    data: {
      rating,
      content,
      clubBookId,
      userId: "current-user-id", // Get from your Auth provider
    }
  });

  // 2. Add Tags (Upsert logic)
  if (tags.length > 0) {
    await Promise.all(tags.map(tag => 
      db.tag.upsert({
        where: { name_clubBookId: { name: tag, clubBookId } },
        update: {},
        create: { name: tag, clubBookId }
      })
    ));
  }

  revalidatePath(`/club/[slug]/book/[id]`);
}
```

