The core of the app relies on the relationships between Clubs, Books, and Reviews.

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Club {
  id          String   @id @default(cuid())
  name        String
  description String?
  ownerId     String
  reviews     Review[]
  createdAt   DateTime @default(now())
}

model Book {
  id        String   @id @default(cuid())
  title     String
  author    String
  coverUrl  String?
  tags      Tag[]    @relation("BookToTag")
  reviews   Review[]
}

model Review {
  id        String   @id @default(cuid())
  content   String   @db.Text
  rating    Int      @default(0)
  bookId    String
  book      Book     @relation(fields: [bookId], references: [id])
  clubId    String
  club      Club     @relation(fields: [clubId], references: [id])
  userId    String
  createdAt DateTime @default(now())
}

model Tag {
  id    String @id @default(cuid())
  name  String @unique
  books Book[] @relation("BookToTag")
}
