#### B. Review Submission (Server Action)
Using Next.js Server Actions to handle data mutations without needing a separate API route.

```ts
// app/actions/reviews.ts
"use server"
import { db } from "@/lib/db";
import { revalidatePath } from "next/cache";

export async function createReview(formData: FormData, clubId: string, bookId: string) {
  const content = formData.get("content") as string;
  const rating = parseInt(formData.get("rating") as string);
  const tagsString = formData.get("tags") as string; // comma separated

  const tags = tagsString.split(",").map(t => t.trim().toLowerCase());

  await db.review.create({
    data: {
      content,
      rating,
      clubId,
      bookId,
      userId: "user_current_id", // Obtained from Auth session
    }
  });

  // Connect tags to the book
  for (const tagName of tags) {
    await db.tag.upsert({
      where: { name: tagName },
      update: { books: { connect: { id: bookId } } },
      create: { name: tagName, books: { connect: { id: bookId } } },
    });
  }

  revalidatePath(`/clubs/${clubId}`);
}
```

