### 3. Key Feature: Adding a Review & Custom Tags

To handle the "Long Reviews" and "Custom Tags" requirement, we use a React Hook Form with a Zod schema.

#### `components/ReviewForm.tsx` (Logic Snippet)
```tsx
const reviewSchema = z.object({
  rating: z.number().min(1).max(5),
  content: z.string().min(50, "Reviews must be at least 50 characters."),
  tags: z.string().transform(val => val.split(',').map(s => s.trim().toLowerCase()))
});

export function ReviewForm({ bookId, clubId }: { bookId: string, clubId: string }) {
  // 1. Logic to handle submission
  const onSubmit = async (values: z.infer<typeof reviewSchema>) => {
    // Save Review
    await supabase.from('reviews').upsert({
      book_id: bookId,
      club_id: clubId,
      content: values.content,
      rating: values.rating
    });

    // Save Tags (handling many-to-many)
    for (const tagName of values.tags) {
      // 1. Insert tag if it doesn't exist
      const { data: tag } = await supabase.from('tags').upsert({ name: tagName }).select().single();
      // 2. Link tag to book and club
      await supabase.from('book_club_tags').upsert({
        book_id: bookId,
        club_id: clubId,
        tag_id: tag.id
      });
    }
  };

  return (
    /* Render UI using Shadcn Textarea for 'long reviews' 
       and a simple comma-separated input for tags */
    <form>...</form>
  );
}
```

