#### Order Dashboard Component (`/app/dashboard/page.tsx`)
This component fetches the order history and listens for real-time updates.

```tsx
'use client';
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';
import { Package, Clock, CheckCircle2, Truck } from 'lucide-react';

export default function OrderDashboard() {
  const [orders, setOrders] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchOrders();

    // REAL-TIME SUBSCRIPTION
    const channel = supabase
      .channel('order-updates')
      .on('postgres_changes', { 
        event: 'UPDATE', 
        schema: 'public', 
        table: 'orders' 
      }, (payload) => {
        // Update the specific order in the state when a change occurs
        setOrders(prev => prev.map(order => 
          order.id === payload.new.id ? { ...order, ...payload.new } : order
        ));
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  async function fetchOrders() {
    const { data, error } = await supabase
      .from('orders')
      .select(`
        *,
        order_items (*)
      `)
      .order('created_at', { ascending: false });

    if (!error) setOrders(data);
    setLoading(false);
  }

  if (loading) return <div className="p-8 text-center">Loading your orders...</div>;

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h1 className="text-3xl font-bold mb-8">My Order History</h1>
      <div className="space-y-6">
        {orders.map((order) => (
          <div key={order.id} className="bg-white border rounded-xl shadow-sm overflow-hidden">
            <div className="p-6 border-b bg-gray-50 flex justify-between items-center">
              <div>
                <p className="text-sm text-gray-500 uppercase font-semibold">Order ID</p>
                <p className="font-mono text-sm">{order.id.slice(0, 8)}...</p>
              </div>
              <StatusBadge status={order.status} />
            </div>

            <div className="p-6">
              <h3 className="font-semibold mb-4 text-gray-700">Items</h3>
              <ul className="space-y-3">
                {order.order_items.map((item: any) => (
                  <li key={item.id} className="flex justify-between items-center text-sm">
                    <span>{item.product_name} <span className="text-gray-400">x{item.quantity}</span></span>
                    <span className="font-medium">${(item.unit_price * item.quantity).toFixed(2)}</span>
                  </li>
                ))}
              </ul>
              <div className="mt-6 pt-4 border-t flex justify-between items-center">
                <span className="font-bold text-lg">Total</span>
                <span className="font-bold text-lg text-indigo-600">${order.total_amount}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function StatusBadge({ status }: { status: string }) {
  const styles: any = {
    pending: "bg-yellow-100 text-yellow-800 border-yellow-200",
    shipped: "bg-blue-100 text-blue-800 border-blue-200",
    delivered: "bg-green-100 text-green-800 border-green-200",
  };

  return (
    <span className={`px-3 py-1 rounded-full text-xs font-bold border flex items-center gap-2 ${styles[status] || 'bg-gray-100'}`}>
      {status === 'shipped' && <Truck size={14} />}
      {status === 'delivered' && <CheckCircle2 size={14} />}
      {status === 'pending' && <Clock size={14} />}
      {status.toUpperCase()}
    </span>
  );
}
```

