```tsx
import React, { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabase';
import { Package, Clock, CheckCircle2, Truck } from 'lucide-react';

interface Order {
  id: string;
  status: string;
  total_amount: number;
  created_at: string;
  order_items: any[];
}

export default function OrderHistory({ userId }: { userId: string }) {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchOrders();

    // REAL-TIME SUBSCRIPTION
    const channel = supabase
      .channel('order-updates')
      .on(
        'postgres_changes',
        { event: 'UPDATE', schema: 'public', table: 'orders' },
        (payload) => {
          setOrders((current) =>
            current.map((order) =>
              order.id === payload.new.id ? { ...order, status: payload.new.status } : order
            )
          );
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  const fetchOrders = async () => {
    const { data, error } = await supabase
      .from('orders')
      .select(`*, order_items(*)`)
      .eq('customer_id', userId)
      .order('created_at', { ascending: false });

    if (data) setOrders(data);
    setLoading(false);
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'Delivered': return <CheckCircle2 className="text-green-500" />;
      case 'Shipped': return <Truck className="text-blue-500" />;
      default: return <Clock className="text-amber-500" />;
    }
  };

  if (loading) return <div className="p-8 text-center">Loading your history...</div>;

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h1 className="text-2xl font-bold mb-6">Your Orders</h1>
      <div className="space-y-4">
        {orders.map((order) => (
          <div key={order.id} className="bg-white border rounded-lg shadow-sm overflow-hidden">
            <div className="p-4 bg-gray-50 border-b flex justify-between items-center">
              <div>
                <p className="text-xs text-gray-500 uppercase font-semibold">Order ID</p>
                <p className="font-mono text-sm">{order.id.slice(0, 8)}</p>
              </div>
              <div className="flex items-center gap-2 bg-white px-3 py-1 rounded-full border">
                {getStatusIcon(order.status)}
                <span className="font-medium">{order.status}</span>
              </div>
            </div>

            <div className="p-4">
              <table className="w-full">
                <thead>
                  <tr className="text-left text-xs text-gray-400 border-b">
                    <th className="pb-2">Item</th>
                    <th className="pb-2">Qty</th>
                    <th className="pb-2 text-right">Price</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {order.order_items.map((item: any) => (
                    <tr key={item.id} className="text-sm">
                      <td className="py-3 font-medium">{item.product_name}</td>
                      <td className="py-3">{item.quantity}</td>
                      <td className="py-3 text-right">${item.unit_price}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <div className="mt-4 pt-4 border-t flex justify-between items-center font-bold text-lg">
                <span>Total</span>
                <span>${order.total_amount}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
