### Phase 1: Database Schema
First, we enable the vector extension in PostgreSQL and set up our product table.

```sql
-- Enable the pgvector extension
create extension if not exists vector;

-- Create a table for our furniture catalog
create table furniture_items (
  id uuid primary key default uuid_generate_v4(),
  name text not null,
  sku text unique,
  price decimal,
  image_url text,
  -- CLIP models usually output 512 or 768 dimensions
  embedding vector(512) 
);

-- Create a similarity search function
create or replace function match_furniture (
  query_embedding vector(512),
  match_threshold float,
  match_count int
)
returns table (
  id uuid,
  name text,
  sku text,
  price decimal,
  image_url text,
  similarity float
)
language plpgsql
as $$
begin
  return query
  select
    furniture_items.id,
    furniture_items.name,
    furniture_items.sku,
    furniture_items.price,
    furniture_items.image_url,
    1 - (furniture_items.embedding <=> query_embedding) as similarity
  from furniture_items
  where 1 - (furniture_items.embedding <=> query_embedding) > match_threshold
  order by furniture_items.embedding <=> query_embedding
  limit match_count;
end;
$$;
```

