### Phase 2: The Logic (API Layer)
We need a way to turn an uploaded image into a vector. We'll use the `@xenova/transformers` library to run the CLIP model on the server side (Node.js), avoiding the latency of external API calls.

```typescript
// app/api/search/route.ts
import { NextResponse } from 'next/server';
import { pipeline } from '@xenova/transformers';
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_KEY!);

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const imageFile = formData.get('image') as Blob;

    // 1. Initialize the Vision Pipeline
    const visionModel = await pipeline('feature-extraction', 'Xenova/clip-vit-base-patch32');

    // 2. Convert Blob to Buffer for processing
    const arrayBuffer = await imageFile.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    // 3. Generate the Embedding
    // We use the 'image' processor of CLIP
    const output = await visionModel(buffer);
    const embedding = Array.from(output.data);

    // 4. Query Supabase using pgvector
    const { data: matches, error } = await supabase.rpc('match_furniture', {
      query_embedding: embedding,
      match_threshold: 0.5, // Adjust based on strictness
      match_count: 12,
    });

    if (error) throw error;

    return NextResponse.json(matches);
  } catch (err) {
    console.error(err);
    return NextResponse.json({ error: "Failed to process image" }, { status: 500 });
  }
}
```

