### 3. Implementation

#### A. The Vector Search Logic (Server-side)
This utility handles the conversion of an image into a vector and queries Pinecone.

```typescript
// lib/vector-search.ts
import { Pinecone } from '@pinecone-database/pinecone';
import Replicate from "replicate";

const pinecone = new Pinecone({ apiKey: process.env.PINECONE_API_KEY! });
const replicate = new Replicate({ auth: process.env.REPLICATE_API_TOKEN });

export async function findSimilarItems(imageBuffer: Buffer) {
  // 1. Generate Embedding using CLIP model
  // We use Replicate to run the model so we don't need a GPU locally
  const output = await replicate.run(
    "openai/clip:76113970b40e4e676100c6d705c5a452a229064c2438814777d94f26010530df",
    { input: { input_image: imageBuffer } }
  );

  const embedding = (output as any).embedding;

  // 2. Query Pinecone
  const index = pinecone.Index("furniture-catalog");
  const queryResponse = await index.query({
    vector: embedding,
    topK: 6,
    includeMetadata: true,
  });

  return queryResponse.matches.map(match => match.metadata);
}
```

