create extension if not exists vector;

-- Catalog table for furniture items
create table catalog_items (
  id uuid primary key default uuid_generate_v4(),
  name text not null,
  description text,
  price decimal(10, 2),
  image_url text not null,
  -- CLIP ViT-L/14 produces 768-dimensional vectors
  embedding vector(768),
  created_at timestamp with time zone default now()
);

-- Create a spatial index for fast similarity search
create index on catalog_items using ivfflat (embedding vector_cosine_ops)
with (lists = 100);
```

