### 3. The Backend API: Similarity Search

When a designer uploads a photo, we vectorize it and query Supabase using **Cosine Similarity**.

**`app/api/search/route.ts`**
```typescript
import { createClient } from '@supabase/supabase-js';
import { getImageEmbedding } from '@/lib/embeddings';

export async function POST(req: Request) {
  const formData = await req.formData();
  const file = formData.get('file') as File;

  // 1. Convert uploaded image to vector
  const userVector = await getImageEmbedding(file);

  const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_KEY!);

  // 2. RPC call to perform vector search
  // matches = (1 - (embedding <=> userVector))
  const { data: matches, error } = await supabase.rpc('match_furniture', {
    query_embedding: userVector,
    match_threshold: 0.5, // Sensitivity
    match_count: 10,      // Number of results
  });

  return Response.json(matches);
}
```

