**`lib/ai.ts`**
```typescript
import { OpenAI } from 'openai';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function generateEmbedding(text: string) {
  const response = await openai.embeddings.create({
    model: "text-embedding-3-small",
    input: text,
  });
  return response.data[0].embedding;
}
```

**`app/actions.ts`** (Server Action to save and find related)
```typescript
"use server"
import { prisma } from "@/lib/db";
import { generateEmbedding } from "@/lib/ai";

export async function saveMemory(content: string, url?: string) {
  const embedding = await generateEmbedding(content);
  const type = url?.includes('youtube.com') || url?.includes('youtu.be') ? 'video' : url ? 'link' : 'text';

  // 1. Save the memory
  // Note: Prisma doesn't support vector types natively for inserts yet, 
  // so we use a raw query for the embedding part or a separate helper.
  const memory = await prisma.$executeRawUnsafe(
    `INSERT INTO "Memory" (id, content, url, type, embedding, "createdAt") 
     VALUES (gen_random_uuid(), $1, $2, $3, $4, NOW()) RETURNING *`,
    content, url, type, embedding
  );

  // 2. Find related memories using Cosine Similarity
  // We look for items where the distance is small
  const related: any[] = await prisma.$queryRawUnsafe(`
    SELECT id, content, type, url, (embedding <=> $1::vector) as distance
    FROM "Memory"
    WHERE (embedding <=> $1::vector) < 0.5
    ORDER BY distance ASC
    LIMIT 5;
  `, `[${embedding.join(',')}]`);

  return { success: true, related: related.filter(r => r.distance > 0) };
}
```

