### 1. Database Schema (SQL)

Run this in your Supabase SQL Editor to enable the vector extension and create the necessary tables.

```sql
-- Enable the pgvector extension
create extension if not exists vector;

-- Create a table for our "brain" entries
create table entries (
  id uuid primary key default gen_random_uuid(),
  content text not null,               -- The text snippet or description
  source_url text,                     -- Original link if it's a web/video item
  title text,                          -- Scraped or user-provided title
  type text check (type in ('text', 'video', 'link')),
  embedding vector(1536),              -- Array for OpenAI embeddings
  created_at timestamp with time zone default now()
);

-- Create a function to search for related entries based on vector similarity
create or replace function match_entries (
  query_embedding vector(1536),
  match_threshold float,
  match_count int
)
returns table (
  id uuid,
  content text,
  title text,
  type text,
  source_url text,
  similarity float
)
language plpgsql
as $$
begin
  return query
  select
    entries.id,
    entries.content,
    entries.title,
    entries.type,
    entries.source_url,
    1 - (entries.embedding <=> query_embedding) as similarity
  from entries
  where 1 - (entries.embedding <=> query_embedding) > match_threshold
  order by entries.embedding <=> query_embedding
  limit match_count;
end;
$$;
```

