### 3. Server Action: Saving & Finding Related Items

This is the "Brain" of the app. When you save a note, it immediately looks for relatives.

```typescript
// app/actions.ts
'server-actions'
import { createClient } from '@supabase/supabase-js';
import { generateEmbedding } from '@/lib/openai';

const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!);

export async function saveEntry(formData: FormData) {
  const content = formData.get('content') as string;
  const url = formData.get('url') as string;
  const type = url ? (url.includes('youtube.com') ? 'video' : 'link') : 'text';

  // 1. Generate the embedding for the new content
  const embedding = await generateEmbedding(content);

  // 2. Save to Supabase
  const { data: newEntry, error } = await supabase
    .from('entries')
    .insert({
      content,
      source_url: url,
      type,
      embedding,
      title: url ? "New Link" : "Note" // In production, you'd scrape the title here
    })
    .select()
    .single();

  if (error) throw new Error(error.message);

  // 3. Find related items using our SQL function
  const { data: related } = await supabase.rpc('match_entries', {
    query_embedding: embedding,
    match_threshold: 0.5, // 50% similarity
    match_count: 5,
  });

  // Filter out the item we just added
  return {
    entry: newEntry,
    related: related?.filter(r => r.id !== newEntry.id) || []
  };
}
```

