### 3. The API: Saving and Finding Related Notes

When a note is saved, we generate its embedding and then immediately query the database for the 5 most similar notes using **cosine similarity**.

```typescript
// app/api/notes/route.ts
import { prisma } from "@/lib/prisma";
import { generateEmbedding } from "@/lib/openai";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  const { content, title, url, type } = await req.json();

  // 1. Generate the embedding for the new note
  const embedding = await generateEmbedding(content);

  // 2. Save the note using a raw SQL query (Prisma doesn't fully support vector inserts yet)
  const embeddingSql = `[${embedding.join(',')}]`;

  const savedNote = await prisma.$queryRaw`
    INSERT INTO "Note" (id, content, title, url, type, embedding, "updatedAt")
    VALUES (gen_random_uuid(), ${content}, ${title}, ${url}, ${type}, ${embeddingSql}::vector, now())
    RETURNING id, content, title;
  `;

  // 3. Find related notes using Cosine Similarity
  // The <=> operator is pgvector's cosine distance operator
  const relatedNotes = await prisma.$queryRaw`
    SELECT id, title, content, type, (embedding <=> ${embeddingSql}::vector) as distance
    FROM "Note"
    WHERE id != ${(savedNote as any)[0].id}
    ORDER BY distance ASC
    LIMIT 5;
  `;

  return NextResponse.json({ note: savedNote, related: relatedNotes });
}
```

