### 2. Backend Logic (API Routes)

#### Create/Send Message (`app/api/chat/route.ts`)
This route handles saving user messages, calling OpenAI, and saving the assistant response.

```typescript
import { NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import OpenAI from 'openai';

const prisma = new PrismaClient();
const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function POST(req: Request) {
  const { message, sessionId } = await req.json();

  // 1. Find or Create Session
  let session = sessionId 
    ? await prisma.chatSession.findUnique({ where: { id: sessionId } })
    : await prisma.chatSession.create({ data: { title: message.substring(0, 30) } });

  if (!session) return NextResponse.json({ error: "Session not found" }, { status: 404 });

  // 2. Save User Message
  await prisma.message.create({
    data: { role: 'user', content: message, chatSessionId: session.id }
  });

  // 3. Get AI Response
  const completion = await openai.chat.completions.create({
    model: "gpt-4o-mini",
    messages: [{ role: "user", content: message }],
  });

  const aiContent = completion.choices[0].message.content || "";

  // 4. Save AI Message
  const savedAiMessage = await prisma.message.create({
    data: { role: 'assistant', content: aiContent, chatSessionId: session.id }
  });

  return NextResponse.json({ sessionId: session.id, message: savedAiMessage });
}
```

#### Search Sessions (`app/api/sessions/route.ts`)
This route allows searching through chat titles and message contents.

```typescript
export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const query = searchParams.get('q') || "";

  const sessions = await prisma.chatSession.findMany({
    where: {
      OR: [
        { title: { contains: query, mode: 'insensitive' } },
        { messages: { some: { content: { contains: query, mode: 'insensitive' } } } }
      ]
    },
    orderBy: { updatedAt: 'desc' },
    include: { messages: { take: 1 } } // Preview of last message
  });

  return NextResponse.json(sessions);
}
```

