### 2. Server Action: Chat Logic (`app/actions.ts`)

This handles saving messages to the database and interacting with the LLM.

```typescript
"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function createSession() {
  const session = await prisma.chatSession.create({
    data: { title: "New Chat" },
  });
  return session.id;
}

export async function saveMessage(sessionId: string, role: 'user' | 'assistant', content: string) {
  await prisma.message.create({
    data: {
      sessionId,
      role,
      content,
    },
  });

  // Update session title if it's the first message
  if (role === 'user') {
    const messageCount = await prisma.message.count({ where: { sessionId } });
    if (messageCount === 1) {
      await prisma.chatSession.update({
        where: { id: sessionId },
        data: { title: content.substring(0, 40) + "..." },
      });
    }
  }

  revalidatePath("/");
}

export async function getSessions(search?: string) {
  return prisma.chatSession.findMany({
    where: search ? {
      OR: [
        { title: { contains: search } },
        { messages: { some: { content: { contains: search } } } }
      ]
    } : undefined,
    orderBy: { updatedAt: 'desc' },
  });
}
```

