### 2. The AI Edge Route (`app/api/chat/route.ts`)

This route handles the streaming and persists messages to the database.

```typescript
import { openai } from '@ai-sdk/openai';
import { streamText, convertToCoreMessages } from 'ai';
import { prisma } from '@/lib/prisma';

export async function POST(req: Request) {
  const { messages, sessionId } = await req.json();

  // 1. Get the last message (user's prompt)
  const lastMessage = messages[messages.length - 1];

  // 2. Persist the user message to the DB
  await prisma.message.create({
    data: {
      content: lastMessage.content,
      role: 'user',
      sessionId: sessionId,
    },
  });

  // 3. Request a streaming completion from OpenAI
  const result = await streamText({
    model: openai('gpt-4o-mini'),
    messages: convertToCoreMessages(messages),
    onFinish: async (event) => {
      // 4. Persist the assistant's full response once finished
      await prisma.message.create({
        data: {
          content: event.text,
          role: 'assistant',
          sessionId: sessionId,
        },
      });

      // Update session timestamp
      await prisma.session.update({
        where: { id: sessionId },
        data: { updatedAt: new Date() }
      });
    },
  });

  return result.toDataStreamResponse();
}
```

