### 1. Database Schema
We need to track `Documents` (PDF metadata), `DocumentChunks` (the vector data), and `Messages` (chat history).

```sql
-- Enable pgvector extension
create extension if not exists vector;

-- Table for uploaded PDF metadata
create table documents (
  id uuid primary key default uuid_generate_v4(),
  name text not null,
  storage_path text not null,
  user_id uuid references auth.users(id),
  created_at timestamp with time zone default now()
);

-- Table for vector chunks
create table document_sections (
  id uuid primary key default uuid_generate_v4(),
  document_id uuid references documents(id) on delete cascade,
  content text not null,
  embedding vector(1536) -- For OpenAI text-embedding-3-small
);

-- Table for Chat History
create table chat_messages (
  id uuid primary key default uuid_generate_v4(),
  user_id uuid references auth.users(id),
  document_id uuid references documents(id),
  role text check (role in ('user', 'assistant')),
  content text not null,
  created_at timestamp with time zone default now()
);
