### 2. The Implementation Plan

#### Step A: PDF Processing (The Ingestion Pipeline)
When a user uploads a PDF, we need to:
1. Save the file to Storage.
2. Parse the PDF into text.
3. Split the text into manageable chunks (e.g., 1000 characters).
4. Generate embeddings for those chunks using OpenAI.
5. Store them in `pgvector`.

```typescript
// app/api/upload/route.ts
import { PDFLoader } from "langchain/document_loaders/fs/pdf";
import { RecursiveCharacterTextSplitter } from "langchain/text_splitter";
import { OpenAIEmbeddings } from "@langchain/openai";
import { SupabaseVectorStore } from "@langchain/community/vectorstores/supabase";
import { createClient } from "@supabase/supabase-js";

export async function POST(req: Request) {
  const formData = await req.formData();
  const file = formData.get("file") as File;

  // 1. Upload to Supabase Storage
  const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!);
  const { data: uploadData } = await supabase.storage
    .from('pdfs')
    .upload(`${Date.now()}-${file.name}`, file);

  // 2. Parse & Chunk
  const loader = new PDFLoader(file);
  const rawDocs = await loader.load();
  const splitter = new RecursiveCharacterTextSplitter({ chunkSize: 1000, chunkOverlap: 200 });
  const docs = await splitter.splitDocuments(rawDocs);

  // 3. Store in Vector DB
  await SupabaseVectorStore.fromDocuments(
    docs,
    new OpenAIEmbeddings(),
    {
      client: supabase,
      tableName: 'document_sections',
      queryName: 'match_documents',
    }
  );

  return Response.json({ success: true });
}
```

#### Step B: The Chat Engine (RAG)
This endpoint handles the user query, retrieves relevant chunks, and streams the answer while saving history.

```typescript
// app/api/chat/route.ts
import { OpenAIStream, StreamingTextResponse } from 'ai';
import { Configuration, OpenAIApi } from 'openai-edge';
import { createClient } from "@supabase/supabase-js";

export async function POST(req: Request) {
  const { messages, documentId } = await req.json();
  const lastMessage = messages[messages.length - 1].content;

  // 1. Search for context using Vector Similarity
  const supabase = createClient(...);
  const { data: chunks } = await supabase.rpc('match_documents', {
    query_embedding: await generateEmbedding(lastMessage),
    match_threshold: 0.5,
    match_count: 5,
  });

  const context = chunks.map(c => c.content).join("\n");

  // 2. Query LLM with Context
  const response = await openai.createChatCompletion({
    model: 'gpt-4o',
    stream: true,
    messages: [
      { role: 'system', content: `Answer based on this context: ${context}` },
      ...messages
    ],
  });

  // 3. Stream and Save to DB
  const stream = OpenAIStream(response, {
    onCompletion: async (completion) => {
      // Save user question and assistant answer to chat_messages table
      await supabase.from('chat_messages').insert([
        { document_id: documentId, role: 'user', content: lastMessage },
        { document_id: documentId, role: 'assistant', content: completion }
      ]);
    }
  });

  return new StreamingTextResponse(stream);
}
```

