### 2. PDF Processing & Vector Ingestion

When a user uploads a PDF, we don't just store the file. We must:
1. Parse the text.
2. Split it into "chunks" (so we don't exceed LLM token limits).
3. Convert chunks into "Embeddings" (vectors).
4. Store vectors in Pinecone.

**File: `lib/pinecone.ts`**
```typescript
import { PDFLoader } from "langchain/document_loaders/fs/pdf";
import { RecursiveCharacterTextSplitter } from "langchain/text_splitter";
import { OpenAIEmbeddings } from "@langchain/openai";
import { PineconeStore } from "@langchain/pinecone";
import { Pinecone } from "@pinecone-database/pinecone";

export const processPdfIntoPinecone = async (fileUrl: string, fileId: string) => {
  // 1. Download & Load PDF
  const response = await fetch(fileUrl);
  const blob = await response.blob();
  const loader = new PDFLoader(blob);
  const pageLevelDocs = await loader.load();

  // 2. Split text into manageable chunks
  const splitter = new RecursiveCharacterTextSplitter({
    chunkSize: 1000,
    chunkOverlap: 200,
  });
  const docs = await splitter.splitDocuments(pageLevelDocs);

  // 3. Initialize Pinecone
  const pc = new Pinecone({ apiKey: process.env.PINECONE_API_KEY! });
  const pineconeIndex = pc.Index(process.env.PINECONE_INDEX_NAME!);

  // 4. Embed and store
  await PineconeStore.fromDocuments(docs, new OpenAIEmbeddings(), {
    pineconeIndex,
    namespace: fileId, // Namespace by fileId to isolate searches
  });
};
```

