### 3. The Chat API Route

This is the core logic. It takes a question, searches Pinecone for context, and asks GPT-4o for an answer based *only* on that context.

**File: `app/api/chat/route.ts`**
```typescript
import { OpenAIStream, StreamingTextResponse } from 'ai';
import { openai } from '@/lib/openai-client';
import { db } from '@/lib/db';
import { getContext } from '@/lib/context'; // Helper to query Pinecone

export async function POST(req: Request) {
  const { messages, fileId, userId } = await req.json();
  const lastMessage = messages[messages.length - 1];

  // 1. Get context from Pinecone
  const context = await getContext(lastMessage.content, fileId);

  // 2. Prompt Engineering
  const prompt = {
    role: 'system',
    content: `AI assistant is a brand new, powerful, human-like artificial intelligence.
    Use the following pieces of context to answer the user's question.
    If you don't know the answer, just say that you don't know, don't try to make up an answer.
    ----------------
    CONTEXT:
    ${context}
    `,
  };

  // 3. Call OpenAI with context + chat history
  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    stream: true,
    messages: [prompt, ...messages],
  });

  // 4. Save User Message to SQL
  await db.message.create({
    data: { text: lastMessage.content, fileId, userId, isUser: true }
  });

  const stream = OpenAIStream(response, {
    onCompletion: async (completion) => {
      // 5. Save AI Response to SQL when finished
      await db.message.create({
        data: { text: completion, fileId, userId, isUser: false }
      });
    },
  });

  return new StreamingTextResponse(stream);
}
```

