### 1. Database Schema & Setup

Run the following SQL in your Supabase SQL Editor to set up the vector extension, tables for documents, and chat history.

```sql
-- Enable the pgvector extension
create extension if not exists vector;

-- Documents table to store PDF metadata and embeddings
create table documents (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references auth.users(id),
  content text, -- The text chunk
  metadata jsonb,
  embedding vector(1536), -- For OpenAI embeddings
  file_name text,
  created_at timestamp with time zone default now()
);

-- Chat history table
create table chat_history (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references auth.users(id),
  role text check (role in ('user', 'assistant')),
  content text,
  created_at timestamp with time zone default now()
);

-- Enable RLS
alter table documents enable row level security;
alter table chat_history enable row level security;

-- Policies
create policy "Users can manage their own documents" on documents 
  for all using (auth.uid() = user_id);
create policy "Users can manage their own chat history" on chat_history 
  for all using (auth.uid() = user_id);
