### 2. Implementation: The PDF Processor

This Server Action handles the PDF upload, extracts text, chunks it, and generates embeddings.

```typescript
// app/actions/upload.ts
"use server";
import { createClient } from "@/utils/supabase/server";
import { OpenAIEmbeddings } from "@langchain/openai";
import PDFParser from "pdf-parse"; // You'll need to npm install pdf-parse

export async function uploadPDF(formData: FormData) {
  const supabase = createClient();
  const file = formData.get("file") as File;
  const { data: { user } } = await supabase.auth.getUser();

  if (!user || !file) throw new Error("Unauthorized or missing file");

  // 1. Upload to Supabase Storage
  const { data: storageData, error: storageError } = await supabase.storage
    .from("pdfs")
    .upload(`${user.id}/${Date.now()}-${file.name}`, file);

  // 2. Extract Text (Simplified chunking logic)
  const buffer = Buffer.from(await file.arrayBuffer());
  const pdfData = await PDFParser(buffer);
  const text = pdfData.text;

  // 3. Chunk & Embed
  // In production, use a recursive character splitter
  const chunks = text.match(/[\s\S]{1,1000}/g) || []; 
  const embeddings = new OpenAIEmbeddings({
    openAIApiKey: process.env.OPENAI_API_KEY,
    modelName: "text-embedding-3-small",
  });

  const processedChunks = await Promise.all(
    chunks.map(async (chunk) => {
      const embedding = await embeddings.embedQuery(chunk);
      return {
        user_id: user.id,
        content: chunk,
        embedding,
        file_name: file.name,
      };
    })
  );

  // 4. Save to pgvector
  await supabase.from("documents").insert(processedChunks);

  return { success: true };
}
```

