### 3. Implementation: The RAG Chat API

This route handles the user query, performs a vector search, and streams the answer.

```typescript
// app/api/chat/route.ts
import { openai } from "@ai-sdk/openai";
import { streamText, createDataStreamResponse } from "ai";
import { createClient } from "@/utils/supabase/server";

export async function POST(req: Request) {
  const { messages } = await req.json();
  const lastMessage = messages[messages.length - 1].content;
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();

  // 1. Generate embedding for the question
  const res = await fetch("https://api.openai.com/v1/embeddings", {
    method: "POST",
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${process.env.OPENAI_API_KEY}` },
    body: JSON.stringify({ input: lastMessage, model: "text-embedding-3-small" }),
  });
  const { data } = await res.json();
  const embedding = data[0].embedding;

  // 2. Vector Search (Match threshold and count)
  const { data: documents } = await supabase.rpc("match_documents", {
    query_embedding: embedding,
    match_threshold: 0.5,
    match_count: 5,
  });

  const context = documents?.map((d: any) => d.content).join("\n") ?? "";

  // 3. Stream AI Response
  const result = await streamText({
    model: openai("gpt-4o"),
    system: `You are a research assistant. Use the following context to answer: ${context}`,
    messages,
    onFinish: async ({ text }) => {
      // 4. Save to Chat History
      await supabase.from("chat_history").insert([
        { user_id: user?.id, role: "user", content: lastMessage },
        { user_id: user?.id, role: "assistant", content: text },
      ]);
    },
  });

  return result.toDataStreamResponse();
}
```

*Note: You must define the `match_documents` function in your Supabase SQL editor to calculate cosine similarity.*

