### 2. The Core Application Logic

We'll implement a Fastify server with clean separation of concerns.

#### Video Controller (Metadata & History)
This handles retrieving videos and updating the user's progress.

```typescript
// src/routes/video.routes.ts
import { FastifyInstance } from 'fastify';
import { prisma } from '../lib/prisma';

export async function videoRoutes(fastify: FastifyInstance) {

  // Get Video Metadata
  fastify.get('/videos/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const video = await prisma.video.findUnique({ where: { id } });

    if (!video) return reply.status(404).send({ error: 'Video not found' });
    return video;
  });

  // Record Viewing Progress (Heartbeat)
  // In production, you might throttle this or use Redis for buffering
  fastify.post('/videos/:id/progress', async (request, reply) => {
    const { id: videoId } = request.params as { id: string };
    const { userId, position } = request.body as { userId: string, position: number };

    const video = await prisma.video.findUnique({ where: { id: videoId } });
    const isCompleted = position >= (video?.duration || 0) * 0.9; // 90% threshold

    const history = await prisma.viewingHistory.upsert({
      where: { userId_videoId: { userId, videoId } },
      update: { lastPosition: position, completed: isCompleted },
      create: { userId, videoId, lastPosition: position, completed: isCompleted }
    });

    return history;
  });

  // Get User History
  fastify.get('/history/:userId', async (request) => {
    const { userId } = request.params as { userId: string };
    return prisma.viewingHistory.findMany({
      where: { userId },
      include: { video: true },
      orderBy: { updatedAt: 'desc' },
      take: 20
    });
  });
}
```

#### Playlist Controller
Manages the creation and organization of user playlists.

```typescript
// src/routes/playlist.routes.ts
import { FastifyInstance } from 'fastify';
import { prisma } from '../lib/prisma';

export async function playlistRoutes(fastify: FastifyInstance) {

  fastify.post('/playlists', async (request) => {
    const { userId, name, description } = request.body as any;
    return prisma.playlist.create({
      data: { userId, name, description }
    });
  });

  fastify.post('/playlists/:id/videos', async (request) => {
    const { id: playlistId } = request.params as { id: string };
    const { videoId } = request.body as { videoId: string };

    // Get the current max order to append to the end
    const lastVideo = await prisma.playlistVideo.findFirst({
      where: { playlistId },
      orderBy: { order: 'desc' }
    });

    return prisma.playlistVideo.create({
      data: {
        playlistId,
        videoId,
        order: (lastVideo?.order ?? 0) + 1
      }
    });
  });

  fastify.get('/playlists/:id', async (request) => {
    const { id } = request.params as { id: string };
    return prisma.playlist.findUnique({
      where: { id },
      include: {
        videos: {
          include: { video: true },
          orderBy: { order: 'asc' }
        }
      }
    });
  });
}
```

