  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id            String          @id @default(uuid())
  email         String          @unique
  playlists     Playlist[]
  viewingHistory ViewingHistory[]
  createdAt     DateTime        @default(now())
}

model Video {
  id          String   @id @default(uuid())
