  videos      PlaylistVideo[]
  isPublic    Boolean         @default(true)
  createdAt   DateTime        @default(now())
}

// Join table for Playlist <-> Video Many-to-Many
model PlaylistVideo {
  playlistId String
  videoId    String
  order      Int      // To maintain playlist sequence
  playlist   Playlist @relation(fields: [playlistId], references: [id])
  video      Video    @relation(fields: [videoId], references: [id])

  @@id([playlistId, videoId])
}

model ViewingHistory {
  id               String   @id @default(uuid())
  userId           String
  videoId          String
  watchedSeconds   Int      // Current timestamp in video
  lastWatchedAt    DateTime @updatedAt
  user             User     @relation(fields: [userId], references: [id])
  video            Video    @relation(fields: [videoId], references: [id])

  @@unique([userId, videoId]) // One entry per user/video pair
  @@index([userId, lastWatchedAt])
}
