### 🚀 2. The Application Code

Below is a structured Express application. For brevity, I've combined the core logic into specialized services.

#### Metadata & History Controller (`src/controllers/video.controller.ts`)

```typescript
import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';

const prisma = new PrismaClient();

// Validation Schemas
const HistorySchema = z.object({
  videoId: z.string().uuid(),
  watchedSeconds: z.number().min(0),
});

export const VideoController = {
  // 1. Metadata: Fetch video details
  async getVideoMetadata(req: Request, res: Response) {
    const { id } = req.params;
    const video = await prisma.video.findUnique({
      where: { id },
      include: { _count: { select: { history: true } } }
    });

    if (!video) return res.status(404).json({ error: "Video not found" });
    return res.json(video);
  },

  // 2. Viewing History: Update progress
  async updateHistory(req: Request, res: Response) {
    try {
      const userId = req.headers['x-user-id'] as string; // Mock Auth
      const { videoId, watchedSeconds } = HistorySchema.parse(req.body);

      const history = await prisma.viewingHistory.upsert({
        where: {
          userId_videoId: { userId, videoId }
        },
        update: {
          watchedSeconds,
          lastWatchedAt: new Date(),
        },
        create: {
          userId,
          videoId,
          watchedSeconds,
        }
      });

      return res.status(200).json(history);
    } catch (error) {
      return res.status(400).json({ error: "Invalid data" });
    }
  },

  // 3. Playlists: Add video to playlist
  async addToPlaylist(req: Request, res: Response) {
    const { playlistId, videoId } = req.params;

    // Get current max order
    const lastItem = await prisma.playlistVideo.findFirst({
      where: { playlistId },
      orderBy: { order: 'desc' }
    });

    const entry = await prisma.playlistVideo.create({
      data: {
        playlistId,
        videoId,
        order: (lastItem?.order || 0) + 1
      }
    });

    return res.json(entry);
  }
};
```

