  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Product {
  id          String    @id @default(cuid())
  name        String
  description String?
  brand       String
  category    String
  variants    Variant[]
  createdAt   DateTime  @default(now())
  updatedAt   DateTime  @updatedAt
}

model Variant {
  id        String   @id @default(cuid())
  sku       String   @unique
  name      String   // e.g., "T-Shirt - Blue - Large"
  price     Decimal  @db.Decimal(10, 2)
  size      String?
  color     String?
  productId String
  product   Product  @relation(fields: [productId], references: [id])
