### 2. Backend Logic: The Inventory Service

The most critical part of an IMS is ensuring that when stock is updated, it happens atomically. We use **Prisma Transactions** to ensure that if one part of a stock movement fails, the whole operation rolls back.

```typescript
// inventory.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from './prisma.service';

@Injectable()
export class InventoryService {
  constructor(private prisma: PrismaService) {}

  /**
   * Adjusts stock levels and records the movement for audit trails
   */
  async adjustStock(dto: {
    variantId: string;
    warehouseId: string;
    quantity: number; // Positive for restock, negative for sales
    type: 'IN' | 'OUT' | 'TRANSFER' | 'ADJUSTMENT';
    reference?: string;
  }) {
    return this.prisma.$transaction(async (tx) => {
      // 1. Update or Create the Stock record
      const stock = await tx.stock.upsert({
        where: {
          variantId_warehouseId: {
            variantId: dto.variantId,
            warehouseId: dto.warehouseId,
          },
        },
        update: {
          quantity: { increment: dto.quantity },
        },
        create: {
          variantId: dto.variantId,
          warehouseId: dto.warehouseId,
          quantity: dto.quantity,
        },
      });

      // 2. Prevent negative inventory
      if (stock.quantity < 0) {
        throw new BadRequestException('Insufficient stock in warehouse');
      }

      // 3. Create Audit Trail
      await tx.stockMovement.create({
        data: {
          variantId: dto.variantId,
          warehouseId: dto.warehouseId,
          quantity: dto.quantity,
          type: dto.type,
          reference: dto.reference,
        },
      });

      return stock;
    });
  }

  /**
   * Get total stock across all warehouses for a specific SKU
   */
  async getGlobalStock(sku: string) {
    const variant = await this.prisma.variant.findUnique({
      where: { sku },
      include: { stocks: true },
    });

    const total = variant?.stocks.reduce((acc, s) => acc + s.quantity, 0) || 0;
    return { sku, total, breakdowns: variant?.stocks };
  }
}
```

