### 3. Core Logic: Atomic Stock Updates

In a multi-warehouse system, updating stock must be **atomic**. We use Prisma transactions to ensure that the `Stock` level and the `StockMovement` log are updated simultaneously.

```typescript
// app/api/inventory/adjust/route.ts
import { prisma } from "@/lib/db";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  const { variantId, warehouseId, quantity, type } = await req.json();

  try {
    const result = await prisma.$transaction(async (tx) => {
      // 1. Update or Create the stock record
      const stock = await tx.stock.upsert({
        where: {
          variantId_warehouseId: { variantId, warehouseId },
        },
        update: {
          quantity: { increment: quantity },
        },
        create: {
          variantId,
          warehouseId,
          quantity,
        },
      });

      // 2. Log the movement for auditing
      await tx.stockMovement.create({
        data: {
          variantId,
          warehouseId,
          quantity,
          type,
        },
      });

      return stock;
    });

    return NextResponse.json(result);
  } catch (error) {
    return NextResponse.json({ error: "Failed to update stock" }, { status: 500 });
  }
}
```

