### 3. Core Business Logic: Atomic Stock Adjustment

When moving inventory, we must ensure data integrity. If a transfer fails halfway, we shouldn't lose or gain "ghost" items.

```typescript
// lib/inventory-service.ts
import { prisma } from "./prisma";

export async function transferStock(
  variantId: string,
  fromWarehouseId: string,
  toWarehouseId: string,
  quantity: number
) {
  return await prisma.$transaction(async (tx) => {
    // 1. Decrement from source
    const sourceStock = await tx.stockLevel.update({
      where: {
        variantId_warehouseId: { variantId, warehouseId: fromWarehouseId },
      },
      data: { quantity: { decrement: quantity } },
    });

    if (sourceStock.quantity < 0) {
      throw new Error("Insufficient stock in source warehouse");
    }

    // 2. Increment at destination (or create if doesn't exist)
    await tx.stockLevel.upsert({
      where: {
        variantId_warehouseId: { variantId, warehouseId: toWarehouseId },
      },
      update: { quantity: { increment: quantity } },
      create: { variantId, warehouseId: toWarehouseId, quantity },
    });

    // 3. Log the transaction
    await tx.transaction.create({
      data: {
        variantId,
        warehouseId: toWarehouseId,
        type: "TRANSFER",
        quantity,
        reference: `From ${fromWarehouseId} to ${toWarehouseId}`,
      },
    });
  });
}
```

