#### Step 2: Tenant Connection Factory
This service generates a Prisma client configured to look only at one specific schema.

```typescript
// src/tenant/tenant.service.ts
import { Injectable, Scope } from '@nestjs/common';
import { PrismaClient } from '@prisma/client';

@Injectable({ scope: Scope.REQUEST }) // Important: New instance per request
export class TenantService {
  private _prisma: PrismaClient;

  // This is called by the middleware/interceptor once the tenant is identified
  setTenant(tenantId: string) {
    const schemaName = `tenant_${tenantId}`;

    // We override the connection URL to include the schema search path
    this._prisma = new PrismaClient({
      datasources: {
        db: {
          url: `${process.env.DATABASE_URL}?schema=${schemaName}`,
        },
      },
    });
  }

  get db() {
    return this._prisma;
  }
}
```

#### Step 3: The Tenant Middleware
This extracts the tenant ID from the request header (or subdomain) and initializes the service.

```typescript
// src/tenant/tenant.middleware.ts
import { Injectable, NestMiddleware, UnauthorizedException } from '@nestjs/common';
import { TenantService } from './tenant.service';

@Injectable()
export class TenantMiddleware implements NestMiddleware {
  constructor(private readonly tenantService: TenantService) {}

  use(req: any, res: any, next: () => void) {
    const tenantId = req.headers['x-tenant-id']; // Or parse from req.subdomains

    if (!tenantId) {
      throw new UnauthorizedException('No tenant context provided');
    }

    this.tenantService.setTenant(tenantId);
    next();
  }
}
```

