### 4. Tenant Provisioning Logic
When a new customer signs up, you must run a script to create their isolated environment.

```typescript
// src/provisioning/provisioning.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaClient } from '@prisma/client';
import { execSync } from 'child_process';

@Injectable()
export class ProvisioningService {
  private masterPrisma = new PrismaClient();

  async createTenant(tenantId: string) {
    const schemaName = `tenant_${tenantId}`;

    // 1. Create the schema in Postgres
    await this.masterPrisma.$executeRawUnsafe(`CREATE SCHEMA IF NOT EXISTS "${schemaName}"`);

    // 2. Run migrations against the new schema
    // In production, you'd use a more robust migration runner
    const dbUrl = `${process.env.DATABASE_URL}?schema=${schemaName}`;
    execSync(`npx prisma db push`, {
      env: { ...process.env, DATABASE_URL: dbUrl },
    });

    return { success: true, schema: schemaName };
  }
}
```

