### 5. The Frontend (Next.js Middleware)
To provide a professional experience, we use subdomains (e.g., `tesla.myapp.com`).

```typescript
// middleware.ts (Next.js)
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  const url = request.nextUrl;
  const hostname = request.headers.get('host');

  // Extract subdomain (e.g., "tesla" from "tesla.myapp.com")
  const currentHost = hostname.replace(`.localhost:3000`, ``).replace(`.myapp.com`, ``);

  if (currentHost && currentHost !== 'www' && currentHost !== 'myapp') {
    // Rewrite the URL to the dynamic tenant route
    return NextResponse.rewrite(new URL(`/_tenants/${currentHost}${url.pathname}`, request.url));
  }
}
```

