### 5. The Data Access Layer (Server Action)

This is how you fetch data safely. Notice we don't manually add `WHERE tenant_id = ...` because the DB handles it.

```typescript
// src/app/dashboard/actions.ts
"use server";

import { auth } from "@clerk/nextjs";
import { withTenant } from "@/db";
import { documents } from "@/db/schema";

export async function getDocuments() {
  const { orgId } = auth();
  if (!orgId) throw new Error("Unauthorized");

  // RLS will automatically filter these to only show the ones for orgId
  return await withTenant(orgId, async (tx) => {
    return await tx.select().from(documents);
  });
}

export async function createDocument(title: string) {
  const { orgId } = auth();
  if (!orgId) throw new Error("Unauthorized");

  return await withTenant(orgId, async (tx) => {
    return await tx.insert(documents).values({
      title,
      tenantId: orgId, // Must still provide it for the insert
    });
  });
}
```

