### 4. The "Strict Isolation" DB Client

This is the core of your application. We wrap the Prisma client to ensure a `tenantId` is always present.

```typescript
// lib/prisma.ts
import { PrismaClient } from "@prisma/client";

export const prisma = new PrismaClient();

// This function returns a scoped Prisma client
export function getTenantDb(tenantId: string) {
  return prisma.$extends({
    query: {
      $allModels: {
        async $allOperations({ model, operation, args, query }) {
          // 1. For find/update/delete, inject the tenantId filter
          if (['findFirst', 'findMany', 'update', 'updateMany', 'delete', 'deleteMany', 'count'].includes(operation)) {
            (args as any).where = { ...(args as any).where, tenantId };
          }

          // 2. For create, inject the tenantId automatically
          if (operation === 'create') {
            (args as any).data = { ...(args as any).data, tenantId };
          }

          return query(args);
        },
      },
    },
  });
}
```

