### 5. Multi-Tenant Middleware

In a SaaS, you usually detect the tenant via a **subdomain** (e.g., `apple.saas.com`) or a **path** (e.g., `saas.com/apple`). We will use subdomains.

```typescript
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  const url = request.nextUrl;
  const hostname = request.headers.get("host") || "";

  // Define your main domain
  const rootDomain = process.env.NEXT_PUBLIC_ROOT_DOMAIN || "myapp.com";

  // Extract subdomain (e.g., 'tenant1.myapp.com' -> 'tenant1')
  const subdomain = hostname.replace(`.${rootDomain}`, "");

  if (subdomain === rootDomain || subdomain === "www") {
    return NextResponse.next();
  }

  // Rewrite the URL to the dynamic tenant route
  return NextResponse.rewrite(
    new URL(`/_subdomain/${subdomain}${url.pathname}`, request.url)
  );
}

export const config = {
  matcher: ['/((?!api|_next/static|_next/image|favicon.ico).*)'],
};
```

