## 1. Database Schema (Prisma)

A robust ticketing system requires a normalized schema to track state changes and relationships.

```prisma
// prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

enum TicketStatus {
  OPEN
  IN_PROGRESS
  RESOLVED
  CLOSED
}

enum Priority {
  LOW
  MEDIUM
  HIGH
  URGENT
}

model User {
  id            String    @id @default(cuid())
  name          String?
  email         String    @unique
  role          String    @default("USER") // USER, AGENT, ADMIN
  ticketsCreated Ticket[] @relation("CreatedBy")
  ticketsAssigned Ticket[] @relation("AssignedTo")
  comments      Comment[]
}

model Ticket {
  id          String   @id @default(cuid())
  title       String
  description String   @db.Text
  status      TicketStatus @default(OPEN)
  priority    Priority     @default(MEDIUM)

  createdById String
  createdBy   User     @relation("CreatedBy", fields: [createdById], references: [id])

  assignedToId String?
  assignedTo   User?    @relation("AssignedTo", fields: [assignedToId], references: [id])

  comments    Comment[]
  attachments Attachment[]
  history     StatusHistory[]

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt
}

model Comment {
  id        String   @id @default(cuid())
  content   String   @db.Text
  ticketId  String
  ticket    Ticket   @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  userId    String
  user      User     @relation(fields: [userId], references: [id])
  createdAt DateTime @default(now())
}

model Attachment {
  id        String   @id @default(cuid())
  fileUrl   String
  fileName  String
  fileSize  Int
  ticketId  String
  ticket    Ticket   @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  createdAt DateTime @default(now())
}

model StatusHistory {
  id         String       @id @default(cuid())
  ticketId   String
  ticket     Ticket       @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  oldStatus  TicketStatus
  newStatus  TicketStatus
  changedBy  String       // User name or ID
  createdAt  DateTime     @default(now())
}
