## 2. Core Logic: Ticket Actions

We use **Next.js Server Actions** to handle logic. This ensures that status changes and history logging happen in a single database transaction.

```typescript
// app/lib/actions/tickets.ts
"use server"

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { TicketStatus, Priority } from "@prisma/client";

export async function updateTicketStatus(
  ticketId: string, 
  newStatus: TicketStatus,
  userId: string,
  userName: string
) {
  // 1. Fetch current status for history
  const ticket = await prisma.ticket.findUnique({
    where: { id: ticketId },
    select: { status: true }
  });

  if (!ticket) throw new Error("Ticket not found");

  // 2. Perform transaction: Update Ticket + Create History Record
  await prisma.$transaction([
    prisma.ticket.update({
      where: { id: ticketId },
      data: { status: newStatus }
    }),
    prisma.statusHistory.create({
      data: {
        ticketId,
        oldStatus: ticket.status,
        newStatus: newStatus,
        changedBy: userName
      }
    })
  ]);

  revalidatePath(`/tickets/${ticketId}`);
}

export async function addComment(ticketId: string, userId: string, content: string) {
  await prisma.comment.create({
    data: {
      content,
      ticketId,
      userId
    }
  });
  revalidatePath(`/tickets/${ticketId}`);
}
```

