#### Comment Section with File Support (`CommentSection.tsx`)
Using React Query for instant updates.

```tsx
"use client";

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase/client';
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Paperclip } from "lucide-react";

export default function CommentSection({ ticketId }: { ticketId: string }) {
  const queryClient = useQueryClient();
  const [comment, setComment] = useState("");
  const [file, setFile] = useState<File | null>(null);

  const { data: comments, isLoading } = useQuery({
    queryKey: ['comments', ticketId],
    queryFn: async () => {
      const { data } = await supabase
        .from('comments')
        .select('*, profiles(full_name), attachments(*)')
        .eq('ticket_id', ticketId)
        .order('created_at', { ascending: true });
      return data;
    }
  });

  const submitMutation = useMutation({
    mutationFn: async () => {
      // 1. Post Comment
      const { data: newComment, error: cErr } = await supabase
        .from('comments')
        .insert([{ ticket_id: ticketId, body: comment, user_id: (await supabase.auth.getUser()).data.user?.id }])
        .select()
        .single();

      if (cErr) throw cErr;

      // 2. Handle Attachment if exists
      if (file && newComment) {
        const fileExt = file.name.split('.').pop();
        const filePath = `${ticketId}/${newComment.id}.${fileExt}`;

        await supabase.storage.from('attachments').upload(filePath, file);

        const { data: urlData } = supabase.storage.from('attachments').getPublicUrl(filePath);

        await supabase.from('attachments').insert([{
          ticket_id: ticketId,
          comment_id: newComment.id,
          file_url: urlData.publicUrl,
          file_name: file.name,
          uploaded_by: newComment.user_id
        }]);
      }
    },
    onSuccess: () => {
      setComment("");
      setFile(null);
      queryClient.invalidateQueries({ queryKey: ['comments', ticketId] });
    }
  });

  return (
    <div className="space-y-4">
      <h3 className="text-xl font-semibold">Activity</h3>
      <div className="space-y-4 border-l-2 ml-2 pl-4">
        {comments?.map((c) => (
          <div key={c.id} className="bg-slate-50 p-4 rounded-lg relative">
            <p className="text-sm font-bold">{c.profiles.full_name}</p>
            <p className="mt-1">{c.body}</p>
            {c.attachments?.map((a: any) => (
              <a key={a.id} href={a.file_url} className="flex items-center gap-2 text-blue-600 text-sm mt-2 hover:underline">
                <Paperclip className="w-4 h-4" /> {a.file_name}
              </a>
            ))}
          </div>
        ))}
      </div>

      <div className="mt-6 space-y-2">
        <Textarea 
          placeholder="Write a response..." 
          value={comment}
          onChange={(e) => setComment(e.target.value)}
        />
        <div className="flex justify-between items-center">
          <input 
            type="file" 
            id="file-upload" 
            className="hidden" 
            onChange={(e) => setFile(e.target.files?.[0] || null)}
          />
          <label htmlFor="file-upload" className="cursor-pointer text-sm text-muted-foreground flex items-center gap-1">
            <Paperclip className="w-4 h-4" /> {file ? file.name : "Attach file"}
          </label>
          <Button 
            disabled={!comment || submitMutation.isPending}
            onClick={() => submitMutation.mutate()}
          >
            Post Comment
          </Button>
        </div>
      </div>
    </div>
  );
}
