This schema tracks the core requirements: tickets, comments, attachments, and the history of status changes.

```prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

enum TicketStatus {
  OPEN
  IN_PROGRESS
  RESOLVED
  CLOSED
}

enum Priority {
  LOW
  MEDIUM
  HIGH
  URGENT
}

model User {
  id            String          @id @default(cuid())
  email         String          @unique
  name          String?
  role          String          @default("USER") // USER, AGENT, ADMIN
  tickets       Ticket[]        @relation("Reporter")
  assignedTo    Ticket[]        @relation("Assignee")
  comments      Comment[]
  statusChanges StatusHistory[]
}

model Ticket {
  id          String          @id @default(cuid())
  title       String
  description String          @db.Text
  status      TicketStatus    @default(OPEN)
  priority    Priority        @default(MEDIUM)

  reporterId  String
  reporter    User            @relation("Reporter", fields: [reporterId], references: [id])

  assigneeId  String?
  assignee    User?           @relation("Assignee", fields: [assigneeId], references: [id])

  comments    Comment[]
  attachments Attachment[]
  history     StatusHistory[]

  createdAt   DateTime        @default(now())
  updatedAt   DateTime        @updatedAt
}

model Comment {
  id        String   @id @default(cuid())
  content   String   @db.Text
  ticketId  String
  ticket    Ticket   @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  userId    String
  user      User     @relation(fields: [userId], references: [id])
  createdAt DateTime @default(now())
}

model Attachment {
  id        String   @id @default(cuid())
  url       String   // S3 or Supabase Storage URL
  fileName  String
  fileType  String
  ticketId  String
  ticket    Ticket   @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  createdAt DateTime @default(now())
}

model StatusHistory {
  id         String       @id @default(cuid())
  ticketId   String
  ticket     Ticket       @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  oldStatus  TicketStatus
  newStatus  TicketStatus
  changedById String
  changedBy  User         @relation(fields: [changedById], references: [id])
  createdAt  DateTime     @default(now())
}
