### 2. Backend Logic: Changing Status & Tracking History

In a production system, changing a status isn't just a database update; it's a transaction that must record *who* changed it and *when*.

```typescript
// src/app/api/tickets/[id]/status/route.ts
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function PATCH(req: Request, { params }: { params: { id: string } }) {
  const { newStatus, userId } = await req.json();
  const ticketId = params.id;

  try {
    const result = await prisma.$transaction(async (tx) => {
      // 1. Get current status
      const currentTicket = await tx.ticket.findUnique({
        where: { id: ticketId },
        select: { status: true }
      });

      if (!currentTicket) throw new Error("Ticket not found");

      // 2. Update Ticket
      const updatedTicket = await tx.ticket.update({
        where: { id: ticketId },
        data: { status: newStatus },
      });

      // 3. Create History Record
      await tx.statusHistory.create({
        data: {
          ticketId,
          oldStatus: currentTicket.status,
          newStatus: newStatus,
          changedById: userId,
        },
      });

      return updatedTicket;
    });

    return NextResponse.json(result);
  } catch (error) {
    return NextResponse.json({ error: "Update failed" }, { status: 500 });
  }
}
```

