### 4. Handling Attachments

For production-ready file uploads, we use **Pre-signed URLs**. This avoids putting heavy load on our Next.js server by allowing the client to upload directly to S3/Cloud Storage.

```typescript
// src/lib/storage.ts (Example using AWS S3 SDK)
import { S3Client, PutObjectCommand } from "@aws-sdk/client-s3";
import { getSignedUrl } from "@aws-sdk/s3-request-presigner";

const s3 = new S3Client({ region: process.env.AWS_REGION });

export async function getUploadUrl(fileName: string, contentType: string) {
  const key = `attachments/${Date.now()}-${fileName}`;
  const command = new PutObjectCommand({
    Bucket: process.env.S3_BUCKET_NAME,
    Key: key,
    ContentType: contentType,
  });

  const url = await getSignedUrl(s3, command, { expiresIn: 3600 });
  return { url, key };
}
```

