### 2. The Form Builder State (`store/useFormStore.ts`)

A survey builder requires a "draft" state where users can reorder or edit questions before saving.

```typescript
import { create } from 'zustand';

export type QuestionType = 'TEXT' | 'MULTIPLE_CHOICE' | 'RATING';

export interface QuestionDraft {
  id: string;
  type: QuestionType;
  label: string;
  required: boolean;
  config: any;
}

interface FormStore {
  questions: QuestionDraft[];
  addQuestion: (type: QuestionType) => void;
  updateQuestion: (id: string, updates: Partial<QuestionDraft>) => void;
  removeQuestion: (id: string) => void;
  moveQuestion: (id: string, direction: 'up' | 'down') => void;
}

export const useFormStore = create<FormStore>((set) => ({
  questions: [],
  addQuestion: (type) => set((state) => ({
    questions: [...state.questions, {
      id: crypto.randomUUID(),
      type,
      label: 'New Question',
      required: false,
      config: type === 'MULTIPLE_CHOICE' ? { options: ['Option 1'] } : {}
    }]
  })),
  updateQuestion: (id, updates) => set((state) => ({
    questions: state.questions.map(q => q.id === id ? { ...q, ...updates } : q)
  })),
  removeQuestion: (id) => set((state) => ({
    questions: state.questions.filter(q => q.id !== id)
  })),
  moveQuestion: (id, direction) => set((state) => {
    const index = state.questions.findIndex(q => q.id === id);
    const newQuestions = [...state.questions];
    const offset = direction === 'up' ? -1 : 1;
    if (index + offset < 0 || index + offset >= newQuestions.length) return state;
    [newQuestions[index], newQuestions[index + offset]] = [newQuestions[index + offset], newQuestions[index]];
    return { questions: newQuestions };
  })
}));
```

