### 4. Server Action for Submission (`app/actions/submit-form.ts`)

Server Actions allow us to handle the dynamic data securely without writing explicit API boilerplate.

```typescript
"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function submitForm(formId: string, data: Record<string, any>) {
  try {
    await prisma.submission.create({
      data: {
        formId,
        responses: {
          create: Object.entries(data).map(([questionId, value]) => ({
            questionId,
            value: value, // Prisma handles JSON conversion
          })),
        },
      },
    });

    revalidatePath(`/admin/forms/${formId}/results`);
    return { success: true };
  } catch (error) {
    console.error("Submission Error:", error);
    return { success: false, error: "Failed to submit form" };
  }
}
