### 2. Database Schema (The Foundation)

The core challenge is the relationship between the "Canonical Content" and its "Translations/Variations." We use a **One-to-Many** relationship.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Content {
  id           String        @id @default(uuid())
  slug         String        @unique // e.g., "summer-collection-2024"
  createdAt    DateTime      @default(now())
  updatedAt    DateTime      @updatedAt
  authorId     String
  status       Status        @default(DRAFT)

  // Relations
  translations Translation[]
}

model Translation {
  id          String   @id @default(uuid())
  contentId   String
  locale      String   // e.g., "en-US", "fr-FR", "fr-CA"
  title       String
  body        String   @db.Text
  isOriginal  Boolean  @default(false)

  // Relations
  content     Content  @relation(fields: [contentId], references: [id], onDelete: Cascade)

  @@unique([contentId, locale]) // Prevents duplicate locales for the same content
  @@index([locale])
}

enum Status {
  DRAFT
  PUBLISHED
  ARCHIVED
}
```

