### 3. Backend Implementation (NestJS)

We need a service that handles **Locale Fallbacks**. If a user requests `fr-CA` but only `fr-FR` exists, we should intelligently decide what to return.

```typescript
// content.service.ts
import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from './prisma.service';

@Injectable()
export class ContentService {
  constructor(private prisma: PrismaService) {}

  async getLocalizedContent(slug: string, requestedLocale: string) {
    // 1. Fetch content with the requested locale AND the original locale
    const content = await this.prisma.content.findUnique({
      where: { slug },
      include: {
        translations: {
          where: {
            OR: [
              { locale: requestedLocale },
              { isOriginal: true }
            ]
          }
        }
      }
    });

    if (!content) throw new NotFoundException('Content not found');

    // 2. Logic: Priority -> Requested Locale -> Original Locale
    const preferred = content.translations.find(t => t.locale === requestedLocale);
    const fallback = content.translations.find(t => t.isOriginal);

    return {
      id: content.id,
      slug: content.slug,
      locale: preferred?.locale || fallback?.locale,
      data: preferred || fallback,
      isFallback: !preferred
    };
  }
}
```

