### 1. Database Schema Design (The "Translation Table" Pattern)

We will use the **Translation Table pattern**. Instead of adding columns for every language (which doesn't scale), we create a separate table for translations. This allows us to support infinite languages and regional variations.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Article {
  id        String   @id @default(cuid())
  slug      String   @unique
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  // Relations
  translations ArticleTranslation[]
}

model ArticleTranslation {
  id          String   @id @default(cuid())
  articleId   String
  locale      String   // e.g., "en-US", "pt-BR", "pt-PT"
  title       String
  content     String   @db.Text
  isPublished Boolean  @default(false)

  article     Article  @relation(fields: [articleId], references: [id], onDelete: Cascade)

  @@unique([articleId, locale]) // Prevents duplicate translations for the same locale
  @@index([locale])
}
```

