### 2. Implementation: The Backend Logic

We need a utility to fetch the correct version of content based on a user's locale, with a "fallback" mechanism (e.g., if `pt-BR` is missing, try `pt` or `en`).

```typescript
// lib/api/articles.ts
import { prisma } from "@/lib/prisma";

export async function getArticleBySlug(slug: string, locale: string) {
  const article = await prisma.article.findUnique({
    where: { slug },
    include: {
      translations: {
        where: {
          // We try to match the exact locale (e.g., 'en-US')
          // In a production app, you'd add fallback logic here
          locale: locale,
          isPublished: true,
        },
      },
    },
  });

  if (!article || article.translations.length === 0) {
    return null;
  }

  // Return the base article combined with the specific translation
  return {
    id: article.id,
    slug: article.slug,
    ...article.translations[0],
  };
}
```

