### 2. Database Schema (Prisma)

A common mistake is putting translations in columns (e.g., `title_en`, `title_fr`). This doesn't scale. We will use a **Translation Table** pattern.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-id"
}

model Content {
  id        String   @id @default(cuid())
  slug      String   @unique // The unique identifier in the URL
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  // Relations
  translations ContentTranslation[]

  @@index([slug])
}

model ContentTranslation {
  id          String   @id @default(cuid())
  contentId   String
  content     Content  @relation(fields: [contentId], references: [id], onDelete: Cascade)

  // Language & Regional Variation
  languageCode String  // e.g., "en", "pt"
  regionCode   String? // e.g., "US", "GB", "BR"

  // Localized Fields
  title       String
  body        String   @db.Text
  isPublished Boolean  @default(false)

  @@unique([contentId, languageCode, regionCode])
  @@index([languageCode, regionCode])
}
```

