### 3. Core Logic: The Data Access Layer

We need a robust way to fetch content that handles **Fallbacks**. If a user requests `en-GB` but only `en-US` exists, we should decide whether to show a fallback or a 404.

```typescript
// lib/db/content.ts
import { prisma } from "./prisma";

export async function getContentBySlug(slug: string, locale: string) {
  const [lang, region] = locale.split('-');

  // Fetch the base content and all relevant translations
  const content = await prisma.content.findUnique({
    where: { slug },
    include: {
      translations: {
        where: {
          OR: [
            { languageCode: lang, regionCode: region || null }, // Perfect match
            { languageCode: lang, regionCode: null },           // Language match, no region
            { languageCode: 'en', regionCode: null }            // Global Fallback
          ]
        }
      }
    }
  });

  if (!content || content.translations.length === 0) return null;

  // Logic to pick the best translation (Prioritize specific over general)
  const bestTranslation = 
    content.translations.find(t => t.languageCode === lang && t.regionCode === region) ||
    content.translations.find(t => t.languageCode === lang) ||
    content.translations[0];

  return {
    ...content,
    ...bestTranslation
  };
}
```

