### 4. Server Action (Data Persistence)

We use a Next.js Server Action to handle the submission. It extracts core fields and bundles everything else into the `attributes` JSONB column.

```typescript
// app/actions/create-job.ts
"use server";

import { prisma } from "@/lib/prisma";
import { INDUSTRY_CONFIG } from "@/lib/industry-fields";

export async function createJob(formData: FormData) {
  const industry = formData.get("industry") as string;
  const industryFields = INDUSTRY_CONFIG[industry];

  // 1. Extract dynamic attributes
  const attributes: Record<string, any> = {};
  Object.keys(industryFields).forEach((key) => {
    const value = formData.get(`attr_${key}`);
    // Basic casting based on config
    if (industryFields[key].type === 'boolean') {
      attributes[key] = value === 'on';
    } else {
      attributes[key] = value;
    }
  });

  // 2. Save to Postgres
  const job = await prisma.job.create({
    data: {
      title: formData.get("title") as string,
      description: formData.get("description") as string,
      location: formData.get("location") as string,
      industry: industry as any,
      roleType: formData.get("roleType") as any,
      companyId: "cl_12345", // Example ID
      attributes: attributes, // Stored as JSONB
    },
  });

  return job;
}
```

