### 1. The Database Schema
Our core `Job` model will have standard fields (title, company) and a `metadata` JSONB field for industry-specific data.

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Company {
  id    String @id @default(cuid())
  name  String
  jobs  Job[]
}

model Job {
  id              String   @id @default(cuid())
  createdAt       DateTime @default(now())
  title           String
  description     String
  location        String
  industry        Industry // Enum: TECH, HEALTHCARE, FINANCE, etc.
  roleType        RoleType // Enum: FULL_TIME, CONTRACT, etc.

  // Dynamic fields stored here
  metadata        Json     @default("{}") 

  companyId       String
  company         Company  @relation(fields: [companyId], references: [id])
}

enum Industry {
  TECH
  HEALTHCARE
  FINANCE
}

enum RoleType {
  FULL_TIME
  CONTRACT
  FREELANCE
}
