### 2. Validation Logic (The "Variable" Part)
We need a way to define what fields are required for each industry. We’ll use Zod to create a conditional schema.

```typescript
// lib/validations/job.ts
import * as z from "zod";

const baseSchema = z.object({
  title: z.string().min(3),
  industry: z.enum(["TECH", "HEALTHCARE", "FINANCE"]),
  companyId: z.string(),
});

// Dynamic metadata schemas
const techMetadata = z.object({
  techStack: z.array(z.string()),
  githubRequired: z.boolean(),
});

const healthcareMetadata = z.object({
  certificationId: z.string().min(5),
  shiftType: z.enum(["Day", "Night", "Rotating"]),
});

// Combined Schema
export const jobSchema = z.discriminatedUnion("industry", [
  baseSchema.extend({
    industry: z.literal("TECH"),
    metadata: techMetadata,
  }),
  baseSchema.extend({
    industry: z.literal("HEALTHCARE"),
    metadata: healthcareMetadata,
  }),
  // Add more industries as needed
]);
```

