### 3. Server Action for Job Creation
This handles the logic of saving both static and dynamic fields.

```typescript
// app/actions/create-job.ts
"use server";

import { db } from "@/lib/db";
import { jobSchema } from "@/lib/validations/job";
import { revalidatePath } from "next/cache";

export async function createJob(formData: any) {
  // Validate data against our dynamic schema
  const result = jobSchema.safeParse(formData);

  if (!result.success) {
    return { error: result.error.format() };
  }

  const { title, industry, companyId, metadata } = result.data;

  try {
    const job = await db.job.create({
      data: {
        title,
        industry,
        companyId,
        metadata, // Stored as JSONB
      },
    });

    revalidatePath("/");
    return { success: true, job };
  } catch (error) {
    return { error: "Database error" };
  }
}
```

