## 2. Data Architecture (Prisma Schema)

This schema handles the relationship between organizers, events, ticket tiers, and registrations.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Event {
  id          String   @id @default(cuid())
  title       String
  description String   @db.Text
  location    String
  imageUrl    String?
  startDate   DateTime
  endDate     DateTime
  organizerId String   // Clerk User ID
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  tickets     TicketType[]
  registrations Registration[]
}

model TicketType {
  id        String   @id @default(cuid())
  name      String   // e.g., "VIP", "Early Bird"
  price     Float    // 0 for free
  capacity  Int
  eventId   String
  event     Event    @relation(fields: [eventId], references: [id], onDelete: Cascade)

  registrations Registration[]
}

model Registration {
  id           String   @id @default(cuid())
  userId       String   // Clerk User ID
  ticketTypeId String
  ticketType   TicketType @relation(fields: [ticketTypeId], references: [id])
  eventId      String
  event        Event    @relation(fields: [eventId], references: [id])
  status       String   @default("confirmed") // confirmed, cancelled, pending
  stripeId     String?  // Payment tracking
  createdAt    DateTime @default(now())
}
```

