## 3. Core Feature: Event Creation Logic

Using **Server Actions** in Next.js allows us to handle form submissions securely without building separate API endpoints.

```typescript
// app/lib/actions/event.ts
"use server"

import { auth } from "@clerk/nextjs";
import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { z } from "zod";

const EventSchema = z.object({
  title: z.string().min(3),
  description: z.string().min(10),
  location: z.string().min(3),
  startDate: z.string(),
  ticketName: z.string(),
  ticketPrice: z.coerce.number(),
  capacity: z.coerce.number(),
});

export async function createEvent(formData: FormData) {
  const { userId } = auth();
  if (!userId) throw new Error("Unauthorized");

  const validatedFields = EventSchema.parse({
    title: formData.get("title"),
    description: formData.get("description"),
    location: formData.get("location"),
    startDate: formData.get("startDate"),
    ticketName: formData.get("ticketName"),
    ticketPrice: formData.get("ticketPrice"),
    capacity: formData.get("capacity"),
  });

  const event = await prisma.event.create({
    data: {
      title: validatedFields.title,
      description: validatedFields.description,
      location: validatedFields.location,
      startDate: new Date(validatedFields.startDate),
      endDate: new Date(validatedFields.startDate), // Simple default
      organizerId: userId,
      tickets: {
        create: {
          name: validatedFields.ticketName,
          price: validatedFields.ticketPrice,
          capacity: validatedFields.capacity,
        }
      }
    }
  });

  revalidatePath("/");
  return { id: event.id };
}
```

