## 4. The Registration Interface

This component handles the "Checkout" flow. In a production app, this would trigger a Stripe Checkout Session.

```tsx
// components/RegisterButton.tsx
"use client"

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { loadStripe } from "@stripe/stripe-js";

export default function RegisterButton({ ticketId, price }: { ticketId: string, price: number }) {
  const [loading, setLoading] = useState(false);

  const handleRegistration = async () => {
    setLoading(true);
    try {
      // 1. Call API to create Stripe Session
      const res = await fetch("/api/checkout", {
        method: "POST",
        body: JSON.stringify({ ticketId }),
      });
      const { sessionId } = await res.json();

      // 2. Redirect to Stripe
      const stripe = await loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY!);
      await stripe?.redirectToCheckout({ sessionId });
    } catch (error) {
      console.error("Registration failed", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Button onClick={handleRegistration} disabled={loading}>
      {price === 0 ? "Get Free Ticket" : `Buy Ticket ($${price})`}
    </Button>
  );
}
```

