### 2. Core Business Logic (`lib/actions/event.actions.ts`)

This handles the critical logic of registering for an event while ensuring we don't exceed capacity.

```typescript
"use server"

import { db } from "@/lib/db";
import { auth } from "@clerk/nextjs/server";
import { revalidatePath } from "next/cache";

export async function registerForEvent(eventId: string) {
  const { userId } = auth();
  if (!userId) throw new Error("Unauthorized");

  // Use a transaction to ensure data integrity
  return await db.$transaction(async (tx) => {
    // 1. Check event capacity
    const event = await tx.event.findUnique({
      where: { id: eventId },
      include: { _count: { select: { registrations: true } } }
    });

    if (!event) throw new Error("Event not found");
    if (event._count.registrations >= event.capacity) {
      throw new Error("Event is sold out");
    }

    // 2. Create registration
    const registration = await tx.registration.create({
      data: {
        eventId,
        userId,
        ticketCode: `TKT-${Math.random().toString(36).substring(2, 9).toUpperCase()}`,
      }
    });

    revalidatePath(`/events/${eventId}`);
    return registration;
  });
}
```

