### 2. Stripe Checkout Logic (Server Action)

Next.js Server Actions allow us to handle the checkout process securely without creating separate API endpoints.

```typescript
// app/actions/checkout.ts
"use server"

import { stripe } from "@/lib/stripe";
import { prisma } from "@/lib/prisma";
import { redirect } from "next/navigation";

export async function createCheckoutSession(formData: FormData) {
  const ticketTierId = formData.get("ticketTierId") as string;
  const userId = formData.get("userId") as string;

  const tier = await prisma.ticketTier.findUnique({
    where: { id: ticketTierId },
    include: { event: true }
  });

  if (!tier || tier.capacity <= 0) throw new Error("Ticket unavailable");

  const session = await stripe.checkout.sessions.create({
    payment_method_types: ["card"],
    line_items: [
      {
        price_data: {
          currency: "usd",
          product_data: {
            name: `${tier.event.title} - ${tier.name}`,
            description: tier.event.description,
          },
          unit_amount: tier.price,
        },
        quantity: 1,
      },
    ],
    mode: "payment",
    success_url: `${process.env.NEXT_PUBLIC_URL}/success?session_id={CHECKOUT_SESSION_ID}`,
    cancel_url: `${process.env.NEXT_PUBLIC_URL}/events/${tier.eventId}`,
    metadata: {
      userId,
      ticketTierId,
      eventId: tier.eventId,
    },
  });

  // Create a pending registration
  await prisma.registration.create({
    data: {
      userId,
      eventId: tier.eventId,
      ticketTierId: tier.id,
      status: "PENDING",
      stripeSessionId: session.id,
    },
  });

  redirect(session.url!);
}
```

