### 4. Handling Webhooks (Fulfillment)

When a payment succeeds, Stripe sends a webhook. This is where we update the database to confirm the registration.

```typescript
// app/api/webhooks/stripe/route.ts
import { headers } from "next/headers";
import { stripe } from "@/lib/stripe";
import { prisma } from "@/lib/prisma";

export async function POST(req: Request) {
  const body = await req.text();
  const signature = headers().get("Stripe-Signature") as string;

  let event;
  try {
    event = stripe.webhooks.constructEvent(
      body,
      signature,
      process.env.STRIPE_WEBHOOK_SECRET!
    );
  } catch (err) {
    return new Response("Webhook Error", { status: 400 });
  }

  if (event.type === "checkout.session.completed") {
    const session = event.data.object as any;

    await prisma.$transaction([
      // 1. Confirm Registration
      prisma.registration.update({
        where: { stripeSessionId: session.id },
        data: { status: "CONFIRMED" },
      }),
      // 2. Decrement Ticket Capacity
      prisma.ticketTier.update({
        where: { id: session.metadata.ticketTierId },
        data: { capacity: { decrement: 1 } },
      }),
    ]);
  }

  return new Response("OK", { status: 200 });
}
```

