### 2. Core Implementation: Social Graph & Posts

I've structured this using NestJS modules. Below is the logic for the **Social Service**, which handles the complex follower logic and feed generation.

#### Social Service (Followers & Following)

```typescript
// src/social/social.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class SocialService {
  constructor(private prisma: PrismaService) {}

  async followUser(followerId: string, followingId: string) {
    if (followerId === followingId) {
      throw new BadRequestException('You cannot follow yourself');
    }

    return this.prisma.follows.create({
      data: {
        followerId,
        followingId,
      },
    });
  }

  async unfollowUser(followerId: string, followingId: string) {
    return this.prisma.follows.delete({
      where: {
        followerId_followingId: { followerId, followingId },
      },
    });
  }

  async getFollowers(userId: string) {
    return this.prisma.follows.findMany({
      where: { followingId: userId },
      include: { follower: { select: { id: true, username: true } } },
    });
  }
}
```

#### Post Service (Feed with Cursor Pagination)

Standard offset pagination (`LIMIT 10 OFFSET 20`) is slow for social feeds because new posts shifting the list cause duplicates. We use **Cursor Pagination**.

```typescript
// src/posts/posts.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class PostsService {
  constructor(private prisma: PrismaService) {}

  async createPost(userId: string, content: string) {
    return this.prisma.post.create({
      data: { content, authorId: userId },
    });
  }

  async likePost(userId: string, postId: string) {
    return this.prisma.like.upsert({
      where: { userId_postId: { userId, postId } },
      create: { userId, postId },
      update: {}, // Do nothing if already liked
    });
  }

  // Generate a feed of posts from people the user follows
  async getFeed(userId: string, cursor?: string) {
    const following = await this.prisma.follows.findMany({
      where: { followerId: userId },
      select: { followingId: true },
    });

    const followingIds = following.map((f) => f.followingId);
    // Include the user's own posts in their feed
    followingIds.push(userId);

    return this.prisma.post.findMany({
      take: 10,
      skip: cursor ? 1 : 0,
      cursor: cursor ? { id: cursor } : undefined,
      where: {
        authorId: { in: followingIds },
      },
      orderBy: { createdAt: 'desc' },
      include: {
        author: { select: { username: true } },
        _count: { select: { likes: true, comments: true } },
      },
    });
  }
}
```

