### 4. Ingestion API (Fastify + TypeScript)

This service receives logs from your applications. In a production environment, we'd add a buffer (like Redis or Kafka) here, but ClickHouse handles batches very well.

```typescript
// ingest-api/src/index.ts
import Fastify from 'fastify';
import { createClient } from '@clickhouse/client';
import { z } from 'zod';

const app = Fastify({ logger: true });
const clickhouse = createClient({ host: 'http://localhost:8123' });

const LogSchema = z.object({
  level: z.enum(['INFO', 'WARN', 'ERROR', 'DEBUG']),
  service_name: z.string(),
  message: z.string(),
  metadata: z.record(z.any()).optional(),
  trace_id: z.string().uuid().optional(),
});

app.post('/ingest', async (request, reply) => {
  const result = LogSchema.safeParse(request.body);
  if (!result.success) return reply.status(400).send(result.error);

  const log = result.data;

  // Note: In high production, you would batch these in-memory 
  // and write every 1-5 seconds to ClickHouse.
  await clickhouse.insert({
    table: 'logs',
    values: [{
      ...log,
      metadata: JSON.stringify(log.metadata || {}),
      timestamp: new Date().toISOString()
    }],
    format: 'JSONEachRow',
  });

  return { status: 'accepted' };
});

app.listen({ port: 3001 });
```

