### 5. The Dashboard (Next.js)

We need a way to query these logs. This component fetches data based on filters.

**Data Fetching Server Action:**

```typescript
// dashboard/app/actions.ts
'use server';
import { createClient } from '@clickhouse/client';

const clickhouse = createClient({ host: 'http://localhost:8123' });

export async function queryLogs(filters: { service?: string, level?: string, search?: string }) {
  let query = `SELECT * FROM logs WHERE 1=1`;

  if (filters.service) query += ` AND service_name = '${filters.service}'`;
  if (filters.level) query += ` AND level = '${filters.level}'`;
  if (filters.search) query += ` AND message LIKE '%${filters.search}%'`;

  query += ` ORDER BY timestamp DESC LIMIT 100`;

  const resultSet = await clickhouse.query({ query, format: 'JSONEachRow' });
  return resultSet.json();
}
```

