### 4. The Ingestion API (`app/api/logs/route.ts`)
This endpoint receives logs from external services.

```typescript
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { z } from 'zod';

const logSchema = z.object({
  message: z.string(),
  level: z.enum(['DEBUG', 'INFO', 'WARN', 'ERROR', 'FATAL']),
  service: z.string(),
  source: z.string().optional(),
  metadata: z.record(z.any()).optional(),
});

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const validatedData = logSchema.parse(body);

    const log = await prisma.log.create({
      data: {
        ...validatedData,
        timestamp: new Date(),
      },
    });

    return NextResponse.json(log, { status: 201 });
  } catch (error) {
    return NextResponse.json({ error: 'Invalid log format' }, { status: 400 });
  }
}
```

### 5. The Query API (`app/api/query/route.ts`)
Handles filtering and searching.

```typescript
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);

  const service = searchParams.get('service');
  const level = searchParams.get('level');
  const search = searchParams.get('search');

  const logs = await prisma.log.findMany({
    where: {
      AND: [
        service ? { service } : {},
        level ? { level: level as any } : {},
        search ? { message: { contains: search, mode: 'insensitive' } } : {},
      ],
    },
    orderBy: { timestamp: 'desc' },
    take: 100,
  });

  return NextResponse.json(logs);
}
```

