### 2. Category Logic (The Tree Structure)

Handling nested categories requires fetching children recursively.

**`src/categories/categories.service.ts`**
```typescript
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class CategoriesService {
  constructor(private prisma: PrismaService) {}

  async create(data: { name: string; slug: string; parentId?: string }) {
    return this.prisma.category.create({ data });
  }

  // Returns the full category tree
  async getTree() {
    const allCategories = await this.prisma.category.findMany();
    return this.buildTree(allCategories, null);
  }

  private buildTree(categories: any[], parentId: string | null = null) {
    return categories
      .filter(cat => cat.parentId === parentId)
      .map(cat => ({
        ...cat,
        children: this.buildTree(categories, cat.id),
      }));
  }
}
```

