### 3. Product Logic (Handling Variable Attributes)

We use DTOs (Data Transfer Objects) to validate the flexible JSON input.

**`src/products/dto/create-product.dto.ts`**
```typescript
import { IsString, IsNumber, IsObject, IsOptional, IsNotEmpty } from 'class-validator';

export class CreateProductDto {
  @IsString()
  @IsNotEmpty()
  name: string;

  @IsString()
  @IsNotEmpty()
  sku: string;

  @IsNumber()
  price: number;

  @IsString()
  categoryId: string;

  @IsObject()
  @IsOptional()
  attributes: Record<string, any>; // This handles the variable specs
}
```

**`src/products/products.service.ts`**
```typescript
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { CreateProductDto } from './dto/create-product.dto';

@Injectable()
export class ProductsService {
  constructor(private prisma: PrismaService) {}

  create(dto: CreateProductDto) {
    return this.prisma.product.create({
      data: {
        ...dto,
        price: dto.price.toString(), // Prisma handles Decimal as string/Decimal objects
      },
    });
  }

  // Advanced filtering by category OR specific JSON attributes
  async findAll(categoryId?: string, color?: string) {
    return this.prisma.product.findMany({
      where: {
        ...(categoryId && { categoryId }),
        ...(color && {
          attributes: {
            path: ['color'],
            equals: color,
          },
        }),
      },
      include: { category: true },
    });
  }
}
```

