### 1. The Database Schema (Prisma)

This schema defines a self-referencing `Category` (to create a tree) and a `Product` with a JSONB field for attributes.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Category {
  id        String     @id @default(uuid())
  name      String
  slug      String     @unique
  parentId  String?
  parent    Category?  @relation("CategoryToCategory", fields: [parentId], references: [id])
  children  Category[] @relation("CategoryToCategory")
  products  Product[]
  createdAt DateTime   @default(now())
  updatedAt DateTime   @updatedAt
}

model Product {
  id          String   @id @default(uuid())
  name        String
  sku         String   @unique
  description String?
  price       Decimal  @db.Decimal(10, 2)

  // Variable attributes stored as JSONB
  // Example: { "color": "Midnight Blue", "storage": "256GB", "screen_size": 6.1 }
  attributes  Json     @default("{}")

  categoryId  String
  category    Category @relation(fields: [categoryId], references: [id])

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([attributes], type: Gin) // High-performance indexing for JSON
}
```

---

### 2. Category Logic: Handling the Tree

To fetch a full nested category tree, we implement a recursive service method.

```typescript
// categories.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from './prisma.service';

@Injectable()
export class CategoriesService {
  constructor(private prisma: PrismaService) {}

  async getCategoryTree() {
    // Fetch all categories
    const allCategories = await this.prisma.category.findMany();

    // Convert flat list to tree
    return this.buildTree(allCategories, null);
  }

  private buildTree(categories: any[], parentId: string | null = null) {
    return categories
      .filter(cat => cat.parentId === parentId)
      .map(cat => ({
        ...cat,
        children: this.buildTree(categories, cat.id)
      }));
  }
}
```

