### 4. Implementation: Querying JSONB

The service layer translates the API request into a PostgreSQL JSONB query.

```typescript
// products.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from './prisma.service';

@Injectable()
export class ProductsService {
  constructor(private prisma: PrismaService) {}

  async findAll(filters: { categorySlug?: string; attributes?: Record<string, any> }) {
    const { categorySlug, attributes } = filters;

    return this.prisma.product.findMany({
      where: {
        ...(categorySlug && { category: { slug: categorySlug } }),
        ...(attributes && {
          attributes: {
            path: [],
            equals: attributes, // Prisma's way of filtering JSONB
          },
        }),
      },
      include: { category: true },
    });
  }

  async create(data: any) {
    // In a production app, use Zod or class-validator here to 
    // validate that 'attributes' matches what the category expects
    return this.prisma.product.create({ data });
  }
}
```

