### 4. The API Implementation

We will create a structured API. Here is the core logic in `src/index.ts`.

```typescript
import Fastify from 'fastify';
import { PrismaClient } from '@prisma/client';
import { 
  serializerCompiler, 
  validatorCompiler, 
  ZodTypeProvider 
} from 'fastify-type-provider-zod';
import z from 'zod';

const prisma = new PrismaClient();
const app = Fastify().withTypeProvider<ZodTypeProvider>();

app.setValidatorCompiler(validatorCompiler);
app.setSerializerCompiler(serializerCompiler);

// --- CATEGORY ENDPOINTS ---

// Create Category (Nested)
app.post('/categories', {
  schema: {
    body: z.object({
      name: z.string(),
      slug: z.string(),
      parentId: z.string().optional(),
    })
  }
}, async (req, reply) => {
  const category = await prisma.category.create({ data: req.body });
  return category;
});

// Get Category Tree
app.get('/categories/tree', async () => {
  // Fetch root categories and include children recursively
  // Note: For massive trees, consider a materialized path or specialized query
  return prisma.category.findMany({
    where: { parentId: null },
    include: {
      children: {
        include: { children: true }
      }
    }
  });
});

// --- PRODUCT ENDPOINTS ---

// Create Product with Variable Attributes
app.post('/products', {
  schema: {
    body: z.object({
      name: z.string(),
      sku: z.string(),
      price: z.number(),
      categoryId: z.string(),
      attributes: z.record(z.any()), // This handles the dynamic nature
    })
  }
}, async (req, reply) => {
  const product = await prisma.product.create({
    data: {
      ...req.body,
      price: req.body.price.toString() // Prisma/PG Decimal handling
    }
  });
  return product;
});

// Search Products by Attribute
// Example: GET /products?color=red
app.get('/products', {
  schema: {
    query: z.record(z.string())
  }
}, async (req) => {
  const { categoryId, ...filters } = req.query;

  return prisma.product.findMany({
    where: {
      ...(categoryId && { categoryId }),
      // Advanced: Filtering inside JSONB
      attributes: {
        path: [],
        equals: filters // Simple matching
      }
    },
    include: { category: true }
  });
});

const start = async () => {
  try {
    await app.listen({ port: 3000 });
    console.log('🚀 Server ready at http://localhost:3000');
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
};

start();
```

### 5. Why this is Production-Ready

1.  **Validation (Zod):** Every request is validated before it hits the database. If a user sends a string where a number should be, the API returns a `400 Bad Request` automatically.
2.  **JSONB Performance:** In the Prisma schema, I added a `@@index([attributes], type: Gin)`. This is crucial. Without a **GIN index**, searching through millions of products by dynamic attributes (like "Find all blue shirts") would require a full table scan. With it, it's lightning fast.
3.  **Recursive Relations:** The `Category` model uses a self-relation. This allows for an infinite depth of subcategories (Electronics -> Computers -> Laptops -> Gaming).
4.  **Type Safety:** By using the Fastify Zod Provider, the `req.body` inside the route handlers is automatically typed based on the schema.
5.  **Scalable Data Model:** Using JSONB for attributes is superior to adding columns every time a new product type is added. You can store "Battery Life" for electronics and "Fabric" for clothing in the same table without migrations.

