### 3. Server Action: Logging a Book & Review

Next.js Server Actions allow us to handle form submissions securely on the server.

```typescript
// app/actions.ts
"use server"

import { db } from "@/lib/db";
import { auth } from "@/auth"; // NextAuth configuration
import { revalidatePath } from "next/cache";

export async function createReview(formData: FormData) {
  const session = await auth();
  if (!session?.user) throw new Error("Unauthorized");

  const googleId = formData.get("googleId") as string;
  const rating = parseInt(formData.get("rating") as string);
  const comment = formData.get("comment") as string;
  const bookData = JSON.parse(formData.get("bookData") as string);

  // 1. Ensure the book exists in our DB
  const book = await db.book.upsert({
    where: { googleId },
    update: {},
    create: {
      googleId,
      title: bookData.title,
      author: bookData.author,
      thumbnail: bookData.thumbnail,
      description: bookData.description,
    },
  });

  // 2. Create the review
  await db.review.create({
    data: {
      rating,
      comment,
      userId: session.user.id,
      bookId: book.id,
    },
  });

  revalidatePath("/");
}
```

