### 2. Server Actions (`app/actions.ts`)

Instead of writing `fetch` calls, we use Server Actions to handle logic directly on the server.

```typescript
"use server";

import { revalidatePath } from "next/cache";
import { prisma } from "@/lib/prisma";
import { z } from "zod";

const ReviewSchema = z.object({
  bookId: z.string(),
  userName: z.string().min(2, "Name is too short"),
  rating: z.coerce.number().min(1).max(5),
  comment: z.string().min(10, "Review must be at least 10 characters"),
});

export async function addReview(formData: FormData) {
  const validatedFields = ReviewSchema.safeParse({
    bookId: formData.get("bookId"),
    userName: formData.get("userName"),
    rating: formData.get("rating"),
    comment: formData.get("comment"),
  });

  if (!validatedFields.success) {
    return { error: "Invalid fields" };
  }

  await prisma.review.create({
    data: validatedFields.data,
  });

  revalidatePath(`/books/${validatedFields.data.bookId}`);
}

export async function addBook(formData: FormData) {
  const title = formData.get("title") as string;
  const author = formData.get("author") as string;

  await prisma.book.create({
    data: { title, author },
  });

  revalidatePath("/");
}
```

