#### Streak Logic Utility (`lib/streak-utils.ts`)
Calculating streaks is the core "business logic." We need to check consecutive days.

```typescript
import { format, subDays, isSameDay, parseISO } from 'date-fns';

export function calculateStreak(completionDates: string[]): number {
  if (completionDates.length === 0) return 0;

  const sortedDates = completionDates
    .map(d => parseISO(d))
    .sort((a, b) => b.getTime() - a.getTime());

  let streak = 0;
  let currentDate = new Date();

  // Normalize today to start of day for comparison
  currentDate.setHours(0, 0, 0, 0);

  for (let i = 0; i < sortedDates.length; i++) {
    const habitDate = sortedDates[i];
    habitDate.setHours(0, 0, 0, 0);

    const expectedDate = subDays(currentDate, streak);
    expectedDate.setHours(0, 0, 0, 0);

    if (isSameDay(habitDate, expectedDate)) {
      streak++;
    } else if (isSameDay(habitDate, currentDate) || habitDate > expectedDate) {
      continue; // Skip duplicates or future dates
    } else {
      break; // Streak broken
    }
  }

  return streak;
}
```

