```typescript
'use server'

import { createClient } from '@/utils/supabase/server';
import { revalidatePath } from 'next/cache';

export async function toggleHabit(habitId: string, date: string, isCompleted: boolean) {
  const supabase = createClient();

  if (isCompleted) {
    await supabase
      .from('completions')
      .delete()
      .match({ habit_id: habitId, completed_at: date });
  } else {
    await supabase
      .from('completions')
      .insert({ habit_id: habitId, completed_at: date });
  }

  revalidatePath('/');
}

export async function addHabit(name: string, color: string) {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();

  await supabase
    .from('habits')
    .insert({ name, color, user_id: user?.id });

  revalidatePath('/');
}
```

