### 💻 Implementation

#### 1. Habit Logic (The Streak Engine)
Calculating streaks in the frontend is more flexible for small datasets. We'll create a utility to calculate the current streak by looking at the completion dates.

```typescript
// lib/habit-utils.ts
import { differenceInDays, parseISO, startOfDay, format } from 'date-fns';

export function calculateStreak(completionDates: string[]) {
  if (completionDates.length === 0) return 0;

  // Sort dates descending
  const sortedDates = completionDates
    .map(d => startOfDay(parseISO(d)))
    .sort((a, b) => b.getTime() - a.getTime());

  let streak = 0;
  let currentDate = startOfDay(new Date());

  // If the latest completion isn't today or yesterday, streak is broken
  const diff = differenceInDays(currentDate, sortedDates[0]);
  if (diff > 1) return 0;

  // If latest is yesterday, start checking from there
  if (diff === 1) currentDate = sortedDates[0];

  for (let i = 0; i < sortedDates.length; i++) {
    const diff = differenceInDays(currentDate, sortedDates[i]);
    if (diff === 0) {
      streak++;
      currentDate.setDate(currentDate.getDate() - 1);
    } else {
      break;
    }
  }
  return streak;
}
```

#### 2. The Main Dashboard Component
Using React Query to fetch habits and their completions.

```tsx
// components/HabitList.tsx
'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import { calculateStreak } from '@/lib/habit-utils';
import { CheckCircle2, Circle, Flame, Trash2 } from 'lucide-react';
import { format } from 'date-fns';

export default function HabitList() {
  const queryClient = useQueryClient();
  const today = format(new Date(), 'yyyy-MM-dd');

  // Fetch Habits
  const { data: habits, isLoading } = useQuery({
    queryKey: ['habits'],
    queryFn: async () => {
      const { data } = await supabase
        .from('habits')
        .select(`*, completions(completed_at)`);
      return data;
    }
  });

  // Toggle Completion Mutation
  const toggleMutation = useMutation({
    mutationFn: async ({ habitId, completed }: { habitId: string, completed: boolean }) => {
      if (completed) {
        return supabase.from('completions').delete().eq('habit_id', habitId).eq('completed_at', today);
      } else {
        return supabase.from('completions').insert({ habit_id: habitId, completed_at: today });
      }
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['habits'] }),
  });

  if (isLoading) return <div className="p-8 text-center">Loading your journey...</div>;

  return (
    <div className="space-y-4">
      {habits?.map((habit) => {
        const completionDates = habit.completions.map((c: any) => c.completed_at);
        const isCompletedToday = completionDates.includes(today);
        const streak = calculateStreak(completionDates);

        return (
          <div key={habit.id} className="flex items-center justify-between p-4 bg-white border rounded-xl shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => toggleMutation.mutate({ habitId: habit.id, completed: isCompletedToday })}
                className="transition-transform active:scale-90"
              >
                {isCompletedToday ? (
                  <CheckCircle2 className="w-8 h-8 text-green-500 fill-green-50" />
                ) : (
                  <Circle className="w-8 h-8 text-slate-300" />
                )}
              </button>
              <div>
                <h3 className="font-semibold text-slate-800">{habit.name}</h3>
                <div className="flex items-center text-orange-600 font-medium text-sm">
                  <Flame className="w-4 h-4 mr-1 fill-orange-500" />
                  {streak} day streak
                </div>
              </div>
            </div>

            <div className="flex gap-2 text-slate-400">
               {/* Last 7 days mini-grid could go here */}
            </div>
          </div>
        );
      })}
    </div>
  );
}
```

