### 2. Streak Logic (`lib/streak-utils.ts`)

Calculating streaks accurately requires handling date gaps.

```typescript
import { startOfDay, subDays, isSameDay } from "date-fns";

export function calculateStreak(completions: { date: Date }[]) {
  if (completions.length === 0) return 0;

  // Sort dates descending (newest first)
  const sortedDates = completions
    .map((c) => startOfDay(new Date(c.date)))
    .sort((a, b) => b.getTime() - a.getTime());

  let streak = 0;
  let currentDate = startOfDay(new Date());

  // If the latest completion isn't today or yesterday, streak is broken
  const latest = sortedDates[0];
  if (!isSameDay(latest, currentDate) && !isSameDay(latest, subDays(currentDate, 1))) {
    return 0;
  }

  // If the latest is yesterday but not today, we start checking from yesterday
  if (isSameDay(latest, subDays(currentDate, 1)) && !isSameDay(latest, currentDate)) {
    currentDate = subDays(currentDate, 1);
  }

  for (const date of sortedDates) {
    if (isSameDay(date, currentDate)) {
      streak++;
      currentDate = subDays(currentDate, 1);
    } else if (date < currentDate) {
      break;
    }
  }

  return streak;
}
```

