### 3. Server Actions (`app/actions.ts`)

Using Next.js Server Actions to handle data mutations without creating manual API endpoints.

```typescript
"use server";

import { prisma } from "@/lib/db";
import { revalidatePath } from "next/cache";
import { auth } from "@/lib/auth"; // Your NextAuth config
import { startOfDay } from "date-fns";

export async function toggleHabit(habitId: string, isCompleted: boolean) {
  const session = await auth();
  if (!session) throw new Error("Unauthorized");

  const today = startOfDay(new Date());

  if (isCompleted) {
    await prisma.completion.create({
      data: { habitId, date: today },
    });
  } else {
    await prisma.completion.deleteMany({
      where: { habitId, date: today },
    });
  }

  revalidatePath("/");
}

export async function addHabit(title: string) {
  const session = await auth();
  if (!session?.user?.id) return;

  await prisma.habit.create({
    data: { title, userId: session.user.id },
  });

  revalidatePath("/");
}
```

