### 2. Core Logic: Server Actions (`lib/actions.ts`)
We use Server Actions to handle business logic securely on the server.

```typescript
"use server"

import { prisma } from "@/lib/db";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";

export async function createQuiz(formData: FormData, teacherId: string) {
  const title = formData.get("title") as string;
  const questionsData = JSON.parse(formData.get("questions") as string);

  await prisma.quiz.create({
    data: {
      title,
      teacherId,
      questions: {
        create: questionsData.map((q: any) => ({
          text: q.text,
          options: {
            create: q.options.map((o: any) => ({
              text: o.text,
              isCorrect: o.isCorrect,
            })),
          },
        })),
      },
    },
  });

  revalidatePath("/dashboard");
  redirect("/dashboard");
}

export async function submitQuiz(quizId: string, studentId: string, answers: Record<string, string>) {
  const quiz = await prisma.quiz.findUnique({
    where: { id: quizId },
    include: { questions: { include: { options: true } } },
  });

  if (!quiz) throw new Error("Quiz not found");

  let score = 0;
  quiz.questions.forEach((q) => {
    const selectedOptionId = answers[q.id];
    const correctOption = q.options.find((o) => o.isCorrect);
    if (selectedOptionId === correctOption?.id) {
      score++;
    }
  });

  await prisma.submission.create({
    data: {
      quizId,
      studentId,
      score: Math.round((score / quiz.questions.length) * 100),
    },
  });

  revalidatePath("/results");
  redirect("/results");
}
```

