"use client"

import { useState } from "react";
import { createQuiz } from "@/lib/actions";

export default function QuizCreator({ teacherId }: { teacherId: string }) {
  const [questions, setQuestions] = useState([{ text: "", options: [{ text: "", isCorrect: false }] }]);

  const addQuestion = () => {
    setQuestions([...questions, { text: "", options: [{ text: "", isCorrect: false }] }]);
  };

  const handleAction = async (formData: FormData) => {
    formData.append("questions", JSON.stringify(questions));
    await createQuiz(formData, teacherId);
  };

  return (
    <form action={handleAction} className="space-y-8 max-w-2xl mx-auto p-6 bg-white rounded-xl shadow-md">
      <h1 className="text-2xl font-bold">Create New Quiz</h1>
      <input 
        name="title" 
        placeholder="Quiz Title (e.g. Intro to Biology)" 
        className="w-full p-2 border rounded"
        required 
      />

      {questions.map((q, qIdx) => (
        <div key={qIdx} className="p-4 border rounded-lg bg-gray-50">
          <input
            placeholder={`Question ${qIdx + 1}`}
            className="w-full p-2 mb-2 font-semibold"
            value={q.text}
            onChange={(e) => {
              const newQs = [...questions];
              newQs[qIdx].text = e.target.value;
              setQuestions(newQs);
            }}
          />
          {q.options.map((o, oIdx) => (
            <div key={oIdx} className="flex gap-2 mb-2">
              <input
                type="radio"
                checked={o.isCorrect}
                onChange={() => {
                  const newQs = [...questions];
                  newQs[qIdx].options.forEach((opt, i) => opt.isCorrect = i === oIdx);
                  setQuestions(newQs);
                }}
              />
              <input
                placeholder="Option text"
                className="flex-1 p-1 border text-sm"
                value={o.text}
                onChange={(e) => {
                  const newQs = [...questions];
                  newQs[qIdx].options[oIdx].text = e.target.value;
                  setQuestions(newQs);
                }}
              />
            </div>
          ))}
          <button 
            type="button" 
            onClick={() => {
              const newQs = [...questions];
              newQs[qIdx].options.push({ text: "", isCorrect: false });
              setQuestions(newQs);
            }}
            className="text-sm text-blue-600 hover:underline"
          >
            + Add Option
          </button>
        </div>
      ))}

      <div className="flex justify-between">
        <button type="button" onClick={addQuestion} className="px-4 py-2 bg-gray-200 rounded">
          Add Question
        </button>
        <button type="submit" className="px-4 py-2 bg-green-600 text-white rounded">
          Publish Quiz
        </button>
      </div>
    </form>
  );
}
