### 2. Server Actions (`app/lib/actions.ts`)

Instead of building a separate REST API, we use Server Actions for better type safety and less boilerplate.

```typescript
"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { getServerSession } from "next-auth";
import { authOptions } from "@/app/api/auth/[...nextauth]/route";

export async function createQuiz(formData: any) {
  const session = await getServerSession(authOptions);
  if (session?.user.role !== "TEACHER") throw new Error("Unauthorized");

  const quiz = await prisma.quiz.create({
    data: {
      title: formData.title,
      description: formData.description,
      teacherId: session.user.id,
      questions: {
        create: formData.questions.map((q: any) => ({
          text: q.text,
          choices: {
            create: q.choices.map((c: any) => ({
              text: c.text,
              isCorrect: c.isCorrect,
            })),
          },
        })),
      },
    },
  });

  revalidatePath("/dashboard");
  return { success: true };
}

export async function submitQuiz(quizId: string, answers: Record<string, string>) {
  const session = await getServerSession(authOptions);
  if (!session) throw new Error("Unauthorized");

  const quiz = await prisma.quiz.findUnique({
    where: { id: quizId },
    include: { questions: { include: { choices: true } } },
  });

  let score = 0;
  quiz?.questions.forEach((q) => {
    const correctChoice = q.choices.find((c) => c.isCorrect);
    if (answers[q.id] === correctChoice?.id) {
      score++;
    }
  });

  await prisma.submission.create({
    data: {
      quizId,
      studentId: session.user.id,
      score: Math.round((score / (quiz?.questions.length || 1)) * 100),
    },
  });

  revalidatePath("/dashboard");
  return { score };
}
```

