"use client";

import { useState } from "react";
import { submitQuiz } from "@/app/lib/actions";

export default function TakeQuiz({ params, quiz }: { params: { id: string }, quiz: any }) {
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [result, setResult] = useState<number | null>(null);

  const handleSubmit = async () => {
    const res = await submitQuiz(params.id, answers);
    setResult(res.score);
  };

  if (result !== null) {
    return (
      <div className="text-center p-10">
        <h2 className="text-4xl font-bold">Quiz Complete!</h2>
        <p className="text-2xl mt-4">Your Score: {result}%</p>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto p-6">
      <h1 className="text-2xl font-bold mb-6">{quiz.title}</h1>
      {quiz.questions.map((q: any) => (
        <div key={q.id} className="mb-8">
          <p className="font-medium mb-3">{q.text}</p>
          {q.choices.map((c: any) => (
            <label key={c.id} className="flex items-center gap-3 p-3 border rounded mb-2 cursor-pointer hover:bg-gray-50">
              <input
                type="radio"
                name={q.id}
                onChange={() => setAnswers({ ...answers, [q.id]: c.id })}
              />
              {c.text}
            </label>
          ))}
        </div>
      ))}
      <button 
        onClick={handleSubmit}
        className="bg-blue-600 text-white px-6 py-2 rounded-lg"
      >
        Submit Answers
      </button>
    </div>
  );
}
