### 2. The Encryption Core Service

This service handles the heavy lifting of encrypting data and generating searchable blind indices.

```typescript
// src/vault/vault.service.ts
import { Injectable } from '@nestjs/common';
import * as crypto from 'crypto';

@Injectable()
export class VaultService {
  // In production, these would be fetched from AWS KMS or HashiCorp Vault
  private readonly ENCRYPTION_KEY = Buffer.from(process.env.MASTER_KEY, 'hex'); // 32 bytes
  private readonly BLIND_INDEX_ROOT_KEY = process.env.BLIND_INDEX_KEY; 
  private readonly ALGORITHM = 'aes-256-gcm';

  /**
   * Encrypts PII and generates a Blind Index for searching
   */
  encryptField(value: string): { ciphertext: string; blindIndex: string } {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv(this.ALGORITHM, this.ENCRYPTION_KEY, iv);

    let encrypted = cipher.update(value, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag().toString('hex');

    // Format: iv:authTag:encryptedValue
    const ciphertext = `${iv.toString('hex')}:${authTag}:${encrypted}`;
    const blindIndex = this.generateBlindIndex(value);

    return { ciphertext, blindIndex };
  }

  decryptField(ciphertext: string): string {
    const [ivHex, authTagHex, encryptedHex] = ciphertext.split(':');
    const decipher = crypto.createDecipheriv(
      this.ALGORITHM,
      this.ENCRYPTION_KEY,
      Buffer.from(ivHex, 'hex')
    );
    decipher.setAuthTag(Buffer.from(authTagHex, 'hex'));

    let decrypted = decipher.update(encryptedHex, 'hex', 'utf8');
    decrypted += decipher.final('utf8');
    return decrypted;
  }

  /**
   * Creates a deterministic hash of the value.
   * We normalize (lowercase/trim) so 'John' and 'john' produce the same index.
   */
  generateBlindIndex(value: string): string {
    return crypto
      .createHmac('sha256', this.BLIND_INDEX_ROOT_KEY)
      .update(value.toLowerCase().trim())
      .digest('hex');
  }
}
```

