### 3. Core Implementation

#### A. The Cryptographic Utility (`crypto.ts`)
This is the heart of the vault. It handles encryption, decryption, and blind index generation.

```typescript
import crypto from 'node:crypto';

// In production, these would be fetched from a Key Management Service (KMS)
const MASTER_KEY = Buffer.from(process.env.MASTER_KEY || '', 'hex'); // 32 bytes
const SEARCH_PEPPER = process.env.SEARCH_PEPPER || 'default-pepper';

export interface EncryptedResult {
  encryptedData: string; // Base64 ciphertext
  iv: string;            // Initialization Vector
  authTag: string;       // GCM Auth Tag
}

export class PrivacyEngine {
  /**
   * Standard AES-256-GCM encryption
   */
  static encrypt(plaintext: string): EncryptedResult {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', MASTER_KEY, iv);

    let encrypted = cipher.update(plaintext, 'utf8', 'base64');
    encrypted += cipher.final('base64');

    return {
      encryptedData: encrypted,
      iv: iv.toString('base64'),
      authTag: cipher.getAuthTag().toString('base64'),
    };
  }

  /**
   * Standard AES-256-GCM decryption
   */
  static decrypt(encrypted: EncryptedResult): string {
    const decipher = crypto.createDecipheriv(
      'aes-256-gcm', 
      MASTER_KEY, 
      Buffer.from(encrypted.iv, 'base64')
    );

    decipher.setAuthTag(Buffer.from(encrypted.authTag, 'base64'));

    let decrypted = decipher.update(encrypted.encryptedData, 'base64', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  /**
   * Blind Indexing: Creates a non-reversible hash for searching.
   * We use HMAC so the hash is unique to our vault and pepper.
   */
  static generateBlindIndex(value: string): string {
    return crypto
      .createHmac('sha256', SEARCH_PEPPER)
      .update(value.toLowerCase().trim())
      .digest('hex');
  }
}
```

#### B. The Vault Service (`vault.service.ts`)
This service interacts with the database to store and retrieve tokens.

```typescript
import { PrivacyEngine } from './crypto';
import { db } from './db'; // Assume a standard Prisma or Kysely client

export class VaultService {
  /**
   * Store PII and return a "Token" (UUID)
   */
  async tokenizeRecord(pii: { email: string; fullName: string; ssn: string }) {
    // 1. Generate Blind Indexes for searchable fields
    const emailIndex = PrivacyEngine.generateBlindIndex(pii.email);

    // 2. Encrypt the full payload
    const encryptedPayload = PrivacyEngine.encrypt(JSON.stringify(pii));

    // 3. Store in DB
    const record = await db.vault.create({
      data: {
        email_index: emailIndex,
        ciphertext: encryptedPayload.encryptedData,
        iv: encryptedPayload.iv,
        tag: encryptedPayload.authTag,
      }
    });

    return record.id; // Return the token to the main SaaS app
  }

  /**
   * Search records using the blind index
   */
  async findByEmail(email: string) {
    const index = PrivacyEngine.generateBlindIndex(email);

    const results = await db.vault.findMany({
      where: { email_index: index }
    });

    // Note: We return the records, but they are still encrypted!
    return results;
  }
}
```

