### 2. The Database Schema (The Core)

The key to "infinite nesting" is a self-referencing relationship. The key to "extensible licensing" is using a `JSONB` column for metadata combined with a `ContentType` discriminator.

```prisma
// schema.prisma

enum ContentType {
  MOVIE
  PODCAST
  SERIES
}

model Category {
  id        String     @id @default(cuid())
  name      String
  parentId  String?    // Null means it's a root category
  parent    Category?  @relation("SubCategories", fields: [parentId], references: [id])
  children  Category[] @relation("SubCategories")
  content   Content[]
}

model Content {
  id          String      @id @default(cuid())
  title       String
  type        ContentType
  categoryId  String
  category    Category    @relation(fields: [categoryId], references: [id])
  licenses    License[]
}

model License {
  id              String      @id @default(cuid())
  contentId       String
  content         Content     @relation(fields: [contentId], references: [id])
  regionCode      String      // ISO 3166-1 alpha-2 (e.g., "US", "GB")
  isAvailable     Boolean     @default(true)

  // This JSONB field allows us to add "podcast-only" or "movie-only" fields
  // like "max_bitrate", "ad_supported", or "guest_requirements"
  licensingTerms  Json        

  startsAt        DateTime
  endsAt          DateTime?
}
