### 3. Backend Logic: Dynamic Licensing Validation

When a user adds a new license for a Podcast, we need to ensure the fields provided are valid for a Podcast. We use a **Strategy Pattern** combined with **Zod**.

```typescript
// lib/licensing/validation.ts
import { z } from 'zod';
import { ContentType } from '@prisma/client';

// Define specific fields for different content types
const MovieLicenseSchema = z.object({
  resolution_limit: z.enum(['4K', 'HD', 'SD']),
  drm_provider: z.string(),
});

const PodcastLicenseSchema = z.object({
  ad_insertion_enabled: z.boolean(),
  exclusive_platform: z.string().optional(),
});

// Selector function to get the right validator
export const getLicenseValidator = (type: ContentType) => {
  switch (type) {
    case 'MOVIE': return MovieLicenseSchema;
    case 'PODCAST': return PodcastLicenseSchema;
    default: throw new Error('Unsupported content type');
  }
};
```

