### 6. Regional Access Middleware

We must prevent users from accessing content restricted in their region. We can use Vercel/Cloudflare Edge headers to detect location.

```typescript
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  // Get country from headers (provided by most modern CDNs/Platforms)
  const country = request.headers.get('x-vercel-ip-country') || 'US';

  // Clone request headers and inject country for use in Server Components
  const requestHeaders = new Headers(request.headers);
  requestHeaders.set('x-user-region', country);

  return NextResponse.next({
    request: { headers: requestHeaders },
  });
}
```

