## 2. Backend Implementation (NestJS)

We need a service that can resolve the recursive category tree and filter media based on the user's region.

### Category Service (Infinite Nesting)

```typescript
// src/categories/categories.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma.service';

@Injectable()
export class CategoriesService {
  constructor(private prisma: PrismaService) {}

  // Fetches the entire tree structure
  async getCategoryTree() {
    const allCategories = await this.prisma.category.findMany();
    return this.buildTree(allCategories, null);
  }

  private buildTree(dataset: any[], parentId: string | null = null) {
    return dataset
      .filter(item => item.parentId === parentId)
      .map(item => ({
        ...item,
        children: this.buildTree(dataset, item.id),
      }));
  }
}
```

### Media Service (Regional Licensing & Dynamic Fields)

This service ensures a user only sees content available in their region.

```typescript
// src/media/media.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma.service';

@Injectable()
export class MediaService {
  constructor(private prisma: PrismaService) {}

  async getMediaForRegion(region: string, categoryId?: string) {
    return this.prisma.media.findMany({
      where: {
        categoryId,
        licenses: {
          some: {
            regionCode: region,
            isAvailable: true,
            OR: [
              { expiresAt: null },
              { expiresAt: { gt: new Date() } }
            ]
          }
        }
      },
      include: {
        licenses: {
          where: { regionCode: region }
        }
      }
    });
  }

  // Example of how we handle dynamic updates
  async updateMediaMetadata(id: string, newFields: Record<string, any>) {
    return this.prisma.media.update({
      where: { id },
      data: {
        metadata: {
          upsert: newFields // Prisma supports merging JSONB
        }
      }
    });
  }
}
```

