import { TrendingService } from './services/TrendingService';
import { Server } from 'socket.io';

const trendingService = new TrendingService();

export function startLeaderboardBroadcaster(io: Server) {
  // Update every 10 seconds as requested
  setInterval(async () => {
    try {
      const top100 = await trendingService.getTopTrending();

      // Broadcast to all connected clients
      io.emit('trending_update', {
        timestamp: Date.now(),
        data: top100
      });

      // Optional: Batch persist top posts to Postgres for historical tracking
      // await persistToMainDB(top100);

    } catch (error) {
      console.error('Error broadcasting leaderboard:', error);
    }
  }, 10000);
}
```

