#### `leaderboard.go`: The Redis Engine
This component handles the atomic incrementing of engagement scores.

```go
package main

import (
	"context"
	"fmt"
	"time"

	"github.com/redis/go-redis/v9"
)

var ctx = context.Background()

type EngagementStore struct {
	rdb *redis.Client
}

// RecordEngagement increments the score for a post in the current hour's bucket
func (s *EngagementStore) RecordEngagement(postID string, weight int) error {
	// Key format: leaderboard:YYYYMMDDHH
	hourKey := fmt.Sprintf("leaderboard:%s", time.Now().Format("2006010215"))

	// ZIncrBy is atomic. It creates the key if it doesn't exist.
	err := s.rdb.ZIncrBy(ctx, hourKey, float64(weight), postID).Err()
	if err != nil {
		return err
	}

	// Set expiration to 2 hours so we don't leak memory, 
	// but keep data long enough for overlap analysis
	return s.rdb.Expire(ctx, hourKey, 2*time.Hour).Err()
}

// GetTopPosts retrieves the top 100 posts
func (s *EngagementStore) GetTopPosts() ([]redis.Z, error) {
	hourKey := fmt.Sprintf("leaderboard:%s", time.Now().Format("2006010215"))
	return s.rdb.ZRevRangeWithScores(ctx, hourKey, 0, 99).Result()
}
```

#### `main.go`: The High-Concurrency Server
We use Go's `http` package and a ticker to broadcast updates.

```go
package main

import (
	"encoding/json"
	"log"
	"net/http"
	"time"

	"github.com/gorilla/websocket"
	"github.com/redis/go-redis/v9"
)

var upgrader = websocket.Upgrader{
	CheckOrigin: func(r *http.Request) bool { return true },
}

func main() {
	rdb := redis.NewClient(&redis.Options{Addr: "localhost:6379"})
	store := &EngagementStore{rdb: rdb}

	// 1. Endpoint to receive engagement (High Velocity)
	http.HandleFunc("/engage", func(w http.ResponseWriter, r *http.Request) {
		postID := r.URL.Query().Get("id")
		action := r.URL.Query().Get("type") // like, share, comment

		// Weighting logic
		weight := 1
		if action == "share" { weight = 3 }
		if action == "comment" { weight = 2 }

		// Fire and forget to Redis
		go store.RecordEngagement(postID, weight)
		w.WriteHeader(http.StatusAccepted)
	})

	// 2. WebSocket for Live Leaderboard updates
	http.HandleFunc("/ws/leaderboard", func(w http.ResponseWriter, r *http.Request) {
		conn, err := upgrader.Upgrade(w, r, nil)
		if err != nil {
			return
		}
		defer conn.Close()

		// Ticker set to 10 seconds as per requirement
		ticker := time.NewTicker(10 * time.Second)
		defer ticker.Stop()

		for range ticker.C {
			topPosts, err := store.GetTopPosts()
			if err != nil {
				log.Println("Error fetching leaderboard:", err)
				continue
			}

			payload, _ := json.Marshal(topPosts)
			if err := conn.WriteMessage(websocket.TextMessage, payload); err != nil {
				return
			}
		}
	})

	log.Println("Server started on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

