### 3. The Pricing Engine (Core Logic)

This service fetches all variables from Redis (the Speed Layer) and applies the business logic.

```typescript
// src/services/pricingEngine.ts
import Redis from 'ioredis';

const redis = new Redis(process.env.REDIS_URL);

interface PriceContext {
  userId: string;
  sku: string;
  geoRegion: string;
}

export const calculateDynamicPrice = async (ctx: PriceContext) => {
  // Fetch all variables in parallel for minimum latency
  const [basePriceStr, loyaltySpend, stockLevel, geoDemand] = await Promise.all([
    redis.get(`prod:base_price:${ctx.sku}`),
    redis.get(`user:12m_spend:${ctx.userId}`),
    redis.get(`prod:stock:${ctx.sku}`),
    redis.get(`demand:region:${ctx.geoRegion}`),
  ]);

  const basePrice = parseFloat(basePriceStr || '100');
  let discount = 0;
  let multiplier = 1.0;

  // 1. Loyalty Discount (User History)
  // If user spent > $1000 in 12 months, 10% discount
  if (parseFloat(loyaltySpend || '0') > 1000) {
    discount += 0.10;
  }

  // 2. Inventory Logic (Warehouse Stock)
  // If stock is high (> 500), add 5% discount to move inventory
  // If stock is low (< 10), add 15% scarcity premium
  const stock = parseInt(stockLevel || '0');
  if (stock > 500) discount += 0.05;
  if (stock < 10) multiplier += 0.15;

  // 3. Geographic Demand
  // If demand in region is "high" (value > 100), increase price by 10%
  const demand = parseInt(geoDemand || '0');
  if (demand > 100) multiplier += 0.10;

  // Final Calculation
  const finalPrice = (basePrice * (1 - discount)) * multiplier;

  return {
    originalPrice: basePrice,
    dynamicPrice: Math.round(finalPrice * 100) / 100,
    appliedDiscount: (discount * 100).toFixed(0) + '%',
    surcharge: ((multiplier - 1) * 100).toFixed(0) + '%',
  };
};
```

