### 2. The Pricing Engine (Core Logic)

This service lives in a high-performance utility file. It calculates the discount based on the three requested vectors.

```typescript
// lib/pricing-engine.ts
import { Redis } from '@upstash/redis';

const redis = Redis.fromEnv();

interface PricingFactors {
  userId: string;
  productId: string;
  basePrice: number;
  userSpend12m: number;
  region: string;
}

export async function calculateDynamicPrice({
  userId,
  productId,
  basePrice,
  userSpend12m,
  region
}: PricingFactors) {
  // 1. Fetch Real-time Stock from Redis (High Speed)
  const stockLevel = await redis.get<number>(`stock:${productId}`) ?? 0;

  // 2. Fetch Regional Demand Multiplier (0.8 to 1.2)
  const regionalDemand = await redis.get<number>(`demand:${region}`) ?? 1.0;

  let discount = 0;

  // Logic A: Loyalty Discount (12-month history)
  if (userSpend12m > 5000) discount += 0.15; // 15% for VIPs
  else if (userSpend12m > 1000) discount += 0.05;

  // Logic B: Stock Clearing (Inventory > 100 units)
  if (stockLevel > 100) discount += 0.10;

  // Logic C: Geographic Demand (Inverse pricing)
  // If demand is low (< 0.9), add a "Stimulus" discount
  const demandAdjustment = regionalDemand < 0.9 ? 0.05 : 0;

  const finalDiscount = Math.min(discount + demandAdjustment, 0.40); // Cap at 40%
  const finalPrice = basePrice * (1 - finalDiscount);

  return {
    originalPrice: basePrice,
    discountedPrice: Number(finalPrice.toFixed(2)),
    appliedDiscount: (finalDiscount * 100).toFixed(0) + "%",
    factors: { stockLevel, regionalDemand, userSpend12m }
  };
}
```

