### 3. The Low-Latency API Route (Edge Runtime)

We use the Edge Runtime to handle the request. This avoids the "Cold Start" of heavy Node.js environments.

```typescript
// app/api/get-price/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { calculateDynamicPrice } from '@/lib/pricing-engine';
import { prisma } from '@/lib/db'; // Initialized Prisma client

export const runtime = 'edge'; // Crucial for latency

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const userId = searchParams.get('userId');
  const productId = searchParams.get('productId');

  // Get Region from Vercel Edge Headers (No Geo-IP lookup needed!)
  const region = req.headers.get('x-vercel-ip-country') || 'US';

  if (!userId || !productId) {
    return NextResponse.json({ error: 'Missing parameters' }, { status: 400 });
  }

  // 1. Get 12-month spend (SQL)
  // In production, you'd cache this sum in Redis and update on every order
  const twelveMonthsAgo = new Date();
  twelveMonthsAgo.setFullYear(twelveMonthsAgo.getFullYear() - 1);

  const stats = await prisma.order.aggregate({
    where: {
      userId,
      createdAt: { gte: twelveMonthsAgo }
    },
    _sum: { totalAmount: true }
  });

  // 2. Get Product Base Price
  const product = await prisma.product.findUnique({
    where: { id: productId }
  });

  if (!product) return NextResponse.json({ error: 'Product not found' }, { status: 404 });

  // 3. Calculate Price
  const pricingData = await calculateDynamicPrice({
    userId,
    productId,
    basePrice: product.basePrice,
    userSpend12m: stats._sum.totalAmount || 0,
    region
  });

  return NextResponse.json(pricingData);
}
```

