### Part 1: Database Schema

We need two primary tables for usage. One for the raw "events" (audit trail) and one for "daily aggregates" (performance).

```sql
-- Track every single usage event for auditing
CREATE TABLE usage_events (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    customer_id TEXT NOT NULL,
    feature_id TEXT NOT NULL, -- e.g., 'emails_sent', 'storage_mb'
    quantity INTEGER NOT NULL,
    idempotency_key TEXT UNIQUE NOT NULL, -- Prevents double counting
    recorded_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Summary table for fast querying and monthly invoicing
CREATE TABLE usage_daily_aggregates (
    customer_id TEXT NOT NULL,
    feature_id TEXT NOT NULL,
    usage_date DATE NOT NULL,
    total_quantity BIGINT DEFAULT 0,
    last_updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    PRIMARY KEY (customer_id, feature_id, usage_date)
);

CREATE INDEX idx_usage_events_customer_date ON usage_events(customer_id, recorded_at);
```

---

### Part 2: The Application Code

#### 1. Event Ingestion API (`/src/server.ts`)
This API receives usage events and pushes them to a queue.

```typescript
import Fastify from 'fastify';
import { Queue } from 'bullmq';
import Redis from 'ioredis';

const fastify = Fastify({ logger: true });
const redisConnection = new Redis(process.env.REDIS_URL!);
const usageQueue = new Queue('usage-events', { connection: redisConnection });

fastify.post('/track-usage', async (request, reply) => {
  const { customerId, featureId, quantity, idempotencyKey } = request.body as any;

  // 1. Push to queue immediately to keep API response time low
  await usageQueue.add('process-usage', {
    customerId,
    featureId,
    quantity,
    idempotencyKey,
    timestamp: new Date()
  }, {
    // BullMQ ensures the job is only added once per idempotency key
    jobId: idempotencyKey 
  });

  return { status: 'accepted' };
});

fastify.listen({ port: 3000 });
```

#### 2. The Worker (`/src/worker.ts`)
The worker processes the queue and updates the database using an **Atomic Upsert**.

```typescript
import { Worker } from 'bullmq';
import { Pool } from 'pg';

const pgPool = new Pool({ connectionString: process.env.DATABASE_URL });

const worker = new Worker('usage-events', async (job) => {
  const { customerId, featureId, quantity, idempotencyKey, timestamp } = job.data;
  const client = await pgPool.connect();

  try {
    await client.query('BEGIN');

    // 1. Insert raw event (will fail if idempotencyKey exists)
    await client.query(
      `INSERT INTO usage_events (customer_id, feature_id, quantity, idempotency_key, recorded_at)
       VALUES ($1, $2, $3, $4, $5)`,
      [customerId, featureId, quantity, idempotencyKey, timestamp]
    );

    // 2. Atomic Upsert into Daily Aggregates
    const date = new Date(timestamp).toISOString().split('T')[0];
    await client.query(
      `INSERT INTO usage_daily_aggregates (customer_id, feature_id, usage_date, total_quantity)
       VALUES ($1, $2, $3, $4)
       ON CONFLICT (customer_id, feature_id, usage_date)
       DO UPDATE SET 
         total_quantity = usage_daily_aggregates.total_quantity + EXCLUDED.total_quantity,
         last_updated_at = NOW()`,
      [customerId, featureId, date, quantity]
    );

    await client.query('COMMIT');
  } catch (err: any) {
    await client.query('ROLLBACK');
    if (err.code === '23505') { // Unique violation (idempotency)
      console.log(`Duplicate event skipped: ${idempotencyKey}`);
      return;
    }
    throw err; // Retry via BullMQ
  } finally {
    client.release();
  }
}, { connection: redisConnection });
```

#### 3. Monthly Sync to Stripe (`/src/cron/sync-stripe.ts`)
Run this once a day or once an hour to sync the internal aggregates to Stripe’s Metered Billing engine.

```typescript
import Stripe from 'stripe';
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, { apiVersion: '2023-10-16' });

async function syncUsageToStripe() {
  // Get all usage from the last 24 hours that hasn't been synced
  const results = await pgPool.query(`
    SELECT customer_id, feature_id, SUM(total_quantity) as total
    FROM usage_daily_aggregates
    WHERE last_updated_at > NOW() - INTERVAL '24 hours'
    GROUP BY customer_id, feature_id
  `);

  for (const row of results.rows) {
    // Stripe Subscription Item ID should be stored in your User/Customer table
    const subscriptionItemId = await getStripeSubItemId(row.customer_id, row.feature_id);

    await stripe.subscriptionItems.createUsageRecord(
      subscriptionItemId,
      {
        quantity: parseInt(row.total),
        timestamp: Math.floor(Date.now() / 1000),
        action: 'increment',
      }
    );
  }
}
```

---

### Technical Decisions & Production Readiness

1.  **Why the Queue?** If your app sends 1,000 "Email Sent" events per second, writing directly to Postgres would lock the table and slow down your users. The queue (BullMQ) buffers these writes, allowing Postgres to handle them in a controlled stream.
2.  **Idempotency Keys:** This is the most important part of billing. If a network glitch causes the client to retry the `track-usage` call, the `idempotencyKey` ensures you don't charge the customer twice for the same email.
3.  **Daily Aggregates Table:** Querying `usage_events` (millions of rows) to show a customer their current bill would be slow. The `usage_daily_aggregates` table makes the dashboard extremely fast by pre-calculating the totals.
4.  **Stripe Integration:** By using Stripe's `createUsageRecord`, you offload the complex logic of:
    *   Calculating the final price based on tiers (e.g., $0.01 for the first 1k emails, $0.005 after).
    *   Generating the PDF invoice.
    *   Handling failed credit card payments.

### Next Steps for Production
*   **Monitoring:** Set up alerts if the BullMQ "failed" count increases (usually means DB connection issues).
*   **Data Retention:** Move `usage_events` older than 90 days to cold storage (S3/BigQuery) to keep the Postgres DB lean.
*   **Verification:** Periodically run a script to compare the sum of `usage_events` against `usage_daily_aggregates` to ensure data integrity.

This is a sophisticated architectural challenge. Building a multi-language content platform requires a focus on **SEO**, **performance**, and a **normalized database schema** that can handle both translations (e.g., English to French) and regional variations (e.g., US English vs. UK English).

### Technical Stack Selection

| Component | Choice | Alternatives | Why? |
| :--- | :--- | :--- | :--- |
| **Frontend** | **Next.js (App Router)** | Remix, Vue/Nuxt | Next.js offers built-in Internationalized Routing, superior SEO via Server-Side Rendering, and middleware for locale detection. |
| **Backend** | **Next.js API Routes** | Express, Go | For this scope, keeping the API within Next.js reduces deployment complexity and allows sharing of TypeScript types between the frontend and backend. |
| **Database** | **PostgreSQL** | MongoDB, MySQL | PostgreSQL is excellent for relational data. The "One Content -> Many Translations" relationship is strictly relational. |
| **ORM** | **Prisma** | Drizzle, TypeORM | Prisma’s schema-driven approach makes managing complex relations between content and translations highly intuitive. |
| **Styling** | **Tailwind CSS** | CSS Modules | Rapid UI development and handles Right-to-Left (RTL) layouts (like Arabic/Hebrew) easily via utility classes. |

---

### 1. Database Schema (The Foundation)

The core of a multi-language platform is the **Translation Table Pattern**. We separate the "Metadata" (ID, author, timestamps) from the "Localized Content" (Title, Body, Slug).

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Content {
  id        String   @id @default(cuid())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt
  author    String
  status    String   @default("DRAFT") // DRAFT, PUBLISHED

  // Relations
  translations Translation[]
}

model Translation {
  id        String   @id @default(cuid())
  contentId String
  locale    String   // e.g., "en-US", "en-GB", "fr-FR"
  title     String
  slug      String   @unique
  body      String   @db.Text

  // Regional variation flags
  region    String?  // e.g., "US", "GB"

  content   Content  @relation(fields: [contentId], references: [id], onDelete: Cascade)

  @@unique([contentId, locale]) // Prevents duplicate locales for the same content
  @@index([locale, slug])       // Optimized for lookup
}
```

---

### 2. Implementation: The Content API

We need a service layer to fetch content based on the user's requested locale, with a "fallback" mechanism (e.g., if a page isn't translated into French, show English).

```typescript
// lib/api-content.ts
import { prisma } from './prisma';

export async function getContentBySlug(slug: string, locale: string) {
  // 1. Try to find the specific locale/variation
  let translation = await prisma.translation.findUnique({
    where: { slug },
    include: { content: true }
  });

  // 2. Fallback logic: If the slug doesn't match or the locale is wrong, 
  // find the content ID and get the 'en-US' version.
  if (!translation || translation.locale !== locale) {
    const baseContent = await prisma.translation.findFirst({
      where: { 
        content: { translations: { some: { slug } } },
        locale: 'en-US' // Default fallback
      },
      include: { content: true }
    });
    return baseContent;
  }

  return translation;
}
```

---

### 3. Frontend: Multi-Language Routing

Next.js App Router uses a `[locale]` folder structure to handle paths like `/en/about` or `/fr/about`.

**File Structure:**
```text
/app
  /[locale]
    /layout.tsx
    /posts
      /[slug]
        /page.tsx
  /middleware.ts
```

**Middleware for Language Detection:**
```typescript
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { match } from '@formatjs/intl-localematcher';
import Negotiator from 'negotiator';

let locales = ['en-US', 'en-GB', 'fr-FR', 'de-DE'];
let defaultLocale = 'en-US';

function getLocale(request: NextRequest) {
  const headers = { 'accept-language': request.headers.get('accept-language') || '' };
  const languages = new Negotiator({ headers }).languages();
  return match(languages, locales, defaultLocale);
}

export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;
  const pathnameHasLocale = locales.some(
    (locale) => pathname.startsWith(`/${locale}/`) || pathname === `/${locale}`
  );

  if (pathnameHasLocale) return;

  const locale = getLocale(request);
  request.nextUrl.pathname = `/${locale}${pathname}`;
  return NextResponse.redirect(request.nextUrl);
}

export const config = {
  matcher: ['/((?!api|_next/static|_next/image|favicon.ico).*)'],
};
```

