### 4. The Dynamic Content Page

This page fetches data based on the URL params and displays the specific regional variation.

```tsx
// app/[locale]/posts/[slug]/page.tsx
import { getContentBySlug } from '@/lib/api-content';
import { notFound } from 'next/navigation';

export default async function PostPage({ params }: { params: { locale: string, slug: string } }) {
  const data = await getContentBySlug(params.slug, params.locale);

  if (!data) notFound();

  return (
    <article className="max-w-4xl mx-auto py-12 px-4">
      {/* Regional Notification */}
      {data.locale !== params.locale && (
        <div className="bg-amber-100 p-4 mb-6 rounded text-amber-800">
          This content is not available in your language yet. Showing English version.
        </div>
