          Locale: {data.locale}
        </span>
        <h1 className="text-4xl font-extrabold mt-2">{data.title}</h1>
      </header>

      <div 
        className="prose lg:prose-xl"
        dangerouslySetInnerHTML={{ __html: data.body }} 
      />
    </article>
  );
}
