### 1. The Database Schema (The Foundation)

A common mistake is putting translations in columns (e.g., `title_en`, `title_fr`). This isn't scalable. Instead, we use a **One-to-Many relationship** between a `Content` entity and its `Translation` variants.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Article {
  id        String   @id @default(cuid())
  slug      String   @unique // The identifier used in the URL
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  // Relations
  translations Translation[]
}

model Translation {
  id        String   @id @default(cuid())
  articleId String
  article   Article  @relation(fields: [articleId], references: [id], onDelete: Cascade)

  // Localization fields
  locale    String   // e.g., "en", "fr", "es"
  region    String?  // e.g., "US", "GB", "CA"

  // Localized Content
  title     String
  content   String   @db.Text
  isPublished Boolean @default(false)

  @@unique([articleId, locale, region]) // Ensures one variation per locale/region
}
```

