### 2. The Core Localization Logic

We need a utility to fetch content based on a "Fallback Strategy." If a user requests `en-GB` but it doesn't exist, we fallback to `en`.

```typescript
// lib/content-service.ts
import { prisma } from "./prisma";

export async function getLocalizedArticle(slug: string, locale: string, region?: string) {
  const article = await prisma.article.findUnique({
    where: { slug },
    include: {
      translations: {
        where: {
          OR: [
            { locale, region },           // Perfect match: en-GB
            { locale, region: null },     // Language match: en
          ]
        },
        orderBy: [
          { region: 'desc' } // Prioritize specific region over null
        ],
        take: 1
      }
    }
  });

  if (!article || article.translations.length === 0) return null;

  return {
    ...article,
    activeTranslation: article.translations[0]
  };
}
```

