### 2. Backend Implementation (NestJS)

We need a service that handles **Locale Fallback Logic**. If a user requests `en-GB` but it doesn't exist, we might want to return `en-US` or the "canonical" version.

#### The Content Service
```typescript
// src/content/content.service.ts
import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../prisma.service';

@Injectable()
export class ContentService {
  constructor(private prisma: PrismaService) {}

  async getContent(slug: string, locale: string) {
    // 1. Try to find the exact locale match
    let content = await this.prisma.content.findUnique({
      where: { slug_locale: { slug, locale } },
    });

    // 2. Fallback: If not found, try the base language (e.g., en-GB -> en)
    if (!content && locale.includes('-')) {
      const baseLang = locale.split('-')[0];
      content = await this.prisma.content.findFirst({
        where: { 
          slug, 
          locale: { startsWith: baseLang },
          status: 'PUBLISHED' 
        },
      });
    }

    // 3. Absolute Fallback: Get the Canonical (Master) version
    if (!content) {
      content = await this.prisma.content.findFirst({
        where: { slug, canonicalId: null },
      });
    }

    if (!content) throw new NotFoundException('Content not found');
    return content;
  }

  async createTranslation(masterId: string, data: any) {
    return this.prisma.content.create({
      data: {
        ...data,
        canonicalId: masterId,
      },
    });
  }
}
```

