### 3. Frontend Implementation (Next.js)

Next.js allows us to use dynamic segments for locales (e.g., `/[locale]/posts/[slug]`).

#### Locale Middleware
This ensures users are redirected to their preferred language based on headers.

```typescript
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

const locales = ['en-US', 'en-GB', 'fr-FR', 'de-DE'];

export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;
  const pathnameHasLocale = locales.some(
    (locale) => pathname.startsWith(`/${locale}/`) || pathname === `/${locale}`
  );

  if (pathnameHasLocale) return;

  // Redirect if there is no locale
  const locale = request.headers.get('accept-language')?.split(',')[0] || 'en-US';
  request.nextUrl.pathname = `/${locale}${pathname}`;
  return NextResponse.redirect(request.nextUrl);
}

export const config = {
  matcher: ['/((?!api|_next/static|_next/image|favicon.ico).*)'],
};
```

