### 2. The Search Logic (Backend)

We will create a single API endpoint that takes `lat` and `lng` query parameters. We use the `ST_DWithin` function, which is highly optimized using the GIST index.

**File: `app/api/search/route.ts`**
```typescript
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const lat = parseFloat(searchParams.get('lat') || '');
  const lng = parseFloat(searchParams.get('lng') || '');

  if (isNaN(lat) || isNaN(lng)) {
    return NextResponse.json({ error: 'Invalid coordinates' }, { status: 400 });
  }

  // 15 miles in meters (1 mile ≈ 1609.34 meters)
  const radiusMeters = 15 * 1609.34;

  try {
    // We use $queryRaw because standard ORM filters don't support ST_DWithin
    // ST_MakePoint(lng, lat) creates a point, 4326 is the standard GPS SRID
    const users = await prisma.$queryRaw`
      SELECT id, name, ST_Distance(location, ST_MakePoint(${lng}, ${lat})::geography) as distance
      FROM "User"
      WHERE ST_DWithin(location, ST_MakePoint(${lng}, ${lat})::geography, ${radiusMeters})
      ORDER BY distance ASC
      LIMIT 50;
    `;

    const events = await prisma.$queryRaw`
      SELECT id, title, description, date, ST_Distance(location, ST_MakePoint(${lng}, ${lat})::geography) as distance
      FROM "Event"
      WHERE ST_DWithin(location, ST_MakePoint(${lng}, ${lat})::geography, ${radiusMeters})
      ORDER BY date ASC
      LIMIT 50;
    `;

    return NextResponse.json({ users, events });
  } catch (error) {
    console.error(error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}
```

