### 2. The Search API (Next.js Route)

This API takes the user's `lat` and `lng` and returns users and events within a 15-mile radius (approx. 24,140 meters).

```typescript
// app/api/search/route.ts
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const lat = parseFloat(searchParams.get('lat') || '0');
  const lng = parseFloat(searchParams.get('lng') || '0');
  const radiusInMiles = 15;
  const radiusInMeters = radiusInMiles * 1609.34;

  try {
    // We use ST_DWithin for high-performance proximity searching
    // It utilizes the GIST spatial index created earlier
    const nearbyEvents = await prisma.$queryRaw`
      SELECT id, title, description, lat, lng, address,
        ST_Distance(
          ST_GeographyFromText('POINT(' || lng || ' ' || lat || ')'),
          ST_GeographyFromText('POINT(' || "lng" || ' ' || "lat" || ')')
        ) as distance
      FROM "Event"
      WHERE ST_DWithin(
        ST_GeographyFromText('POINT(' || lng || ' ' || lat || ')'),
        ST_GeographyFromText('POINT(' || "lng" || ' ' || "lat" || ')'),
        ${radiusInMeters}
      )
      ORDER BY distance ASC
      LIMIT 50;
    `;

    const nearbyUsers = await prisma.$queryRaw`
      SELECT id, name, image, lat, lng,
        ST_Distance(
          ST_GeographyFromText('POINT(' || lng || ' ' || lat || ')'),
          ST_GeographyFromText('POINT(' || "lng" || ' ' || "lat" || ')')
        ) as distance
      FROM "User"
      WHERE ST_DWithin(
        ST_GeographyFromText('POINT(' || lng || ' ' || lat || ')'),
        ST_GeographyFromText('POINT(' || "lng" || ' ' || "lat" || ')'),
        ${radiusInMeters}
      )
      AND id != 'current-user-id' -- Exclude self
      ORDER BY distance ASC
      LIMIT 20;
    `;

    return NextResponse.json({ events: nearbyEvents, users: nearbyUsers });
  } catch (error) {
    console.error(error);
    return NextResponse.json({ error: "Search failed" }, { status: 500 });
  }
}
```

