### 2. Backend Implementation (Next.js API Route)

We need an endpoint that accepts `lat` and `lng` and returns users and events within 15 miles.
*Note: 15 miles ≈ 24,140 meters.*

```typescript
// app/api/search/route.ts
import { NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();
const RADIUS_METERS = 15 * 1609.34; // Convert miles to meters

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const lat = parseFloat(searchParams.get('lat') || '');
  const lng = parseFloat(searchParams.get('lng') || '');

  if (isNaN(lat) || isNaN(lng)) {
    return NextResponse.json({ error: 'Invalid coordinates' }, { status: 400 });
  }

  try {
    // We use Raw SQL because ST_DWithin is a PostGIS-specific function
    const users = await prisma.$queryRaw`
      SELECT id, name, ST_X(location::geometry) as lng, ST_Y(location::geometry) as lat
      FROM "User"
      WHERE ST_DWithin(location, ST_MakePoint(${lng}, ${lat})::geography, ${RADIUS_METERS})
    `;

    const events = await prisma.$queryRaw`
      SELECT id, title, description, ST_X(location::geometry) as lng, ST_Y(location::geometry) as lat
      FROM "Event"
      WHERE ST_DWithin(location, ST_MakePoint(${lng}, ${lat})::geography, ${RADIUS_METERS})
    `;

    return NextResponse.json({ users, events });
  } catch (error) {
    console.error('Search error:', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}
```

