### 2. The Refund Service

This service contains the core business logic. It utilizes a **Database Transaction** to ensure that we never update stock without recording the refund (or vice-versa).

```typescript
// src/refund/refund.service.ts

import { Injectable, BadRequestException, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { differenceInDays } from 'date-fns';

@Injectable()
export class RefundService {
  constructor(private prisma: PrismaService) {}

  async processRefund(orderId: string, reason: string) {
    // 1. Fetch Order and items
    const order = await this.prisma.order.findUnique({
      where: { id: orderId },
      include: { items: true },
    });

    if (!order) {
      throw new NotFoundException(`Order ${orderId} not found`);
    }

    // 2. Verify 30-day window
    const daysSinceOrder = differenceInDays(new Date(), order.createdAt);
    if (daysSinceOrder > 30) {
      throw new BadRequestException(
        `Refund window expired. Order was placed ${daysSinceOrder} days ago.`,
      );
    }

    // 3. Check if already refunded
    const existingRefund = await this.prisma.refund.findFirst({
      where: { orderId },
    });
    if (existingRefund) {
      throw new BadRequestException('Refund has already been processed for this order.');
    }

    // 4. Atomic Transaction: Create Refund Record and Update Inventory
    return this.prisma.$transaction(async (tx) => {
      // Create refund record
      const refund = await tx.refund.create({
        data: { orderId, reason },
      });

      // Update Stock across ALL warehouses
      // Business Logic: If an order had 2 items of Product A, 
      // and we have 3 warehouses, we restock those 2 items back 
      // into a "Primary" warehouse or distribute them.
      // Per requirements: "Update stock for that variant across all warehouse locations"
      for (const item of order.items) {
        const warehouses = await tx.warehouse.findMany();

        // Distribution Strategy: In a real-world scenario, you'd likely 
        // return stock to the original shipping warehouse. 
        // Here, we'll increment the stock in the 'Main' warehouse or 
        // implement a specific distribution logic.

        for (const warehouse of warehouses) {
            // For this implementation, we assume we want to update the 
            // stock availability record across the system.
            await tx.stock.updateMany({
              where: {
                productId: item.productId,
                warehouseId: warehouse.id,
              },
              data: {
                quantity: { increment: item.quantity },
              },
            });
        }
      }

      return refund;
    });
  }
}
```

