### 2. The Core Analytics Query

This query uses a **Common Table Expression (CTE)** and a **Window Function (`DENSE_RANK`)** to group products by category and rank them by sales volume.

```sql
WITH ProductSales AS (
    -- Calculate total sales per product in the last 24 hours
    SELECT 
        p.id AS product_id,
        p.name AS product_name,
        c.name AS category_name,
        SUM(oi.quantity) AS total_sold
    FROM order_items oi
    JOIN orders o ON oi.order_id = o.id
    JOIN products p ON oi.product_id = p.id
    JOIN categories c ON p.category_id = c.id
    WHERE o.created_at >= NOW() - INTERVAL '24 hours'
    GROUP BY p.id, p.name, c.name
),
RankedProducts AS (
    -- Rank products within each category
    SELECT 
        product_id,
        product_name,
        category_name,
        total_sold,
        DENSE_RANK() OVER (
            PARTITION BY category_name 
            ORDER BY total_sold DESC
        ) as sales_rank
    FROM ProductSales
)
-- Select only the top 5 per category
SELECT * 
FROM RankedProducts 
WHERE sales_rank <= 5
ORDER BY category_name, sales_rank ASC;
```

