### 2. The Checkout Service

The core logic resides here. We use a **Pessimistic Locking** strategy. When a user starts a checkout, we lock the product row immediately.

```typescript
// src/services/checkout.service.ts
import { PrismaClient, OrderStatus } from '@prisma/client';
import { paymentGateway } from '../lib/payment';
import { stockCleanupQueue } from '../lib/queue';

const prisma = new PrismaClient();

export class CheckoutService {
  async processCheckout(productId: number, userId: string) {
    return await prisma.$transaction(async (tx) => {
      // 1. LOCK the product row for update. 
      // This prevents other concurrent transactions from reading this product's stock.
      const products = await tx.$queryRaw<any[]>`
        SELECT id, stock FROM "Product" 
        WHERE id = ${productId} 
        FOR UPDATE
      `;

      const product = products[0];

      if (!product || product.stock <= 0) {
        throw new Error("Product out of stock or does not exist");
      }

      // 2. Decrement stock immediately (Reserve)
      await tx.product.update({
        where: { id: productId },
        data: { stock: { decrement: 1 } },
      });

      // 3. Create Pending Order
      const order = await tx.order.create({
        data: {
          productId: productId,
          status: OrderStatus.PENDING,
        },
      });

      // We commit the transaction here to release the lock quickly.
      // The stock is now "reserved".
      return order;
    });
  }

  async handlePayment(orderId: string, productId: number) {
    try {
      // 4. Simulate Payment
      const paymentSuccess = await paymentGateway.charge();

      if (paymentSuccess) {
        await prisma.order.update({
          where: { id: orderId },
          data: { status: OrderStatus.COMPLETED },
        });
      } else {
        throw new Error("Payment Failed");
      }
    } catch (error) {
      // 5. INSTANT RESTORATION: Payment failed, put the item back
      await this.rollbackStock(orderId, productId);
    }
  }

  private async rollbackStock(orderId: string, productId: number) {
    await prisma.$transaction([
      prisma.product.update({
        where: { id: productId },
        data: { stock: { increment: 1 } },
      }),
      prisma.order.update({
        where: { id: orderId },
        data: { status: OrderStatus.FAILED },
      }),
    ]);
  }
}
```

