### High-Level Logic: The "Reserve-and-Release" Pattern

To handle high concurrency and failures:
1.  **Atomic Transaction:** Start a DB transaction.
2.  **Pessimistic Lock:** Lock the product row so no other request can modify it.
3.  **Stock Check & Decrement:** If stock > 0, decrement it and create a "Pending" order.
4.  **Commit Transaction:** Release the DB lock as quickly as possible.
5.  **Payment Processing:** Attempt payment.
6.  **Success/Failure:** If payment fails, start a new transaction to increment the stock back.

---

### 1. Database Schema

```typescript
// product.entity.ts
import { Entity, Column, PrimaryGeneratedColumn, Check } from 'typeorm';

@Entity('products')
@Check(`"stock" >= 0`) // Database-level safety net
export class Product {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  name: string;

  @Column('integer')
  stock: number;

  @Column('decimal')
  price: number;
}

// order.entity.ts
export enum OrderStatus {
  PENDING = 'pending',
  PAID = 'paid',
  FAILED = 'failed',
  CANCELLED = 'cancelled',
}

@Entity('orders')
export class Order {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  productId: number;

  @Column()
  status: OrderStatus;
}
```

### 2. The Checkout Service (Core Logic)

This service manages the transaction and the concurrency lock.

```typescript
import { Injectable, BadRequestException, InternalServerErrorException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, DataSource } from 'typeorm';
import { Product } from './entities/product.entity';
import { Order, OrderStatus } from './entities/order.entity';

@Injectable()
export class CheckoutService {
  constructor(
    private dataSource: DataSource,
    @InjectRepository(Product) private productRepo: Repository<Product>,
  ) {}

  async processCheckout(productId: number, paymentInfo: any) {
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    let order: Order;

    try {
      // 1. PESSIMISTIC LOCKING
      // 'pessimistic_write' translates to SELECT ... FOR UPDATE
      // This prevents other transactions from reading/writing this row until we commit.
      const product = await queryRunner.manager.findOne(Product, {
        where: { id: productId },
        lock: { mode: 'pessimistic_write' },
      });

      if (!product || product.stock <= 0) {
        throw new BadRequestException('Product out of stock');
      }

      // 2. DECREMENT STOCK
      product.stock -= 1;
      await queryRunner.manager.save(product);

      // 3. CREATE PENDING ORDER
      order = queryRunner.manager.create(Order, {
        productId,
        status: OrderStatus.PENDING,
      });
      await queryRunner.manager.save(order);

      // Commit the stock reduction immediately to keep lock time short
      await queryRunner.commitTransaction();
    } catch (err) {
      await queryRunner.rollbackTransaction();
      throw err;
    } finally {
      await queryRunner.release();
    }

    // 4. EXTERNAL PAYMENT CALL
    try {
      const paymentSuccessful = await this.mockPaymentGateway(paymentInfo);

      if (paymentSuccessful) {
        await this.updateOrderStatus(order.id, OrderStatus.PAID);
        return { message: 'Purchase successful', orderId: order.id };
      } else {
        throw new Error('Payment failed');
      }
    } catch (error) {
      // 5. INSTANT RESTORATION ON FAILURE
      await this.restoreInventory(productId, order.id);
      throw new BadRequestException('Payment failed, stock restored.');
    }
  }

  private async restoreInventory(productId: number, orderId: string) {
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      // Increment stock back
      await queryRunner.manager.increment(Product, { id: productId }, 'stock', 1);
      // Mark order as failed
      await queryRunner.manager.update(Order, orderId, { status: OrderStatus.FAILED });

      await queryRunner.commitTransaction();
    } catch (err) {
      await queryRunner.rollbackTransaction();
      // Logic for critical failure (e.g., Log to Sentry/CloudWatch)
    } finally {
      await queryRunner.release();
    }
  }

  private async mockPaymentGateway(info: any): Promise<boolean> {
    // Simulate network delay
    await new Promise((res) => setTimeout(res, 1000));
    return Math.random() > 0.2; // 80% success rate
  }

  private async updateOrderStatus(id: string, status: OrderStatus) {
    await this.dataSource.getRepository(Order).update(id, { status });
  }
}
```

### 3. Handling the "Ghost" Inventory (The Cron/Worker)

What happens if the server restarts *after* the stock is decremented but *before* the payment finishes? The stock is lost forever. To fix this, we implement a background worker (using BullMQ or a simple Cron).

```typescript
import { Cron, CronExpression } from '@nestjs/schedule';

@Injectable()
export class InventoryCleanupService {
  constructor(
    @InjectRepository(Order) private orderRepo: Repository<Order>,
    private checkoutService: CheckoutService
  ) {}

  @Cron(CronExpression.EVERY_5_MINUTES)
  async handleStaleOrders() {
    // Find orders that stayed 'PENDING' for more than 10 minutes
    const tenMinsAgo = new Date(Date.now() - 10 * 60 * 1000);

    const staleOrders = await this.orderRepo.find({
      where: {
        status: OrderStatus.PENDING,
        createdAt: LessThan(tenMinsAgo)
      }
    });

    for (const order of staleOrders) {
      // Restore inventory logic
      await this.checkoutService.restoreInventory(order.productId, order.id);
    }
  }
}
```

### Why this is production-ready:

1.  **Concurrency Control:** By using `pessimistic_write` (`SELECT FOR UPDATE`), we ensure that if 1,000 people try to buy the last item at the exact same millisecond, the database will queue them. Only the first one will see `stock: 1`, the rest will see `stock: 0` or wait and then fail.
2.  **Atomicity:** The use of Database Transactions ensures that we never create an order without decrementing stock.
3.  **Resilience:** The "Instant Restoration" logic handles 99% of failures (payment declines). The "Background Worker" handles the 1% of catastrophic failures (server crashes, network timeouts).
4.  **Database Integrity:** The `@Check("stock" >= 0)` constraint in PostgreSQL is a final "fail-safe" that prevents the application from ever setting a negative stock value, regardless of bugs in the code.

### Performance Tip for Extreme Concurrency
If you are expecting "TicketMaster" levels of traffic (millions of hits/sec), locking a database row will become a bottleneck. In that scenario, you would move the inventory to **Redis** and use Lua scripts to perform atomic decrements, then asynchronously sync the result back to PostgreSQL. However, for 99% of applications, the PostgreSQL Pessimistic Locking approach above is safer and easier to maintain.

To build a production-ready system for thousands of image descriptions with hybrid search capabilities (Keyword + Semantic), we need a stack that balances performance, cost, and developer velocity.

### The Tech Stack

#### 1. Database & Vector Store: PostgreSQL with `pgvector`
*   **Alternatives considered:** Pinecone (Vector-only, expensive), Elasticsearch (Complex to manage), MongoDB Atlas (Good, but relational data fits Postgres better).
*   **Why `pgvector`?** It allows us to keep our metadata (image URLs, tags, timestamps) and embeddings in a single ACID-compliant database. We can perform **Hybrid Search** (combining SQL `WHERE` clauses with vector similarity) in a single query.

#### 2. Embeddings: OpenAI `text-embedding-3-small`
*   **Alternatives considered:** HuggingFace (Self-hosted, complex), Cohere (Excellent, but OpenAI is more standard for this scale).
*   **Why?** It’s extremely cheap ($0.00002 / 1k tokens) and highly performant for semantic tasks.

#### 3. Frontend/Backend: Next.js (App Router) + Prisma
*   **Why?** Next.js offers a seamless way to handle both the UI and the API logic. Prisma provides type-safe database access, though we will use Raw SQL for vector operations.

---

### Phase 1: Database Schema and Setup

First, ensure you have a PostgreSQL instance with the `pgvector` extension enabled (standard on Supabase, AWS RDS, or Neon).

**Prisma Schema (`prisma/schema.prisma`):**
```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model ImageMetadata {
  id          String   @id @default(cuid())
  url         String
  description String   @db.Text
  // We use Unsupported for vector types as Prisma doesn't natively support them yet
  embedding   Unsupported("vector(1536)")? 
  createdAt   DateTime @default(now())

  @@index([description], map: "description_idx") // For keyword search
}
```

**Migration SQL:**
Run this to enable the extension and create a specialized index for fast vector searching (HNSW).
```sql
CREATE EXTENSION IF NOT EXISTS vector;

-- Create an HNSW index for semantic search performance
CREATE INDEX ON "ImageMetadata" 
USING hnsw (embedding vector_cosine_ops);
```

---

### Phase 2: The Search Logic (The Core)

We need a service to handle both embedding generation and the hybrid search query.

**`lib/search-service.ts`**
```typescript
import { OpenAI } from 'openai';
import { prisma } from './prisma';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function generateEmbedding(text: string) {
  const response = await openai.embeddings.create({
    model: "text-embedding-3-small",
    input: text,
  });
  return response.data[0].embedding;
}

export async function hybridSearch(query: string, limit = 10) {
  // 1. Generate embedding for the search query
  const queryEmbedding = await generateEmbedding(query);
  const vectorString = `[${queryEmbedding.join(',')}]`;

  // 2. Perform Hybrid Search using Raw SQL
  // We combine Semantic Similarity (Vector) and Lexical Match (Keywords)
  const results = await prisma.$queryRaw`
    SELECT 
      id, url, description,
      (1 - (embedding <=> ${vectorString}::vector)) AS semantic_score,
      ts_rank(to_tsvector('english', description), plainto_tsquery('english', ${query})) AS keyword_score
    FROM "ImageMetadata"
    WHERE 
      (embedding <=> ${vectorString}::vector) < 0.4 -- Similarity threshold
      OR to_tsvector('english', description) @@ plainto_tsquery('english', ${query})
    ORDER BY (semantic_score * 0.7 + keyword_score * 0.3) DESC
    LIMIT ${limit};
  `;

  return results;
}
```

