### Phase 3: API Routes

We need an endpoint to ingest new images and their AI descriptions.

**`app/api/images/route.ts`**
```typescript
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { generateEmbedding } from '@/lib/search-service';

export async function POST(req: Request) {
  const { url, description } = await req.json();

  const embedding = await generateEmbedding(description);

  // Prisma doesn't support vector insertion directly in .create() 
  // without a middleware or raw SQL
  const image = await prisma.$executeRaw`
    INSERT INTO "ImageMetadata" (id, url, description, embedding)
    VALUES (
      gen_random_uuid(), 
      ${url}, 
      ${description}, 
      ${embedding}::vector
    )
  `;

  return NextResponse.json({ success: true });
}
```

