### 3. Implementation: The Form Renderer Component

This component dynamically renders the form based on the JSON configuration saved by the school.

```tsx
// components/forms/DynamicFormRenderer.tsx
"use client"

import { useForm } from "react-hook-form";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

interface Question {
  id: string;
  type: 'text' | 'select' | 'checkbox';
  label: string;
  required: boolean;
  options?: string[];
}

export default function DynamicFormRenderer({ 
  questions, 
  onSubmit 
}: { 
  questions: Question[], 
  onSubmit: (data: any) => void 
}) {
  const { register, handleSubmit, formState: { errors } } = useForm();

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
      {questions.map((q) => (
        <div key={q.id} className="flex flex-col gap-2">
          <Label htmlFor={q.id}>{q.label} {q.required && "*"}</Label>

          {q.type === 'text' && (
            <Input 
              {...register(q.id, { required: q.required })} 
              placeholder={q.label} 
            />
          )}

          {q.type === 'select' && (
            <select 
              {...register(q.id, { required: q.required })}
              className="flex h-10 w-full rounded-md border border-input bg-background px-3"
            >
              {q.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
            </select>
          )}

          {errors[q.id] && <span className="text-red-500 text-sm">This field is required</span>}
        </div>
      ))}
      <Button type="submit">Submit Response</Button>
    </form>
  );
}
```

