### 4. Multi-Tenant Access Control

We must ensure a School Admin from "School A" cannot see "School B's" data, while District Admins can see everything. We implement this using **Middleware** and **Server-Side Checks**.

```tsx
// lib/auth-check.ts
import { db } from "@/lib/db";
import { auth } from "@clerk/nextjs"; // Example using Clerk for Auth

export async function getAuthorizedData(districtId: string) {
  const { userId } = auth();
  const user = await db.user.findUnique({ where: { id: userId } });

  if (!user || user.districtId !== districtId) {
    throw new Error("Unauthorized access to district");
  }

  if (user.role === "DISTRICT_ADMIN") {
    // Return all data for the district
    return await db.form.findMany({
      where: { school: { districtId } },
      include: { school: true, _count: { select: { submissions: true } } }
    });
  }

  // School Admin: Return only their school's data
  return await db.form.findMany({
    where: { schoolId: user.schoolId! },
    include: { school: true, _count: { select: { submissions: true } } }
  });
}
```

