// app/admin/[districtId]/dashboard/page.tsx
import { db } from "@/lib/db";
import { DataTable } from "@/components/ui/data-table";

export default async function DistrictDashboard({ params }: { params: { districtId: string } }) {
  const submissions = await db.submission.findMany({
    where: {
      form: {
        school: { districtId: params.districtId }
      }
    },
    include: {
      form: { include: { school: true } }
    }
  });

  // Flatten data for the table
  const tableData = submissions.map(s => ({
    id: s.id,
    school: s.form.school.name,
    formType: s.form.type,
    submittedAt: s.submittedAt.toLocaleDateString(),
    details: s.data // JSON field
  }));

  return (
    <div className="p-8">
      <h1 className="text-2xl font-bold mb-6">District Overview</h1>
      <DataTable columns={columns} data={tableData} />
    </div>
  );
}
```

