This component allows School Admins to add questions dynamically.

```tsx
// components/FormBuilder.tsx
"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { FormField, FieldType } from "@/types/form";

export function FormBuilder({ schoolId }: { schoolId: string }) {
  const [fields, setFields] = useState<FormField[]>([]);

  const addField = (type: FieldType) => {
    const newField: FormField = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      label: "New Question",
      required: false,
    };
    setFields([...fields, newField]);
  };

  const saveForm = async () => {
    // Call Next.js Server Action to save to DB
    await fetch("/api/forms/create", {
      method: "POST",
      body: JSON.stringify({ schoolId, fields, title: "Volunteer Form" }),
    });
  };

  return (
    <div className="space-y-6 p-6 border rounded-xl bg-white shadow">
      <h2 className="text-xl font-bold">Build Your Form</h2>

      {fields.map((field, index) => (
        <div key={field.id} className="flex items-center gap-4 p-4 border rounded">
          <Input 
            value={field.label} 
            onChange={(e) => {
              const newFields = [...fields];
              newFields[index].label = e.target.value;
              setFields(newFields);
            }}
          />
          <span className="text-sm font-mono bg-slate-100 px-2 py-1 rounded">
            {field.type}
          </span>
        </div>
      ))}

      <div className="flex gap-2">
        <Button onClick={() => addField('TEXT')}>+ Text</Button>
        <Button onClick={() => addField('CHECKBOX')}>+ Checkbox</Button>
      </div>

      <Button variant="default" className="w-full" onClick={saveForm}>
        Publish Form
      </Button>
    </div>
  );
}
```

