### 1. Database Schema (Prisma)

The core of the app is how we relate schools to districts while allowing dynamic questions.

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model District {
  id        String   @id @default(cuid())
  name      String
  slug      String   @unique
  schools   School[]
  createdAt DateTime @default(now())
}

model School {
  id         String   @id @default(cuid())
  name       String
  districtId String
  district   District @relation(fields: [districtId], references: [id])
  forms      Form[]
  users      User[]
  createdAt  DateTime @default(now())
}

model Form {
  id          String       @id @default(cuid())
  title       String
  description String?
  type        FormType     // VOLUNTEER or PERMISSION_SLIP
  config      Json         // Array of fields: { label, type, required, options }
  schoolId    String
  school      School       @relation(fields: [schoolId], references: [id])
  responses   Response[]
  published   Boolean      @default(false)
  createdAt   DateTime     @default(now())
}

model Response {
  id        String   @id @default(cuid())
  formId    String
  form      Form     @relation(fields: [formId], references: [id])
  data      Json     // The actual answers: { "phone": "123", "guardian": "Jane Doe" }
  createdAt DateTime @default(now())
}

enum FormType {
  VOLUNTEER
  PERMISSION_SLIP
}
```

