### 2. The Dynamic Form Builder Logic

Instead of creating tables for every new form, we store the form structure in a `JSONB` column. Here is how we define a "Field" and render it.

```typescript
// types/forms.ts
export type FieldType = 'text' | 'number' | 'email' | 'select' | 'checkbox';

export interface FormField {
  id: string;
  label: string;
  type: FieldType;
  required: boolean;
  options?: string[]; // For select/radio
}

// components/FormRenderer.tsx
import { useForm } from "react-hook-form";

export function FormRenderer({ fields, onSubmit }: { fields: FormField[], onSubmit: (data: any) => void }) {
  const { register, handleSubmit } = useForm();

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
      {fields.map((field) => (
        <div key={field.id} className="flex flex-col gap-2">
          <label className="font-medium">{field.label}</label>
          {field.type === 'text' && (
            <input {...register(field.id)} className="border p-2 rounded" required={field.required} />
          )}
          {field.type === 'select' && (
            <select {...register(field.id)} className="border p-2 rounded">
              {field.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
            </select>
          )}
          {/* Add other field types here */}
        </div>
      ))}
      <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">Submit</button>
    </form>
  );
}
```

