### 1. The Database Schema

The core challenge is storing posts that look different. We use a `group_type` identifier and a `content` JSON blob.

```sql
-- Groups Table
CREATE TABLE groups (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  description TEXT,
  group_type TEXT NOT NULL, -- 'gallery', 'writing', 'code', 'marketplace'
  rules JSONB, -- Array of strings
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Posts Table
CREATE TABLE posts (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  group_id UUID REFERENCES groups(id),
  user_id UUID REFERENCES auth.users(id),
  title TEXT NOT NULL,
  content JSONB NOT NULL, -- This stores the specific layout data
  metadata JSONB, -- Extra info like tags, price, etc.
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
```

