### 1. Data Schema (PostgreSQL)

The key to this app is a flexible `posts` table and a `group_types` definition.

```sql
-- Groups table defining the "flavor" of the community
CREATE TABLE groups (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  description TEXT,
  rules JSONB NOT NULL, -- Array of rule objects
  layout_type TEXT NOT NULL DEFAULT 'text', -- 'gallery', 'blog', 'list'
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Posts table with dynamic content
CREATE TABLE posts (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  group_id UUID REFERENCES groups(id),
  author_id UUID REFERENCES auth.users(id),
  title TEXT NOT NULL,
  content JSONB NOT NULL, -- Flexible structure based on layout_type
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);
```

