### 3. Implementation: The Group Page

In Next.js, we use a dynamic route `app/groups/[slug]/page.tsx`.

```tsx
// app/groups/[slug]/page.tsx
import { supabase } from "@/lib/supabase";
import PostRenderer from "@/components/renderers/PostRenderer";
import RuleSidebar from "@/components/RuleSidebar";

export default async function GroupPage({ params }: { params: { slug: string } }) {
  // Fetch group details and posts in parallel
  const { data: group } = await supabase
    .from('groups')
    .select('*')
    .eq('slug', params.slug)
    .single();

  const { data: posts } = await supabase
    .from('posts')
    .select('*, author:profiles(username)')
    .eq('group_id', group.id)
    .order('created_at', { ascending: false });

  return (
    <main className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-4 gap-8 py-10">
      {/* Dynamic Content Area */}
      <div className="md:col-span-3">
        <header className="mb-8">
          <h1 className="text-4xl font-bold">{group.name}</h1>
          <p className="text-muted-foreground">{group.description}</p>
        </header>

        <PostRenderer groupType={group.layout_type} posts={posts} />
      </div>

      {/* Rules Sidebar - Content changes per group */}
      <aside className="md:col-span-1">
        <RuleSidebar rules={group.rules} />
      </aside>
    </main>
  );
}
```

