}

model Item {
  id           String   @id @default(cuid())
  registryId   String
  registry     Registry @relation(fields: [registryId], references: [id], onDelete: Cascade)
  name         String
  description  String?
  url          String?  // Link to store
  price        Float?
  requestedQty Int      @default(1)
