### 3. Core Logic: Server Actions (`app/actions.ts`)

Server Actions handle the business logic. Note the "Partial Claim" logic which ensures we don't exceed the requested amount.

```typescript
"use server"

import { db } from "@/lib/db";
import { auth } from "@clerk/nextjs";
import { revalidatePath } from "next/cache";

export async function createRegistry(formData: FormData) {
  const { userId } = auth();
  if (!userId) throw new Error("Unauthorized");

  const title = formData.get("title") as string;
  const slug = title.toLowerCase().replace(/ /g, "-") + "-" + Math.random().toString(36).substring(2, 7);

  await db.registry.create({
    data: {
      userId,
      title,
      description: formData.get("description") as string,
      slug,
    },
  });

  revalidatePath("/dashboard");
}

export async function claimItem(itemId: string, quantityToClaim: number) {
  const item = await db.item.findUnique({ where: { id: itemId } });
  if (!item) throw new Error("Item not found");

  const newClaimedQty = item.claimedQty + quantityToClaim;

  if (newClaimedQty > item.requestedQty) {
    throw new Error("Cannot claim more than requested");
  }

  await db.item.update({
    where: { id: itemId },
    data: {
      claimedQty: newClaimedQty,
      isClaimed: newClaimedQty === item.requestedQty
    },
  });

  revalidatePath(`/registry/${item.registryId}`);
}
```

