### 1. Database Schema (`prisma/schema.prisma`)

We need to model the relationship where one user has many registries, and one registry has many items. Crucially, we need a `Claim` table to track partial purchases.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Registry {
  id          String   @id @default(cuid())
  userId      String   // From Clerk
  title       String
  description String?  // The "personalized note"
  slug        String   @unique
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt
  items       Item[]
}

model Item {
  id                String   @id @default(cuid())
  registryId        String
  registry          Registry @relation(fields: [registryId], references: [id], onDelete: Cascade)
  name              String
  url               String?
  price             Float?
  quantityRequested Int      @default(1)
  quantityClaimed   Int      @default(0)
  claims            Claim[]
  createdAt         DateTime @default(now())
}

model Claim {
  id             String   @id @default(cuid())
  itemId         String
  item           Item     @relation(fields: [itemId], references: [id], onDelete: Cascade)
  contributorName String
  quantityTaken  Int
  createdAt      DateTime @default(now())
}
```

