### 2. Core Logic: Server Actions (`lib/actions.ts`)

These functions handle the business logic: creating registries and claiming portions of gifts.

```typescript
"use server"

import { db } from "@/lib/db";
import { auth } from "@clerk/nextjs";
import { revalidatePath } from "next/cache";

export async function createRegistry(formData: FormData) {
  const { userId } = auth();
  if (!userId) throw new Error("Unauthorized");

  const title = formData.get("title") as string;
  const description = formData.get("description") as string;
  const slug = title.toLowerCase().replace(/ /g, "-") + "-" + Math.random().toString(36).substring(2, 7);

  await db.registry.create({
    data: { userId, title, description, slug }
  });

  revalidatePath("/dashboard");
}

export async function claimItem(itemId: string, quantity: number, name: string) {
  await db.$transaction(async (tx) => {
    const item = await tx.item.findUnique({ where: { id: itemId } });
    if (!item) throw new Error("Item not found");

    const remaining = item.quantityRequested - item.quantityClaimed;
    if (quantity > remaining) throw new Error("Not enough items left");

    await tx.claim.create({
      data: { itemId, quantityTaken: quantity, contributorName: name }
    });

    await tx.item.update({
      where: { id: itemId },
      data: { quantityClaimed: { increment: quantity } }
    });
  });

  revalidatePath("/registry/[slug]", "page");
}
```

