### 2. Implementation: The Registry Owner View

The owner needs a dashboard to create registries and add items. Here is the logic for adding an item using **Next.js Server Actions**.

```typescript
// app/lib/actions.ts
'use server'

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function createItem(registryId: string, formData: FormData) {
  const name = formData.get("name") as string;
  const quantityRequested = parseInt(formData.get("quantityRequested") as string);
  const url = formData.get("url") as string;
  const price = parseFloat(formData.get("price") as string);

  await prisma.item.create({
    data: {
      registryId,
      name,
      quantityRequested,
      url,
      price,
    },
  });

  revalidatePath(`/dashboard/registry/${registryId}`);
}
