import { useState } from "react";
import { claimItemAction } from "@/app/lib/actions";

export default function ClaimItemForm({ item }: { item: any }) {
  const remaining = item.quantityRequested - item.quantityClaimed;
  const [amount, setAmount] = useState(1);

  if (remaining <= 0) return <span className="text-green-600 font-bold">Fulfilled!</span>;

  return (
    <form action={() => claimItemAction(item.id, amount)} className="flex gap-2">
      <input 
        type="number" 
        max={remaining} 
        min={1} 
        value={amount}
        onChange={(e) => setAmount(parseInt(e.target.value))}
        className="border rounded p-1 w-16"
      />
      <button className="bg-blue-600 text-white px-4 py-1 rounded">
        Claim {amount}
      </button>
      <p className="text-sm text-gray-500 mt-1">({remaining} remaining)</p>
    </form>
  );
}
```

