### 4. Logic: Partial Claim Server Action

We must ensure that guests don't claim more than what is requested.

```typescript
// app/lib/actions.ts (continued)

export async function claimItemAction(itemId: string, amount: number) {
  const item = await prisma.item.findUnique({ where: { id: itemId } });

  if (!item) throw new Error("Item not found");

  const newClaimedCount = item.quantityClaimed + amount;

  if (newClaimedCount > item.quantityRequested) {
    throw new Error("Cannot claim more than requested");
  }

  await prisma.item.update({
    where: { id: itemId },
    data: { quantityClaimed: newClaimedCount }
  });

  revalidatePath(`/registry/${item.registryId}`);
}
```

