### 2. Database Schema

For clothing with sizes and colors, a flat structure is insufficient. We use a **Product-Variant** relationship.

```sql
-- Products Table
CREATE TABLE products (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  name TEXT NOT NULL,
  description TEXT,
  base_price DECIMAL NOT NULL,
  category TEXT,
  image_url TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Variants Table (Sizes/Colors)
CREATE TABLE variants (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  product_id UUID REFERENCES products(id) ON DELETE CASCADE,
  color TEXT NOT NULL,
  size TEXT NOT NULL,
  sku TEXT UNIQUE NOT NULL,
  stock_quantity INTEGER DEFAULT 0,
  price_override DECIMAL -- In case XL costs more than S
);

-- Search Index
CREATE INDEX products_search_idx ON products USING GIN (to_tsvector('english', name || ' ' || description));
```

