#### A. Global State Store (Zustand)
Manage the cart and search filters across the app.

```typescript
// store/useStore.ts
import { create } from 'zustand';

interface CartItem {
  variantId: string;
  name: string;
  size: string;
  color: string;
  price: number;
  quantity: number;
}

interface StoreState {
  searchQuery: string;
  cart: CartItem[];
  setSearch: (query: string) => void;
  addToCart: (item: CartItem) => void;
}

export const useStore = create<StoreState>((set) => ({
  searchQuery: '',
  cart: [],
  setSearch: (query) => set({ searchQuery: query }),
  addToCart: (item) => set((state) => ({ 
    cart: [...state.cart, item] 
  })),
}));
