### 1. Database Schema (`prisma/schema.prisma`)

Clothing items require a "one-to-many" relationship: one Product has many Variants (combinations of size and color).

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Product {
  id          String    @id @default(cuid())
  name        String
  description String
  category    String
  basePrice   Decimal
  images      String[]  // Array of image URLs
  variants    Variant[]
  createdAt   DateTime  @default(now())
  updatedAt   DateTime  @updatedAt
}

model Variant {
  id        String  @id @default(cuid())
  productId String
  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)
  size      String  // e.g., "S", "M", "L"
  color     String  // e.g., "Blue", "Red"
  sku       String  @unique
  stock     Int     @default(0)
  price     Decimal? // Override base price if needed
}
```

