### 2. The Search & Filter Logic

In a production app, searching should happen on the server to handle large datasets efficiently. We will use Next.js Server Components to fetch data based on URL parameters.

#### `lib/products.ts` (Data Access Layer)

```typescript
import { prisma } from "./prisma";

export async function getProducts(params: {
  query?: string;
  category?: string;
  size?: string;
  color?: string;
}) {
  const { query, category, size, color } = params;

  return await prisma.product.findMany({
    where: {
      AND: [
        query ? { name: { contains: query, mode: 'insensitive' } } : {},
        category ? { category } : {},
        // Filter by variants
        size || color ? {
          variants: {
            some: {
              ...(size && { size }),
              ...(color && { color }),
            }
          }
        } : {},
      ]
    },
    include: {
      variants: true
    }
  });
}
```

