This component updates the URL parameters without a full page reload.

```tsx
'use client';

import { useRouter, useSearchParams } from 'next/navigation';

export default function Filters() {
  const router = useRouter();
  const searchParams = useSearchParams();

  const updateFilter = (key: string, value: string) => {
    const params = new URLSearchParams(searchParams.toString());
    if (value) {
      params.set(key, value);
    } else {
      params.delete(key);
    }
    router.push(`?${params.toString()}`);
  };

  return (
    <div className="space-y-6 p-4 border-r w-64">
      <div>
        <h3 className="font-bold mb-2">Size</h3>
        {['S', 'M', 'L', 'XL'].map(size => (
          <label key={size} className="flex items-center gap-2">
            <input 
              type="checkbox" 
              checked={searchParams.get('size') === size}
              onChange={(e) => updateFilter('size', e.target.checked ? size : '')}
            />
            {size}
          </label>
        ))}
      </div>
      {/* Repeat similar logic for Colors */}
    </div>
  );
}
```

