#### `utils/yjs-handler.ts`
This is where the magic happens. We manage a collection of shared documents in memory and sync them.

```typescript
import * as Y from 'yjs';
import * as syncProtocol from 'y-protocols/dist/sync.js';
import * as awarenessProtocol from 'y-protocols/dist/awareness.js';
import { WebSocket } from 'ws';
import { db } from './db'; // Your Postgres client

const docs = new Map<string, WSSharedDoc>();

class WSSharedDoc extends Y.Doc {
  name: string;
  conns: Set<WebSocket>;

  constructor(name: string) {
    super();
    this.name = name;
    this.conns = new Set();

    // When the doc changes, we could persist to DB here
    this.on('update', (update: Uint8Array) => {
      this.persistUpdate(update);
    });
  }

  async persistUpdate(update: Uint8Array) {
    // Save binary update to Postgres
    await db.docUpdates.create({
      data: { doc_id: this.name, update: Buffer.from(update) }
    });
  }
}

export const setupWSConnection = async (conn: WebSocket, docId: string) => {
  let doc = docs.get(docId);
  if (!doc) {
    doc = new WSSharedDoc(docId);
    // Load existing state from DB
    const persistedDoc = await db.documents.findUnique({ where: { id: docId } });
    if (persistedDoc?.content) {
      Y.applyUpdate(doc, new Uint8Array(persistedDoc.content));
    }
    docs.set(docId, doc);
  }

  doc.conns.add(conn);

  // 1. Send Sync Step 1 (What the server has)
  const encoder = syncProtocol.createSyncStep1Message();
  syncProtocol.writeSyncStep1(encoder, doc);
  conn.send(syncProtocol.encode(encoder));

  conn.on('message', (message: ArrayBuffer) => {
    // Handle incoming Yjs messages (Sync or Awareness)
    const encoder = syncProtocol.readSyncMessage(new Uint8Array(message), doc);
    if (encoder) {
      conn.send(syncProtocol.encode(encoder));
    }
  });

  conn.on('close', () => {
    doc?.conns.delete(conn);
    if (doc?.conns.size === 0) {
      // Cleanup: Save full snapshot and remove from memory
      saveFullSnapshot(docId, Y.encodeStateAsUpdate(doc));
      docs.delete(docId);
    }
  });
};
```

