### 3. Version History & Snapshots

Storing every single keystroke in the `doc_updates` table is great for real-time but inefficient for loading. We implement a **Snapshotting Service**.

```typescript
async function saveFullSnapshot(docId: string, state: Uint8Array) {
  // 1. Update the main document record with the merged binary state
  await db.documents.update({
    where: { id: docId },
    data: { content: Buffer.from(state) }
  });

  // 2. Clear incremental updates to keep DB lean
  await db.docUpdates.deleteMany({ where: { doc_id: docId } });
}

async function createNamedVersion(docId: string, label: string) {
  const doc = docs.get(docId);
  const snapshot = Y.encodeStateAsUpdate(doc);

  await db.versions.create({
    data: {
      doc_id: docId,
      snapshot: Buffer.from(snapshot),
      label: label
    }
  });
}
```

