#### `src/persistence.ts`
This module handles saving the binary document data to the database.

```typescript
import { PrismaClient } from '@prisma/client';
import * as Y from 'yjs';

const prisma = new PrismaClient();

export const persistence = {
  // Retrieve the document from the DB
  bindState: async (docName: string, ydoc: Y.Doc) => {
    const doc = await prisma.document.findUnique({
      where: { id: docName },
    });

    if (doc) {
      // Apply the persisted state to the Yjs document
      Y.applyUpdate(ydoc, doc.content);
    } else {
      // Create a new document if it doesn't exist
      await prisma.document.create({
        data: {
          id: docName,
          name: "Untitled Document",
          content: Buffer.from(Y.encodeStateAsUpdate(ydoc)),
        },
      });
    }

    // Listen for updates and save to DB
    ydoc.on('update', async (update) => {
      // In production, throttle this or use a message queue (e.g., BullMQ)
      // to avoid hammering the DB on every keystroke.
      await prisma.document.update({
        where: { id: docName },
        data: {
          content: Buffer.from(Y.encodeStateAsUpdate(ydoc)),
        },
      });
    });
  },

  // Create a version snapshot
  saveVersion: async (docName: string, ydoc: Y.Doc) => {
    const snapshot = Y.encodeStateAsUpdate(ydoc);
    await prisma.version.create({
      data: {
        documentId: docName,
        snapshot: Buffer.from(snapshot),
      },
    });
  }
};
```

