import { setupWSConnection } from 'y-websocket/bin/utils';
import * as Y from 'yjs';
import { persistence } from './persistence';

const app = express();
const port = process.env.PORT || 3000;
const server = http.createServer(app);
const wss = new WebSocket.Server({ server });

// Map to track active Y.Docs in memory
const docs = new Map<string, Y.Doc>();

wss.on('connection', async (ws, req) => {
  // The URL structure is ws://localhost:3000/document-id
  const docName = req.url?.slice(1) || 'default';

  let ydoc = docs.get(docName);
  if (!ydoc) {
    ydoc = new Y.Doc();
    // Initialize state from Postgres
    await persistence.bindState(docName, ydoc);
    docs.set(docName, ydoc);
  }

  // Set up the standard Yjs websocket connection
  // This handles the protocol for syncing changes between clients
  setupWSConnection(ws, req, {
    docName,
    gc: true, // Garbage collection on
  });

  console.log(`User joined document: ${docName}`);
});

// Endpoint to manually trigger a version snapshot
app.post('/api/documents/:id/snapshot', async (req, res) => {
  const { id } = req.params;
  const ydoc = docs.get(id);
  if (ydoc) {
    await persistence.saveVersion(id, ydoc);
    res.status(200).send({ message: 'Version saved' });
  } else {
    res.status(404).send({ error: 'Document not active' });
  }
});

server.listen(port, () => {
  console.log(`Collaboration server running on port ${port}`);
});
```

