#### `src/persistence.ts`
In a production app, you don't save a string (like "Hello World"). You save the **binary update blocks** emitted by Yjs. This allows you to reconstruct the document history perfectly.

```typescript
import * as Y from 'yjs';

// Interface for database operations
export interface DocumentProvider {
  getSave: (docName: string) => Promise<Uint8Array | null>;
  saveUpdate: (docName: string, update: Uint8Array) => Promise<void>;
}

// Mock Database (Replace with Postgres/Redis in production)
const storage = new Map<string, Uint8Array>();

export const database: DocumentProvider = {
  getSave: async (docName) => storage.get(docName) || null,
  saveUpdate: async (docName, update) => {
    const previous = storage.get(docName);
    if (!previous) {
      storage.set(docName, update);
    } else {
      // Merge new updates with existing ones to prevent fragment growth
      storage.set(docName, Y.mergeUpdates([previous, update]));
    }
  }
};
```

#### `src/server.ts`
We extend the standard `y-websocket` utility to include persistence logic.

```typescript
import http from 'http';
import WebSocket from 'ws';
import express from 'express';
import * as Y from 'yjs';
// @ts-ignore
import { setupWSConnection } from 'y-websocket/bin/utils';
import { database } from './persistence';

const app = express();
const port = process.env.PORT || 3000;
const server = http.createServer(app);
const wss = new WebSocket.Server({ server });

/**
 * Handle Yjs Document Sync
 */
wss.on('connection', async (conn: WebSocket, req: http.IncomingMessage) => {
  // Extract room name from URL (e.g., /my-doc)
  const docName = req.url?.slice(1) || 'default-room';

  // 1. Load initial state from DB
  const persistedData = await database.getSave(docName);

  // 2. Setup the Yjs connection
  // setupWSConnection handles the sync protocol and awareness (cursors)
  const doc = setupWSConnection(conn, req, { docName });

  if (persistedData) {
    Y.applyUpdate(doc, persistedData);
  }

  // 3. Listen for updates to persist them
  doc.on('update', async (update: Uint8Array) => {
    await database.saveUpdate(docName, update);
  });

  console.log(`Client connected to: ${docName}`);
});

server.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});
```

