### 3. Core Implementation

We'll focus on the **Social Graph** and **Feed Logic**, as these are the most complex parts.

#### The Follow Service
This handles the logic for building the social graph.

```typescript
// src/social/social.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class SocialService {
  constructor(private prisma: PrismaService) {}

  async followUser(followerId: string, followingId: string) {
    if (followerId === followingId) {
      throw new BadRequestException('You cannot follow yourself');
    }

    return this.prisma.follow.create({
      data: { followerId, followingId },
    });
  }

  async unfollowUser(followerId: string, followingId: string) {
    return this.prisma.follow.delete({
      where: {
        followerId_followingId: { followerId, followingId },
      },
    });
  }

  async getFollowers(userId: string) {
    return this.prisma.follow.findMany({
      where: { followingId: userId },
      include: { follower: { select: { username: true, id: true } } },
    });
  }
}
```

#### The Feed Logic (High Performance)
In a production system, generating a feed by joining tables for every request is slow. We use **Keyset Pagination** (using `createdAt` and `id`) rather than Offset pagination to ensure stability as new posts arrive.

```typescript
// src/posts/posts.service.ts
@Injectable()
export class PostsService {
  constructor(private prisma: PrismaService) {}

  async getHomeFeed(userId: string, limit: number = 20, cursor?: string) {
    // 1. Get list of IDs the user is following
    const following = await this.prisma.follow.findMany({
      where: { followerId: userId },
      select: { followingId: true },
    });

    const followingIds = following.map((f) => f.followingId);
    // Include the user's own posts in their feed
    followingIds.push(userId);

    // 2. Efficiently fetch posts with Keyset Pagination
    return this.prisma.post.findMany({
      take: limit,
      skip: cursor ? 1 : 0,
      cursor: cursor ? { id: cursor } : undefined,
      where: {
        authorId: { in: followingIds },
      },
      include: {
        author: { select: { username: true } },
        _count: { select: { likes: true, comments: true } },
      },
      orderBy: { createdAt: 'desc' },
    });
  }

  async toggleLike(userId: string, postId: string) {
    const existingLike = await this.prisma.like.findUnique({
      where: { userId_postId: { userId, postId } },
    });

    if (existingLike) {
      return this.prisma.like.delete({
        where: { userId_postId: { userId, postId } },
      });
    }

    return this.prisma.like.create({
      data: { userId, postId },
    });
  }
}
```

