### 3. Backend Implementation (Express & Socket.io)

This server handles API requests and broadcasts real-time location updates.

```javascript
// server/index.js
const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const { PrismaClient } = require('@prisma/client');
const cors = require('cors');

const app = express();
const server = http.createServer(app);
const io = new Server(server, { cors: { origin: "*" } });
const prisma = new PrismaClient();

app.use(cors());
app.use(express.json());

// API: Get all vehicles with current status
app.get('/api/vehicles', async (req, res) => {
  const vehicles = await prisma.vehicle.findMany({
    include: { currentDriver: true }
  });
  res.json(vehicles);
});

// API: Log Maintenance
app.post('/api/maintenance', async (req, res) => {
  const { vehicleId, description, cost, date } = req.body;
  const log = await prisma.maintenanceLog.create({
    data: { vehicleId, description, cost: parseFloat(cost), date: new Date(date) }
  });
  res.json(log);
});

// Real-time: Handle Incoming GPS Data
io.on('connection', (socket) => {
  console.log('Tracker Connected:', socket.id);

  socket.on('update_location', async (data) => {
    const { vehicleId, lat, lng } = data;

    // 1. Update DB (In production, use a buffer/cache to avoid DB thrashing)
    await prisma.vehicle.update({
      where: { id: vehicleId },
      data: { lastLat: lat, lastLng: lng }
    });

    // 2. Broadcast to all connected dispatchers
    io.emit('location_changed', { vehicleId, lat, lng });
  });
});

server.listen(3001, () => console.log('Fleet Server running on port 3001'));
```

