```typescript
// lib/actions/fleet-actions.ts
"use server"

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";

export async function createVehicle(data: any) {
  const vehicle = await prisma.vehicle.create({ data });
  revalidatePath("/dashboard/vehicles");
  return vehicle;
}

export async function updateVehicleLocation(id: string, lat: number, lng: number) {
  return await prisma.vehicle.update({
    where: { id },
    data: { 
      currentLat: lat, 
      currentLng: lng, 
      lastLocationUpdate: new Date() 
    },
  });
}

export async function getFleetOverview() {
  const [vehicles, drivers, activeMaintenace] = await Promise.all([
    prisma.vehicle.count(),
    prisma.driver.count(),
    prisma.vehicle.count({ where: { status: 'IN_MAINTENANCE' } })
  ]);

  return { vehicles, drivers, activeMaintenace };
}
```

