### 🚀 2. Core Implementation (NestJS)

We will implement the **Transaction Logic**, as it's the most critical part. It must be atomic: if the stock update fails, the transaction record must not be created.

#### Transaction Service (`src/transactions/transactions.service.ts`)

```typescript
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { CreateTransactionDto } from './dto/create-transaction.dto';

@Injectable()
export class TransactionsService {
  constructor(private prisma: PrismaService) {}

  async create(dto: CreateTransactionDto) {
    // We use Prisma's $transaction to ensure atomicity
    return this.prisma.$transaction(async (tx) => {
      let total = 0;
      const transactionItems = [];

      for (const item of dto.items) {
        const product = await tx.product.findUnique({
          where: { id: item.productId },
        });

        if (!product || product.stock < item.quantity) {
          throw new BadRequestException(`Product ${item.productId} is out of stock or does not exist.`);
        }

        // 1. Calculate totals
        const itemTotal = Number(product.price) * item.quantity;
        total += itemTotal;

        // 2. Decrement stock
        await tx.product.update({
          where: { id: item.productId },
          data: { stock: { decrement: item.quantity } },
        });

        transactionItems.push({
          productId: product.id,
          quantity: item.quantity,
          priceAtTime: product.price,
        });
      }

      // 3. Create the transaction record
      return tx.transaction.create({
        data: {
          buyerEmail: dto.buyerEmail,
          totalAmount: total,
          items: {
            create: transactionItems,
          },
        },
        include: { items: true },
      });
    });
  }
}
```

