### 3. Core Implementation (Logic & API)

I will focus on the **Transaction Logic**, as it is the most critical part of a marketplace, requiring stock validation and atomicity.

#### **The Transaction Service**
This service handles purchasing a product. We use a **Database Transaction** to ensure that we don't charge a user if the stock runs out at the last millisecond.

```typescript
// src/transactions/transactions.service.ts

import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class TransactionsService {
  constructor(private prisma: PrismaService) {}

  async createTransaction(buyerId: string, productId: string) {
    // We execute this in a $transaction so all steps succeed or all fail
    return this.prisma.$transaction(async (tx) => {
      // 1. Fetch product and check stock
      const product = await tx.product.findUnique({
        where: { id: productId },
      });

      if (!product || product.stock < 1) {
        throw new BadRequestException('Product unavailable or out of stock');
      }

      // 2. Decrement stock
      await tx.product.update({
        where: { id: productId },
        data: { stock: { decrement: 1 } },
      });

      // 3. Create the transaction record
      const transaction = await tx.transaction.create({
        data: {
          amount: product.price,
          productId: product.id,
          buyerId: buyerId,
          sellerId: product.sellerId,
          status: 'COMPLETED', // In a real app, this might start as PENDING until payment gateway responds
        },
        include: {
          product: true,
          seller: { select: { name: true, email: true } },
        },
      });

      return transaction;
    });
  }
}
```

#### **The Product Controller**
Handles listing and searching. We use `class-validator` for DTO (Data Transfer Object) validation.

```typescript
// src/products/products.controller.ts

import { Controller, Post, Body, Get, UseGuards, Request } from '@nestjs/common';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { CreateProductDto } from './dto/create-product.dto';
import { ProductsService } from './products.service';

@Controller('products')
export class ProductsController {
  constructor(private productsService: ProductsService) {}

  @Get()
  async getAllProducts() {
    return this.productsService.findAll();
  }

  @UseGuards(JwtAuthGuard)
  @Post()
  async create(@Request() req, @Body() dto: CreateProductDto) {
    // Ensure only sellers can post
    if (req.user.role !== 'SELLER') {
      throw new UnauthorizedException('Only sellers can list products');
    }
    return this.productsService.create(req.user.userId, dto);
  }
}
```

