### 2. The Location Engine (Redis)

Using Redis to store driver locations ensures we don't hammer the primary database.

```typescript
// src/services/location.service.ts
import { createClient } from 'redis';

const redis = createClient();

export const updateDriverLocation = async (driverId: string, lat: number, lng: number) => {
  // GEOADD adds the driver to a geospatial index named 'drivers:active'
  await redis.geoAdd('drivers:active', {
    longitude: lng,
    latitude: lat,
    member: driverId
  });
};

export const findNearbyDrivers = async (lat: number, lng: number, radiusKm: number) => {
  // Find drivers within X kilometers
  return await redis.geoSearch('drivers:active', 
    { longitude: lng, latitude: lat },
    { radius: radiusKm, unit: 'km' }
  );
};
```

