### 3. Real-time Communication (Socket.io)

This layer handles the live "handshake" between the rider and driver.

```typescript
// src/sockets/trip.handler.ts
import { Server, Socket } from 'socket.io';
import { updateDriverLocation } from '../services/location.service';

export const setupSocketHandlers = (io: Server) => {
  io.on('connection', (socket: Socket) => {

    // 1. Driver updates their location
    socket.on('update_location', async (data: { driverId: string, lat: number, lng: number }) => {
      await updateDriverLocation(data.driverId, data.lat, data.lng);

      // Broadcast location to riders tracking this specific driver
      socket.to(`trip_room_${data.driverId}`).emit('location_changed', data);
    });

    // 2. Join a room for a specific trip to get updates
    socket.on('join_trip', (tripId: string) => {
      socket.join(`trip_room_${tripId}`);
    });
  });
};
```

