### 4. Trip Controller (Express)

This handles the business logic of requesting a trip and calculating ratings.

```typescript
// src/controllers/trip.controller.ts
import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export const completeTrip = async (req: Request, res: Response) => {
  const { tripId, ratingScore, comment } = req.body;

  try {
    const trip = await prisma.$transaction(async (tx) => {
      // 1. Update Trip Status
      const updatedTrip = await tx.trip.update({
        where: { id: tripId },
        data: { status: 'COMPLETED' },
        include: { driver: true }
      });

      // 2. Create Rating
      await tx.rating.create({
        data: { tripId, score: ratingScore, comment }
      });

      // 3. Recalculate Driver's average rating (Async or via trigger)
      const avg = await tx.rating.aggregate({
        where: { trip: { driverId: updatedTrip.driverId } },
        _avg: { score: true }
      });

      await tx.user.update({
        where: { id: updatedTrip.driverId! },
        data: { rating: avg._avg.score || 5.0 }
      });

      return updatedTrip;
    });

    res.json(trip);
  } catch (error) {
    res.status(500).json({ error: "Failed to complete trip" });
  }
};
```

