datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Patient {
  id            String          @id @default(cuid())
  firstName     String
  lastName      String
  dateOfBirth   DateTime
  gender        String
  records       MedicalRecord[]
  createdAt     DateTime        @default(now())
}

model MedicalRecord {
  id              String   @id @default(cuid())
  patientId       String
  patient         Patient  @relation(fields: [patientId], references: [id])

  specialty       SpecialtyType

  // This is where the variable fields live
  // Example: { "bloodPressure": "120/80", "ekgResult": "Normal" }
  clinicalData    Json     

  providerName    String
  visitDate       DateTime @default(now())
}

enum SpecialtyType {
  CARDIOLOGY
  DERMATOLOGY
  GENERAL_PRACTICE
  ONCOLOGY
}
