### 2. The Core Logic: Eligibility Engine

This is a standalone service class that encapsulates the business rules.

```typescript
// src/lib/promotion-engine.ts
import { Coupon, Redemption } from "@prisma/client";

export type Cart = {
  userId: string;
  items: { id: string; price: number; quantity: number }[];
  total: number;
};

export class PromotionEngine {
  static validate(coupon: Coupon, cart: Cart, userRedemptionsCount: number) {
    const now = new Date();

    // 1. Basic Validity
    if (!coupon.isActive) throw new Error("Coupon is inactive");
    if (coupon.startDate > now) throw new Error("Coupon has not started yet");
    if (coupon.endDate && coupon.endDate < now) throw new Error("Coupon expired");

    // 2. Usage Limits
    if (coupon.usageLimit && coupon.usedCount >= coupon.usageLimit) {
      throw new Error("Coupon usage limit reached");
    }
    if (coupon.userLimit && userRedemptionsCount >= coupon.userLimit) {
      throw new Error("You have already used this coupon");
    }

    // 3. Order Constraints
    if (coupon.minOrderValue && cart.total < Number(coupon.minOrderValue)) {
      throw new Error(`Minimum order of $${coupon.minOrderValue} required`);
    }

    return true;
  }

  static calculateDiscount(coupon: Coupon, cartTotal: number): number {
    let discount = 0;

    if (coupon.discountType === "PERCENTAGE") {
      discount = cartTotal * (Number(coupon.discountValue) / 100);
      if (coupon.maxDiscount && discount > Number(coupon.maxDiscount)) {
        discount = Number(coupon.maxDiscount);
      }
    } else if (coupon.discountType === "FIXED_AMOUNT") {
      discount = Number(coupon.discountValue);
    }

    // Ensure we don't discount more than the cart total
    return Math.min(discount, cartTotal);
  }
}
```

