### 3. API Implementation (Hono)

We use a database transaction when redeeming a coupon to ensure we don't exceed `usageLimit` due to concurrent requests (Race Conditions).

```typescript
// src/index.ts
import { Hono } from 'hono';
import { PrismaClient } from '@prisma/client';
import { PromotionEngine } from './lib/promotion-engine';

const app = new Hono();
const prisma = new PrismaClient();

// Validate Coupon Endpoint
app.post('/api/coupons/validate', async (c) => {
  const { code, cart, userId } = await c.req.json();

  const coupon = await prisma.coupon.findUnique({ where: { code: code.toUpperCase() } });

  if (!coupon) return c.json({ valid: false, message: "Invalid code" }, 404);

  const userRedemptions = await prisma.redemption.count({
    where: { couponId: coupon.id, userId }
  });

  try {
    PromotionEngine.validate(coupon, cart, userRedemptions);
    const discount = PromotionEngine.calculateDiscount(coupon, cart.total);

    return c.json({
      valid: true,
      discount,
      newTotal: cart.total - discount
    });
  } catch (err: any) {
    return c.json({ valid: false, message: err.message }, 400);
  }
});

// Redeem Coupon (Atomic Transaction)
app.post('/api/coupons/redeem', async (c) => {
  const { code, cart, userId, orderId } = await c.req.json();

  return await prisma.$transaction(async (tx) => {
    // 1. Lock the coupon row for update to prevent race conditions
    const coupon = await tx.$queryRaw`SELECT * FROM "Coupon" WHERE code = ${code.toUpperCase()} FOR UPDATE` as any[];
    const target = coupon[0];

    if (!target || target.usedCount >= target.usageLimit) {
      throw new Error("Coupon no longer available");
    }

    const discount = PromotionEngine.calculateDiscount(target, cart.total);

    // 2. Increment usage
    await tx.coupon.update({
      where: { id: target.id },
      data: { usedCount: { increment: 1 } }
    });

    // 3. Record redemption
    const redemption = await tx.redemption.create({
      data: {
        couponId: target.id,
        userId,
        orderId,
        amountSaved: discount
      }
    });

    return c.json({ success: true, redemption });
  });
});

export default app;
```

