### 2. The Core Logic: Promotion Validator

This service handles the "Eligibility Logic." It’s designed to be stateless so it can be used for both "Preview" (during cart updates) and "Commit" (during checkout).

```typescript
// src/promotions/promotions.logic.ts

export interface CartContext {
  userId: string;
  itemsTotal: number; // in cents
  shippingTotal: number;
}

export class PromotionEngine {
  static validate(coupon: Coupon, context: CartContext, userRedemptionCount: number) {
    const now = new Date();

    // 1. Basic Validity
    if (!coupon.isActive) throw new Error('Coupon is inactive');
    if (now < coupon.startDate) throw new Error('Coupon has not started yet');
    if (coupon.endDate && now > coupon.endDate) throw new Error('Coupon has expired');

    // 2. Usage Limits
    if (coupon.usageLimit && coupon.usageCount >= coupon.usageLimit) {
      throw new Error('Coupon usage limit reached');
    }
    if (userRedemptionCount >= coupon.limitPerUser) {
      throw new Error('You have already used this coupon');
    }

    // 3. Cart Requirements
    if (context.itemsTotal < coupon.minBasketValue) {
      throw new Error(`Minimum spend of $${coupon.minBasketValue / 100} required`);
    }

    return true;
  }

  static calculateDiscount(coupon: Coupon, context: CartContext): number {
    let discount = 0;

    switch (coupon.discountType) {
      case 'FIXED_AMOUNT':
        discount = coupon.discountValue;
        break;
      case 'PERCENTAGE':
        // discountValue 1000 = 10%
        discount = Math.floor((context.itemsTotal * coupon.discountValue) / 10000);
        if (coupon.maxDiscount) {
          discount = Math.min(discount, coupon.maxDiscount);
        }
        break;
      case 'FREE_SHIPPING':
        discount = context.shippingTotal;
        break;
    }

    // Never discount more than the actual total
    return Math.min(discount, context.itemsTotal + context.shippingTotal);
  }
}
```

