### 3. Atomic Redemption (The Service)

To prevent a coupon with a `usageLimit` of 100 from being used 101 times under heavy load, we use a **Database Transaction** with a row-level lock.

```typescript
// src/promotions/promotions.service.ts

@Injectable()
export class PromotionsService {
  constructor(private prisma: PrismaService) {}

  async applyAndRedeem(code: string, context: CartContext) {
    return this.prisma.$transaction(async (tx) => {
      // 1. Fetch coupon with an Update Lock (FOR UPDATE)
      // This prevents other transactions from modifying this coupon until we finish
      const coupon = await tx.$queryRaw<Coupon[]>`
        SELECT * FROM "Coupon" WHERE "code" = ${code} FOR UPDATE
      `;

      if (!coupon[0]) throw new NotFoundException('Coupon not found');
      const c = coupon[0];

      // 2. Check how many times THIS user has used it
      const userRedemptions = await tx.redemption.count({
        where: { couponId: c.id, userId: context.userId }
      });

      // 3. Run Validation Logic
      PromotionEngine.validate(c, context, userRedemptions);

      // 4. Calculate final discount
      const amountSaved = PromotionEngine.calculateDiscount(c, context);

      // 5. Record Redemption
      await tx.redemption.create({
        data: {
          couponId: c.id,
          userId: context.userId,
          orderId: context.orderId, // Passed in context
          amountSaved
        }
      });

      // 6. Increment Usage Count
      await tx.coupon.update({
        where: { id: c.id },
        data: { usageCount: { increment: 1 } }
      });

      return { amountSaved, code: c.code };
    });
  }
}
```

