  items: Array<{ id: string; price: number; category: string }>;
  userTags: string[]; // e.g., ["VIP", "new_user"]
}

export function validateEligibility(rules: any, context: CartContext): boolean {
  if (!rules) return true;
  return jsonLogic.apply(rules, context);
}

export function calculateDiscount(coupon: any, cartTotal: number): number {
  if (coupon.discountType === 'PERCENTAGE') {
    const discount = cartTotal * (Number(coupon.discountValue) / 100);
    return coupon.maxDiscount ? Math.min(discount, Number(coupon.maxDiscount)) : discount;
  }

  if (coupon.discountType === 'FIXED_AMOUNT') {
    return Math.min(Number(coupon.discountValue), cartTotal);
  }

  return 0;
}
```

