### 3. The Core Service
This service handles the business logic, specifically ensuring we handle **race conditions** when decrementing usage limits.

```typescript
// src/services/coupon.service.ts
import { PrismaClient } from '@prisma/client';
import { validateEligibility, calculateDiscount, CartContext } from '../lib/engine';

const prisma = new PrismaClient();

export class CouponService {
  /**
   * Validates a coupon against a cart without applying it
   */
  async validate(code: string, context: CartContext) {
    const coupon = await prisma.coupon.findUnique({
      where: { code: code.toUpperCase() },
      include: { _count: { select: { redemptions: true } } }
    });

    if (!coupon || !coupon.isActive) throw new Error("Coupon not found or inactive");

    // 1. Check Dates
    const now = new Date();
    if (now < coupon.startDate || (coupon.endDate && now > coupon.endDate)) {
      throw new Error("Coupon expired");
    }

    // 2. Check Global Usage Limits
    if (coupon.usageLimitTotal && coupon._count.redemptions >= coupon.usageLimitTotal) {
      throw new Error("Coupon fully redeemed");
    }

    // 3. Check User Usage Limits
    const userRedemptions = await prisma.redemption.count({
      where: { couponId: coupon.id, userId: context.userId }
    });
    if (userRedemptions >= coupon.usageLimitUser) {
      throw new Error("You have already used this coupon");
    }

    // 4. Check Minimum Spend
    if (context.total < Number(coupon.minOrderValue)) {
      throw new Error(`Minimum spend of ${coupon.minOrderValue} required`);
    }

    // 5. Evaluate Custom JSON Logic
    const isEligible = validateEligibility(coupon.eligibilityRules, context);
    if (!isEligible) throw new Error("Cart items do not qualify for this discount");

    const discountAmount = calculateDiscount(coupon, context.total);

    return {
      couponId: coupon.id,
      code: coupon.code,
      discountAmount,
      newTotal: context.total - discountAmount
    };
  }

  /**
   * Finalizes the coupon usage. Wrapped in a transaction to prevent race conditions.
   */
  async redeem(code: string, orderId: string, userId: string, cartContext: CartContext) {
    return prisma.$transaction(async (tx) => {
      // Re-validate inside transaction to ensure usageLimitTotal isn't hit
      // by a concurrent request between validation and redemption.
      const validation = await this.validate(code, cartContext);

      return tx.redemption.create({
        data: {
          couponId: validation.couponId,
          userId,
          orderId,
          amountSaved: validation.discountAmount
        }
      });
    });
  }
}
```

