### 3. The Matching Engine
The core value of the app is the matching logic. We look for trips where:
1. The start point is within $X$ km of the rider.
2. The destination is within $Y$ km of the rider.
3. The time window is acceptable.
4. There are enough seats.

```typescript
// src/trips/trips.service.ts
import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Trip } from './entities/trip.entity';

@Injectable()
export class TripsService {
  constructor(
    @InjectRepository(Trip)
    private tripRepository: Repository<Trip>,
  ) {}

  async findMatches(riderOrigin: { lng: number, lat: number }, riderDest: { lng: number, lat: number }, startTime: Date) {
    const radiusMeters = 2000; // 2km tolerance
    const timeWindowMinutes = 60;

    return this.tripRepository.createQueryBuilder('trip')
      .where('trip.status = :status', { status: 'available' })
      .andWhere('trip.totalSeats - trip.occupiedSeats > 0')
      // ST_DWithin: Efficiently finds points within a distance
      .andWhere(
        `ST_DWithin(trip.startLocation, ST_SetSRID(ST_Point(:startLng, :startLat), 4326), :dist)`,
        { startLng: riderOrigin.lng, startLat: riderOrigin.lat, dist: radiusMeters }
      )
      .andWhere(
        `ST_DWithin(trip.endLocation, ST_SetSRID(ST_Point(:endLng, :endLat), 4326), :dist)`,
        { endLng: riderDest.lng, endLat: riderDest.lat, dist: radiusMeters }
      )
      // Time matching: Within 1 hour of requested time
      .andWhere(
        `trip.departureTime BETWEEN :start AND :end`,
        { 
          start: new Date(startTime.getTime() - timeWindowMinutes * 60000),
          end: new Date(startTime.getTime() + timeWindowMinutes * 60000)
        }
      )
      .getMany();
  }
}
```

