### 4. Booking Logic (Concurrency Handling)
In a carpooling app, two riders might try to book the last seat simultaneously. We use a **Database Transaction** with an "optimistic lock" or a strict seat check to prevent overbooking.

```typescript
// src/bookings/bookings.service.ts
@Injectable()
export class BookingsService {
  constructor(private dataSource: DataSource) {}

  async createBooking(tripId: string, riderId: string, seatsRequested: number) {
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      // 1. Lock the trip row for update to prevent concurrent modifications
      const trip = await queryRunner.manager.findOne(Trip, {
        where: { id: tripId },
        lock: { mode: 'pessimistic_write' }
      });

      if (!trip || trip.status !== 'available') throw new Error('Trip unavailable');

      const available = trip.totalSeats - trip.occupiedSeats;
      if (available < seatsRequested) throw new Error('Not enough seats');

      // 2. Update seat count
      trip.occupiedSeats += seatsRequested;
      if (trip.occupiedSeats === trip.totalSeats) {
        trip.status = 'full';
      }
      await queryRunner.manager.save(trip);

      // 3. Create Booking record
      const booking = queryRunner.manager.create(Booking, {
        tripId,
        riderId,
        seatsBooked: seatsRequested,
        status: 'confirmed'
      });
      await queryRunner.manager.save(booking);

      await queryRunner.commitTransaction();
      return booking;
    } catch (err) {
      await queryRunner.rollbackTransaction();
      throw err;
    } finally {
      await queryRunner.release();
    }
  }
}
```

