### 1. The Database Schema

The core of a carpooling app is the "Ride Offer" (Driver) and the "Ride Request" (Rider).

```prisma
// schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id           String        @id @default(uuid())
  email        String        @unique
  name         String
  role         Role          @default(RIDER)
  ridesOffered RideOffer[]
  bookings     Booking[]
}

enum Role {
  RIDER
  DRIVER
}

model RideOffer {
  id                String    @id @default(uuid())
  driverId          String
  driver            User      @relation(fields: [driverId], references: [id])

  // Geospatial data stored as Geometry
  // We use Unsupported for PostGIS types in Prisma models
  route             Unsupported("geometry(LineString, 4326)")
  startLocationName String
  endLocationName   String

  departureTime     DateTime
  totalSeats        Int
  availableSeats    Int
  price             Decimal

  bookings          Booking[]
  status            RideStatus @default(SCHEDULED)

  @@index([departureTime])
}

model Booking {
  id           String    @id @default(uuid())
  rideOfferId  String
  rideOffer    RideOffer @relation(fields: [rideOfferId], references: [id])
  riderId      String
  rider        User      @relation(fields: [riderId], references: [id])

  pickupPoint  Unsupported("geometry(Point, 4326)")
  dropoffPoint Unsupported("geometry(Point, 4326)")

  status       BookingStatus @default(PENDING)
}

enum RideStatus { SCHEDULED; ONGOING; COMPLETED; CANCELLED }
enum BookingStatus { PENDING; CONFIRMED; REJECTED; CANCELLED }
