### 3. API Implementation (Fastify + TypeScript)

This implementation shows how to create a Ride Offer with a route.

```typescript
// src/app.ts
import Fastify from 'fastify';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';

const fastify = Fastify({ logger: true });
const prisma = new PrismaClient();

// Schema for creating a ride
const CreateRideSchema = z.object({
  driverId: z.string().uuid(),
  departureTime: z.string().datetime(),
  seats: z.number().min(1),
  // Array of [lng, lat]
  coordinates: z.array(z.array(z.number()).length(2)).min(2), 
  startName: z.string(),
  endName: z.string(),
});

fastify.post('/rides', async (request, reply) => {
  const data = CreateRideSchema.parse(request.body);

  // Convert coordinates to PostGIS LineString WKT (Well-Known Text)
  const lineStringWKT = `LINESTRING(${data.coordinates
    .map((c) => `${c[0]} ${c[1]}`)
    .join(',')})`;

  // We use raw SQL for insertion because of the Geometry type
  await prisma.$executeRawUnsafe(`
    INSERT INTO "RideOffer" (
      id, "driverId", "departureTime", "totalSeats", "availableSeats", 
      "startLocationName", "endLocationName", route, "price"
    ) VALUES (
      gen_random_uuid(), ${data.driverId}, ${data.departureTime}::timestamp, 
      ${data.seats}, ${data.seats}, ${data.startName}, ${data.endName},
      ST_GeomFromText('${lineStringWKT}', 4326), 10.00
    )
  `);

  return { success: true };
});

// Search Endpoint
fastify.get('/rides/search', async (request) => {
  const queryParams = z.object({
    pLat: z.coerce.number(),
    pLng: z.coerce.number(),
    dLat: z.coerce.number(),
    dLng: z.coerce.number(),
    time: z.string().datetime(),
  }).parse(request.query);

  const matches = await findMatchingRides(
    { lng: queryParams.pLng, lat: queryParams.pLat },
    { lng: queryParams.dLng, lat: queryParams.dLat },
    new Date(queryParams.time)
  );

  return { matches };
});

const start = async () => {
  try {
    await fastify.listen({ port: 3000 });
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};
start();
```

