### Part 2: The Ingestion Engine (NestJS Service)

This service handles fetching data. We use a background processor to ensure the UI remains responsive while the system works in the background.

```typescript
// ingestion.service.ts
import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from './prisma.service';
import Parser from 'rss-parser'; // A popular RSS library

@Injectable()
export class IngestionService {
  private parser = new Parser();
  private readonly logger = new Logger(IngestionService.name);

  constructor(private prisma: PrismaService) {}

  async fetchLatestNews() {
    const sources = await this.prisma.source.findMany({ where: { active: true } });

    for (const source of sources) {
      try {
        const feed = await this.parser.parseURL(source.feedUrl);

        for (const item of feed.items) {
          await this.prisma.article.upsert({
            where: { url: item.link },
            update: {}, // Don't overwrite if it exists
            create: {
              title: item.title,
              description: item.contentSnippet,
              url: item.link,
              publishedAt: new Date(item.pubDate),
              sourceId: source.id,
              metadata: { author: item.creator },
              // Logic to handle tags based on keywords/categories
              tags: {
                connectOrCreate: item.categories?.map(cat => ({
                  where: { name: cat },
                  create: { name: cat }
                })) || []
              }
            },
          });
        }
      } catch (error) {
        this.logger.error(`Failed to fetch from ${source.name}: ${error.message}`);
      }
    }
  }
}
