### 3. Implementation Plan

#### **Step 1: The Ingestion Worker**
We use `rss-parser` to fetch feeds and BullMQ to schedule the jobs.

```typescript
// src/ingestion/ingestion.processor.ts
import { Processor, Process } from '@nestjs/bull';
import { Job } from 'bull';
import * as Parser from 'rss-parser';
import { PrismaService } from '../prisma/prisma.service';

@Processor('ingest-queue')
export class IngestionProcessor {
  private parser = new Parser();

  constructor(private prisma: PrismaService) {}

  @Process('sync-source')
  async handleSourceSync(job: Job<{ sourceId: string }>) {
    const source = await this.prisma.source.findUnique({
      where: { id: job.data.sourceId },
    });

    if (!source) return;

    const feed = await this.parser.parseURL(source.feedUrl);

    for (const item of feed.items) {
      await this.prisma.article.upsert({
        where: { url: item.link },
        update: {}, // Don't overwrite existing articles
        create: {
          title: item.title,
          url: item.link,
          slug: this.slugify(item.title),
          publishedAt: new Date(item.pubDate),
          sourceId: source.id,
          metadata: { author: item.creator },
          // Initial engagement record
          metrics: { create: { views: 0 } },
          // Simple auto-tagging logic
          tags: {
            connectOrCreate: item.categories?.map(cat => ({
              where: { name: cat.toLowerCase() },
              create: { name: cat.toLowerCase() },
            })),
          },
        },
      });
    }
  }

  private slugify(text: string) {
    return text.toLowerCase().replace(/ /g, '-').replace(/[^\w-]+/g, '');
  }
}
```

