### 3. Core Implementation (The Worker Pattern)

To ensure reliability, the API shouldn't send the notification directly. It should push a job to a queue.

#### A. The Queue Producer (API)

```typescript
// src/services/notification.service.ts
import { Queue } from 'bullmq';
import { prisma } from '../lib/prisma';

const notificationQueue = new Queue('notifications', {
  connection: { host: 'localhost', port: 6379 }
});

export const triggerNotification = async (userId: string, templateSlug: string, data: any) => {
  // 1. Check User Preferences
  const pref = await prisma.notificationPreference.findFirst({
    where: { userId, enabled: true },
  });

  if (!pref) return { skipped: true, reason: 'User disabled notifications' };

  // 2. Fetch Template
  const template = await prisma.template.findUnique({ where: { slug: templateSlug } });
  if (!template) throw new Error('Template not found');

  // 3. Create Log Entry
  const log = await prisma.notificationLog.create({
    data: {
      userId,
      templateId: template.id,
      channel: template.channel,
      variables: data,
      status: 'PENDING'
    }
  });

  // 4. Add to Queue
  await notificationQueue.add('send-notification', {
    logId: log.id,
    userId,
    templateSlug,
    data
  }, {
    attempts: 3,
    backoff: { type: 'exponential', delay: 1000 }
  });

  return { success: true, logId: log.id };
};
```

#### B. The Queue Consumer (Worker)

This background process does the heavy lifting of rendering templates and calling providers.

```typescript
// src/workers/notification.worker.ts
import { Worker } from 'bullmq';
import Handlebars from 'handlebars';
import { prisma } from '../lib/prisma';

const worker = new Worker('notifications', async (job) => {
  const { logId, userId, templateSlug, data } = job.data;

  try {
    const log = await prisma.notificationLog.findUnique({
      where: { id: logId },
      include: { user: true }
    });
    const template = await prisma.template.findUnique({ where: { slug: templateSlug } });

    if (!log || !template) return;

    // Render content
    const bodyCompiler = Handlebars.compile(template.body);
    const finalBody = bodyCompiler(data);

    // Strategy Pattern for Providers
    if (template.channel === 'EMAIL') {
      await sendEmail(log.user.email, template.subject!, finalBody);
    } else if (template.channel === 'SMS') {
      await sendSMS(log.user.phoneNumber!, finalBody);
    }

    // Update Log
    await prisma.notificationLog.update({
      where: { id: logId },
      data: { status: 'SENT', sentAt: new Date() }
    });

  } catch (error) {
    console.error(`Failed to send notification ${logId}:`, error);
    await prisma.notificationLog.update({
      where: { id: logId },
      data: { status: 'FAILED', metadata: { error: error.message } }
    });
    throw error; // Let BullMQ handle the retry
  }
}, {
  connection: { host: 'localhost', port: 6379 }
});

async function sendEmail(to: string, subject: string, body: string) {
  // Implementation for SendGrid / AWS SES
  console.log(`Sending Email to ${to}: ${subject}`);
}

async function sendSMS(to: string, body: string) {
  // Implementation for Twilio / Vonage
  console.log(`Sending SMS to ${to}: ${body}`);
}
```

