### 2. Core Logic: The Workout Service

This service handles the business logic for logging workouts and retrieving progress.

```typescript
// src/workouts/workouts.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class WorkoutsService {
  constructor(private prisma: PrismaService) {}

  async createWorkout(userId: string, name: string) {
    return this.prisma.workout.create({
      data: { userId, name },
    });
  }

  async addSet(workoutId: string, exerciseId: string, data: any) {
    return this.prisma.workoutSet.create({
      data: {
        workoutId,
        exerciseId,
        ...data,
      },
    });
  }

  async getProgress(userId: string, exerciseId: string) {
    // Returns the Max Weight lifted per workout for a specific exercise over time
    return this.prisma.workoutSet.findMany({
      where: {
        exerciseId,
        workout: { userId },
      },
      select: {
        weight: true,
        workout: { select: { createdAt: true } },
      },
      orderBy: { workout: { createdAt: 'asc' } },
    });
  }
}
```

