### 2. Implementation: The Workout Service

The core logic handles logging a workout. We use a transaction to ensure that if saving one set fails, the whole workout isn't partially saved.

```typescript
// src/workouts/workouts.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { CreateWorkoutDto } from './dto/create-workout.dto';

@Injectable()
export class WorkoutsService {
  constructor(private prisma: PrismaService) {}

  async create(userId: string, dto: CreateWorkoutDto) {
    return this.prisma.workout.create({
      data: {
        userId,
        name: dto.name,
        sets: {
          create: dto.sets.map((set) => ({
            reps: set.reps,
            weight: set.weight,
            exerciseId: set.exerciseId,
            order: set.order,
          })),
        },
      },
      include: {
        sets: true,
      },
    });
  }

  async getProgress(userId: string, exerciseId: string) {
    // Returns weight progression for a specific exercise over time
    return this.prisma.workoutSet.findMany({
      where: {
        exerciseId,
        workout: { userId },
      },
      include: {
        workout: true,
      },
      orderBy: {
        workout: { date: 'asc' },
      },
    });
  }
}
```

