### 3. Tracking Progress Logic

To track progress, we calculate the "Estimated 1-Rep Max" or "Total Volume" per session.

```typescript
// src/progress/progress.service.ts
@Injectable()
export class ProgressService {
  constructor(private prisma: PrismaService) {}

  async getVolumeStats(userId: string) {
    const workouts = await this.prisma.workout.findMany({
      where: { userId },
      include: { sets: true },
    });

    return workouts.map(workout => ({
      date: workout.date,
      name: workout.name,
      totalVolume: workout.sets.reduce((sum, set) => sum + (set.reps * set.weight), 0)
    }));
  }
}
```

