### 4. Input Validation (DTOs)

Ensuring data integrity using `class-validator`.

```typescript
// src/workouts/dto/create-workout.dto.ts
import { IsString, IsArray, ValidateNested, IsInt, IsNumber, Min } from 'class-validator';
import { Type } from 'class-transformer';

class SetDto {
  @IsInt() @Min(1) reps: number;
  @IsNumber() @Min(0) weight: number;
  @IsString() exerciseId: string;
  @IsInt() order: number;
}

export class CreateWorkoutDto {
  @IsString() name: string;
  @IsArray()
  @ValidateNested({ each: true })
  @Type(() => SetDto)
  sets: SetDto[];
}
