### 3. Implementation (NestJS)

Below is the core logic for managing the User Profile and Activity.

#### A. The Activity Interceptor
To make the application "production-ready," we don't want to manually write activity logs in every controller. We use an **Interceptor** to automatically log specific actions.

```typescript
// src/common/interceptors/activity.interceptor.ts
import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { tap } from 'rxjs/operators';

@Injectable()
export class ActivityInterceptor implements NestInterceptor {
  constructor(private prisma: PrismaService) {}

  intercept(context: ExecutionContext, next: CallHandler) {
    const request = context.switchToHttp().getRequest();
    const userId = request.user?.id;

    return next.handle().pipe(
      tap(async () => {
        if (userId) {
          await this.prisma.activityLog.create({
            data: {
              userId,
              action: `${request.method} ${request.url}`,
              metadata: { body: request.body },
            },
          });
        }
      }),
    );
  }
}
```

