#### C. The Users Service
This interacts with the Prisma database.

```typescript
// src/users/users.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class UsersService {
  constructor(private prisma: PrismaService) {}

  async findOne(id: string) {
    return this.prisma.user.findUnique({
      where: { id },
      include: { preferences: true }, // Eager load preferences
    });
  }

  async update(id: string, data: any) {
    const { preferences, ...profileData } = data;

    return this.prisma.user.update({
      where: { id },
      data: {
        ...profileData,
        preferences: {
          update: preferences, // Nested update
        },
      },
    });
  }

  async getActivityLogs(userId: string) {
    return this.prisma.activityLog.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: 50, // Pagination is recommended for production
    });
  }
}
```

