#### 1. Database Schema (`prisma/schema.prisma`)
We define a relational structure where a User has one set of Preferences and many Activity Logs.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id            String         @id @default(uuid())
  email         String         @unique
  password      String
  fullName      String?
  createdAt     DateTime       @default(now())
  preferences   Preference?
  activities    ActivityLog[]
}

model Preference {
  id             String  @id @default(uuid())
  theme          String  @default("light") // 'light' | 'dark'
  notifications  Boolean @default(true)
  language       String  @default("en")
  userId         String  @unique
  user           User    @relation(fields: [userId], references: [id])
}

model ActivityLog {
  id        String   @id @default(uuid())
  action    String   // e.g., "LOGIN", "UPDATE_PROFILE"
  metadata  Json?    // Stores flexible context (e.g., Device info)
  createdAt DateTime @default(now())
  userId    String
  user      User     @relation(fields: [userId], references: [id])
}
```

#### 2. Authentication Middleware (`src/middleware/auth.ts`)
This protects routes and extracts the `userId` from the token.

```typescript
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

export const authenticate = (req: Request, res: Response, next: NextFunction) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) return res.status(401).json({ error: 'Access denied' });

  try {
    const verified = jwt.verify(token, process.env.JWT_SECRET!);
    (req as any).user = verified;
    next();
  } catch (err) {
    res.status(400).json({ error: 'Invalid token' });
  }
};
```

#### 3. The Activity Service (`src/services/activity.service.ts`)
Encapsulating the logic for logging history.

```typescript
import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

export const logActivity = async (userId: string, action: string, metadata: any = {}) => {
  return await prisma.activityLog.create({
    data: {
      userId,
      action,
      metadata
    }
  });
};
```

#### 4. The User Controller (`src/controllers/user.controller.ts`)
This handles retrieving the profile, preferences, and history in a single optimized query.

```typescript
import { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { logActivity } from '../services/activity.service';

const prisma = new PrismaClient();

export const getFullProfile = async (req: Request, res: Response) => {
  const userId = (req as any).user.id;

  try {
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: {
        preferences: true,
        activities: {
          take: 10, // Get the last 10 actions
          orderBy: { createdAt: 'desc' }
        }
      }
    });

    if (!user) return res.status(404).json({ error: 'User not found' });

    // Log this view action
    await logActivity(userId, 'VIEW_PROFILE');

    // Remove password before sending
    const { password, ...userData } = user;
    res.json(userData);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
};

export const updatePreferences = async (req: Request, res: Response) => {
  const userId = (req as any).user.id;
  const { theme, notifications, language } = req.body;

  try {
    const updated = await prisma.preference.update({
      where: { userId },
      data: { theme, notifications, language }
    });

    await logActivity(userId, 'UPDATE_PREFERENCES', { theme, language });
    res.json(updated);
  } catch (error) {
    res.status(400).json({ error: 'Failed to update preferences' });
  }
};
```

