### 3. Implementation (NestJS)

#### A. User Preferences Service
This service handles updating and retrieving user-specific settings.

```typescript
// src/preferences/preferences.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class PreferencesService {
  constructor(private prisma: PrismaService) {}

  async updatePreferences(userId: string, data: any) {
    return this.prisma.preference.upsert({
      where: { userId },
      update: data,
      create: { ...data, userId },
    });
  }
}
```

#### B. Activity Logging Interceptor
In production, you want to log activities automatically. We use a NestJS Interceptor to log actions without cluttering the business logic.

```typescript
// src/common/interceptors/activity-logger.interceptor.ts
import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';
import { PrismaService } from '../../prisma/prisma.service';

@Injectable()
export class ActivityLoggerInterceptor implements NestInterceptor {
  constructor(private prisma: PrismaService) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const request = context.switchToHttp().getRequest();
    const userId = request.user?.id;
    const action = `${request.method} ${request.route.path}`;

    return next.handle().pipe(
      tap(async () => {
        if (userId) {
          await this.prisma.activityLog.create({
            data: { userId, action, metadata: { ip: request.ip } },
          });
        }
      }),
    );
  }
}
```

#### C. User Controller
The interface for the mobile app to interact with the backend.

```typescript
// src/users/users.controller.ts
import { Controller, Get, Body, Patch, UseGuards, UseInterceptors } from '@nestjs/common';
import { JwtAuthGuard } from '../auth/jwt-auth.guard';
import { ActivityLoggerInterceptor } from '../common/interceptors/activity-logger.interceptor';
import { GetUser } from '../auth/get-user.decorator';

@Controller('users')
@UseGuards(JwtAuthGuard)
@UseInterceptors(ActivityLoggerInterceptor) // Automatically logs interactions
export class UsersController {
  constructor(private usersService: UsersService) {}

  @Get('me')
  async getFullProfile(@GetUser('id') userId: string) {
    return this.usersService.findOne(userId, {
      profile: true,
      preferences: true,
    });
  }

  @Patch('preferences')
  async updatePrefs(@GetUser('id') userId: string, @Body() dto: UpdatePrefsDto) {
    return this.preferencesService.updatePreferences(userId, dto);
  }

  @Get('activity')
  async getActivityHistory(@GetUser('id') userId: string) {
    return this.prisma.activityLog.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: 20,
    });
  }
}
```

