### ⚡ 2. The Server-Side Logic (`app/api/volunteers/route.ts`)

This API handles searching. If a `skill` query parameter is provided, it filters the volunteers; otherwise, it returns all.

```typescript
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const skillQuery = searchParams.get('skill');

  try {
    const volunteers = await prisma.volunteer.findMany({
      where: skillQuery ? {
        skills: {
          some: {
            name: {
              contains: skillQuery,
              mode: 'insensitive',
            }
          }
        }
      } : {},
      include: {
        skills: true,
      },
      orderBy: { name: 'asc' }
    });

    return NextResponse.json(volunteers);
  } catch (error) {
    return NextResponse.json({ error: "Failed to fetch volunteers" }, { status: 500 });
  }
}
```

