### 1. Database Schema (`prisma/schema.prisma`)

We need a many-to-many relationship or a structured array for skills. For simplicity and performance in this use case, we will use a relational model.

```prisma
// This defines your Volunteer model
model Volunteer {
  id        String   @id @default(cuid())
  firstName String
  lastName  String
  email     String   @unique
  phone     String?
  status    String   @default("Active") // Active, Inactive, Onboarding
  skills    Skill[]  @relation("VolunteerSkills")
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt
}

model Skill {
  id         String      @id @default(cuid())
  name       String      @unique
  volunteers Volunteer[] @relation("VolunteerSkills")
}
