### 2. The Core Logic: Search & Filtering

In a production app, searching should happen on the server to handle large datasets efficiently. We will use URL search parameters to drive the UI.

```typescript
// src/lib/actions.ts - Server Action for fetching data
import { prisma } from "@/lib/prisma";

export async function getVolunteers(query: string) {
  return await prisma.volunteer.findMany({
    where: {
      OR: [
        { firstName: { contains: query, mode: 'insensitive' } },
        { lastName: { contains: query, mode: 'insensitive' } },
        { skills: { some: { name: { contains: query, mode: 'insensitive' } } } }
      ]
    },
    include: {
      skills: true
    },
    orderBy: { lastName: 'asc' }
  });
}
```

