### 2. Database Schema
We need two main entities: `Profile` (Users) and `Task`.

```prisma
// schema.prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

enum Status {
  BACKLOG
  IN_PROGRESS
  COMPLETED
}

model Profile {
  id         String   @id @default(uuid())
  email      String   @unique
  full_name  String?
  tasks      Task[]   @relation("AssignedTasks")
}

model Task {
  id          String   @id @default(cuid())
  createdAt   DateTime @default(now())
  title       String
  description String?
  dueDate     DateTime
  status      Status   @default(BACKLOG)
  userId      String
  user        Profile  @relation("AssignedTasks", fields: [userId], references: [id])
}
```

