### 3. Core Implementation

#### A. Task Creation Logic (Server Action)
Using Server Actions allows us to handle form submissions without writing API boilerplate.

```typescript
// lib/actions/task-actions.ts
"use server"

import { db } from "@/lib/db";
import { revalidatePath } from "next/cache";
import { z } from "zod";

const TaskSchema = z.object({
  title: z.string().min(3),
  description: z.string().optional(),
  dueDate: z.string(),
  userId: z.string(),
});

export async function createTask(formData: FormData) {
  const validatedFields = TaskSchema.parse({
    title: formData.get("title"),
    description: formData.get("description"),
    dueDate: formData.get("dueDate"),
    userId: formData.get("userId"),
  });

  await db.task.create({
    data: {
      ...validatedFields,
      dueDate: new Date(validatedFields.dueDate),
    },
  });

  revalidatePath("/dashboard");
}
```

