'use client';

import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { TaskCard } from '@/components/task-card';
import { Plus, Loader2 } from 'lucide-react';

export default function Dashboard() {
  const [tasks, setTasks] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    const { data, error } = await supabase
      .from('tasks')
      .select('*')
      .order('due_date', { ascending: true });

    if (!error) setTasks(data);
    setLoading(false);
  }

  async function updateStatus(id: string, status: string) {
    const { error } = await supabase
      .from('tasks')
      .update({ status })
      .eq('id', id);

    if (!error) {
      setTasks(tasks.map(t => t.id === id ? { ...t, status } : t));
    }
  }

  if (loading) return (
    <div className="flex h-screen w-full items-center justify-center">
      <Loader2 className="animate-spin text-blue-600" size={48} />
    </div>
  );

  return (
    <main className="min-h-screen bg-slate-50 p-8">
      <div className="max-w-6xl mx-auto">
        <header className="flex justify-between items-center mb-10">
          <div>
            <h1 className="text-3xl font-bold text-slate-900">Team Tasks</h1>
            <p className="text-slate-500">Track deadlines and progress</p>
          </div>
          <button className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-blue-700 transition-colors">
            <Plus size={20} /> New Task
          </button>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {/* Status Columns */}
          {['todo', 'in-progress', 'done'].map((status) => (
            <div key={status} className="flex flex-col gap-4">
              <h2 className="text-sm font-bold uppercase tracking-wider text-slate-400 border-b pb-2">
                {status.replace('-', ' ')} ({tasks.filter(t => t.status === status).length})
              </h2>
              {tasks
                .filter(t => t.status === status)
                .map(task => (
                  <TaskCard key={task.id} task={task} onUpdateStatus={updateStatus} />
                ))}
            </div>
          ))}
        </div>
      </div>
    </main>
  );
}
```

