### 2. Task Validation & Logic (`lib/actions.ts`)

Using Next.js **Server Actions**, we handle the business logic securely on the server.

```typescript
"use server"

import { revalidatePath } from "next/cache";
import { prisma } from "@/lib/db"; // Assume prisma client instance
import { z } from "zod";
import { auth } from "@clerk/nextjs";

const TaskSchema = z.object({
  title: z.string().min(3, "Title must be at least 3 characters"),
  description: z.string().optional(),
  priority: z.enum(["LOW", "MEDIUM", "HIGH"]),
  deadline: z.string().transform((str) => new Date(str)),
  assignedToId: z.string(),
  assignedToName: z.string(),
});

export async function createTask(formData: FormData) {
  const { userId } = auth();
  if (!userId) throw new Error("Unauthorized");

  const validatedFields = TaskSchema.safeParse({
    title: formData.get("title"),
    description: formData.get("description"),
    priority: formData.get("priority"),
    deadline: formData.get("deadline"),
    assignedToId: formData.get("assignedToId"),
    assignedToName: formData.get("assignedToName"),
  });

  if (!validatedFields.success) return { error: "Invalid fields" };

  await prisma.task.create({
    data: {
      ...validatedFields.data,
      creatorId: userId,
    },
  });

  revalidatePath("/");
}

export async function updateTaskStatus(id: string, status: "TODO" | "IN_PROGRESS" | "DONE") {
  await prisma.task.update({
    where: { id },
    data: { status },
  });
  revalidatePath("/");
}
```

