### 2. The Core Logic: The Weighted Ranking Query

The challenge is combining distance (meters), social density (integers), and interest overlap (count) into a single score.

**The Formula:**
$$Score = (Social \times W_s) + (Overlap \times W_i) - (Log(Distance) \times W_d)$$

*   **Social:** Raw check-in count.
*   **Overlap:** Number of tags the user shares with the event.
*   **Distance:** We use a logarithmic penalty so that being 1km vs 2km away matters more than 100km vs 101km.

```typescript
// src/lib/db/queries.ts
import { sql } from 'kysely';

export async function getRankedEvents(
  lat: number,
  lng: number,
  userInterests: string[],
  weights = { social: 0.5, interest: 2.0, distance: 1.5 }
) {
  return await db
    .selectFrom('events')
    .selectAll()
    .select((eb) => [
      // 1. Calculate Interest Overlap Count using Postgres Array Intersect
      sql<number>`cardinality(array(
        select unnest(category_tags) 
        intersect 
        select unnest(${userInterests}::text[])
      ))`.as('interest_overlap'),

      // 2. Calculate Distance in meters
      sql<number>`ST_Distance(location, ST_SetSRID(ST_MakePoint(${lng}, ${lat}), 4326)::geography)`.as('distance_meters'),

      // 3. The Master Scoring Formula
      sql<number>`(
        (check_in_count * ${weights.social}) + 
        (cardinality(array(
          select unnest(category_tags) intersect select unnest(${userInterests}::text[])
        )) * ${weights.interest}) - 
        (ln(NULLIF(ST_Distance(location, ST_SetSRID(ST_MakePoint(${lng}, ${lat}), 4326)::geography), 0) + 1) * ${weights.distance})
      )`.as('weighted_score')
    ])
    .where(
        // Geospatial bounding box for performance (e.g., within 50km)
        sql`ST_DWithin(location, ST_SetSRID(ST_MakePoint(${lng}, ${lat}), 4326)::geography, 50000)`
    )
    .orderBy('weighted_score', 'desc')
    .limit(20)
    .execute();
}
```

