### 3. Implementation

#### Backend: The Ranking Service (`/app/api/events/route.ts`)

```typescript
import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db'; // Your Kysely or PG client
import { sql } from 'kysely';

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const lat = parseFloat(searchParams.get('lat') || '0');
  const lng = parseFloat(searchParams.get('lng') || '0');
  const userInterests = searchParams.get('interests')?.split(',') || [];

  // Weights for our algorithm
  const W_DIST = 10.0;
  const W_SOCIAL = 5.0;
  const W_INTEREST = 8.0;

  // Single Geospatial Query with Weighted Ranking
  const results = await sql`
    SELECT 
      id, 
      title, 
      check_in_count,
      tags,
      ST_X(location::geometry) as lng,
      ST_Y(location::geometry) as lat,
      ST_Distance(location, ST_MakePoint(${lng}, ${lat})::geography) as distance_meters,
      (
        -- 1. Physical Distance Score (Inverse relationship)
        (${W_DIST} / (1 + ST_Distance(location, ST_MakePoint(${lng}, ${lat})::geography) / 1000)) +

        -- 2. Social Density Score (Logarithmic to prevent viral spikes from over-dominating)
        (${W_SOCIAL} * log(check_in_count + 1)) +

        -- 3. Interest Overlap Score (Using Postgres Array Intersection)
        (${W_INTEREST} * array_length(ARRAY(
          SELECT unnest(tags) INTERSECT SELECT unnest(${userInterests}::text[])
        ), 1))
      ) as total_rank_score
    FROM events
    WHERE ST_DWithin(location, ST_MakePoint(${lng}, ${lat})::geography, 50000) -- 50km radius
    ORDER BY total_rank_score DESC
    LIMIT 20
  `.execute(db);

  return NextResponse.json(results.rows);
}
```

