### 2. The "Single Query" Discovery Engine

This is the heart of the application. We use a Raw SQL query to calculate the score on the fly.

**Scoring Formula:**
$Score = (Density \times W_d) + (Overlap \times W_o) - (Distance \times W_{dist})$

```typescript
// lib/discovery.ts
import { prisma } from "./prisma";

export async function getRankedEvents(
  userLat: number,
  userLon: number,
  userInterests: string[],
  weights = { density: 1.5, overlap: 2.0, distance: 0.001 } // Distance is usually a penalty
) {
  // We use array_length and the array intersection operator '&&' for overlap
  return await prisma.$queryRawUnsafe(`
    SELECT 
      id, 
      title, 
      "checkInCount",
      "interests",
      ST_X(location::geometry) as lon,
      ST_Y(location::geometry) as lat,
      ST_DistanceSphere(location, ST_MakePoint($1, $2)) as distance_meters,

      -- Calculation Logic:
      (
        ("checkInCount" * $3) + 
        (cardinality(ARRAY(SELECT unnest(interests) INTERSECT SELECT unnest($4::text[]))) * $5) - 
        (ST_DistanceSphere(location, ST_MakePoint($1, $2)) * $6)
      ) as weighted_score

    FROM "Event"
    WHERE ST_DWithin(location, ST_MakePoint($1, $2), 50000) -- Only events within 50km
    ORDER BY weighted_score DESC
    LIMIT 20;
  `, userLon, userLat, weights.density, userInterests, weights.overlap, weights.distance);
}
```

