### 1. The Database Schema (Prisma)

The core of an IMS is the relationship between Products, SKUs, and Warehouses. We use a "Junction Table" (`Stock`) to track quantities of a specific SKU in a specific Warehouse.

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Product {
  id          String   @id @default(cuid())
  name        String
  description String?
  category    String
  variants    Sku[]    @relation("ProductToSku")
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt
}

model Sku {
  id         String   @id @default(cuid())
  code       String   @unique // e.g., "TSHIRT-BLUE-L"
  productId  String
  product    Product  @relation("ProductToSku", fields: [productId], references: [id])

  // Variant Attributes
  color      String?
  size       String?
  material   String?
  price      Decimal  @db.Decimal(10, 2)

  stocks     Stock[]
  createdAt  DateTime @default(now())
}

model Warehouse {
  id        String   @id @default(cuid())
  name      String
  location  String   // e.g., "Singapore", "Berlin"
  region    String   // e.g., "APAC", "EMEA"
  stocks    Stock[]
}

model Stock {
  id          String    @id @default(cuid())
  skuId       String
  warehouseId String
  quantity    Int       @default(0)

  sku         Sku       @relation(fields: [skuId], references: [id])
  warehouse   Warehouse @relation(fields: [warehouseId], references: [id])

  @@unique([skuId, warehouseId]) // One entry per SKU per Warehouse
}

model InventoryLog {
  id          String   @id @default(cuid())
  skuId       String
  warehouseId String
  change      Int      // Positive for restock, negative for sale
  type        String   // "SALE", "RESTOCK", "TRANSFER", "ADJUSTMENT"
  createdAt   DateTime @default(now())
}
