### 2. The Business Logic: Stock Transfers

In a global system, transferring stock between warehouses is a common operation. This must be an **atomic transaction** to prevent "ghost" inventory.

```typescript
// app/api/inventory/transfer/route.ts
import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  const { skuId, fromWarehouseId, toWarehouseId, quantity } = await req.json();

  try {
    const result = await prisma.$transaction(async (tx) => {
      // 1. Deduct from source
      const sourceStock = await tx.stock.update({
        where: { skuId_warehouseId: { skuId, warehouseId: fromWarehouseId } },
        data: { quantity: { decrement: quantity } },
      });

      if (sourceStock.quantity < 0) {
        throw new Error("Insufficient stock in source warehouse");
      }

      // 2. Add to destination
      const destStock = await tx.stock.upsert({
        where: { skuId_warehouseId: { skuId, warehouseId: toWarehouseId } },
        update: { quantity: { increment: quantity } },
        create: { skuId, warehouseId: toWarehouseId, quantity },
      });

      // 3. Log the movement
      await tx.inventoryLog.create({
        data: { skuId, warehouseId: toWarehouseId, change: quantity, type: "TRANSFER" },
      });

      return { sourceStock, destStock };
    });

    return NextResponse.json(result);
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 400 });
  }
}
```

