### 3. Core Business Logic: Atomic Stock Updates

In a global system, we must prevent "Race Conditions" (two people buying the last item simultaneously). We use a **Database Transaction**.

```typescript
// lib/actions/inventory.ts
import { prisma } from "@/lib/prisma";

export async function adjustStock(
  skuId: string, 
  warehouseId: string, 
  amount: number,
  type: "SALE" | "RESTOCK" | "TRANSFER"
) {
  return await prisma.$transaction(async (tx) => {
    // 1. Check current stock
    const stock = await tx.stockLevel.findUnique({
      where: { skuId_warehouseId: { skuId, warehouseId } },
    });

    if (!stock && amount < 0) throw new Error("No inventory record found.");

    const currentQty = stock?.quantity || 0;
    if (currentQty + amount < 0) throw new Error("Insufficient stock.");

    // 2. Update or Create StockLevel
    const updatedStock = await tx.stockLevel.upsert({
      where: { skuId_warehouseId: { skuId, warehouseId } },
      update: { quantity: { increment: amount } },
      create: { skuId, warehouseId, quantity: amount },
    });

    // 3. Log the movement for audit trails
    await tx.stockLog.create({
      data: { skuId, warehouseId, change: amount, type },
    });

    return updatedStock;
  });
}
```

