### 3. Implementation: Prevention of Race Conditions

When dealing with global warehouses, "Double Selling" is the biggest risk. We must use **Database Transactions**.

```typescript
// lib/inventory-service.ts
import { prisma } from "./prisma";

export async function adjustStock(
  skuId: string, 
  warehouseId: string, 
  amount: number // Negative for sales, positive for restock
) {
  return await prisma.$transaction(async (tx) => {
    // 1. Get current stock with a row-level lock
    const inventory = await tx.$queryRaw<any[]>`
      SELECT * FROM "Inventory" 
      WHERE "skuId" = ${skuId} AND "warehouseId" = ${warehouseId}
      FOR UPDATE
    `;

    const currentQty = inventory[0]?.quantity || 0;

    // 2. Check for sufficient funds if it's a sale
    if (amount < 0 && currentQty < Math.abs(amount)) {
      throw new Error("Insufficient stock in this warehouse");
    }

    // 3. Update inventory
    const updated = await tx.inventory.upsert({
      where: { skuId_warehouseId: { skuId, warehouseId } },
      update: { quantity: { increment: amount } },
      create: { skuId, warehouseId, quantity: amount },
    });

    // 4. Log the movement for audit trails
    await tx.stockMovement.create({
      data: {
        skuId,
        quantity: amount,
        type: amount > 0 ? "INBOUND" : "OUTBOUND",
        toWhId: amount > 0 ? warehouseId : null,
        fromWhId: amount < 0 ? warehouseId : null,
      },
    });

    return updated;
  });
}
```

