### 2. The Public API (The "Magic" Logic)

The requirement states that posts must appear automatically. We achieve this by adding a filter to the `where` clause: `publishedAt: { lte: new Date() }`.

```typescript
// app/api/posts/public/route.ts
import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  try {
    const now = new Date();

    const posts = await prisma.post.findMany({
      where: {
        status: "PUBLISHED",
        // Only fetch posts where the publish date is Less Than or Equal to Now
        publishedAt: {
          lte: now,
        },
      },
      orderBy: {
        publishedAt: "desc",
      },
    });

    return NextResponse.json(posts);
  } catch (error) {
    return NextResponse.json({ error: "Failed to fetch posts" }, { status: 500 });
  }
}
```

