### 3. Implementation: The API Logic

#### A. Post Creation (Author Perspective)
When an author schedules a post, they provide a future date.

```typescript
import { PrismaClient, PostStatus } from '@prisma/client';
import { z } from 'zod';

const prisma = new PrismaClient();

const CreatePostSchema = z.object({
  title: z.string().min(1),
  content: z.string(),
  // Ensure the date is in the future if they are scheduling
  publishedAt: z.string().datetime().optional(), 
  status: z.nativeEnum(PostStatus)
});

export async function createPost(data: unknown) {
  const validated = CreatePostSchema.parse(data);

  return await prisma.post.create({
    data: {
      ...validated,
      // If status is PUBLISHED but no date provided, publish immediately
      publishedAt: validated.publishedAt || new Date().toISOString(),
    },
  });
}
```

#### B. The Public API (Auto-Serving Logic)
This is the core requirement. We filter posts where the `status` is `PUBLISHED` **and** the `publishedAt` date is less than or equal to the current server time.

```typescript
export async function getPublicPosts() {
  const now = new Date();

  return await prisma.post.findMany({
    where: {
      status: PostStatus.PUBLISHED,
      publishedAt: {
        lte: now, // "Less than or equal to now"
      },
    },
    orderBy: {
      publishedAt: 'desc',
    },
  });
}

export async function getPublicPostById(id: string) {
  const now = new Date();

  const post = await prisma.post.findFirst({
    where: {
      id,
      status: PostStatus.PUBLISHED,
      publishedAt: {
        lte: now,
      },
    },
  });

  if (!post) {
    throw new Error("Post not found or not yet published");
  }

  return post;
}
```

