### 1. Database Schema (Prisma)

This schema handles the relationships between users, recipes, ingredients, and variations.

```prisma
// prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id         String     @id @default(uuid())
  username   String     @unique
  email      String     @unique
  recipes    Recipe[]   @relation("UserRecipes")
  variations Variation[]
}

model Recipe {
  id              String             @id @default(uuid())
  title           String
  instructions    String             // Stored as Markdown or Text
  nutritionalData Json               // { calories: 500, protein: '20g', ... }
  createdAt       DateTime           @default(now())

  authorId        String
  author          User               @relation("UserRecipes", fields: [authorId], references: [id])

  ingredients     RecipeIngredient[]
  variations      Variation[]
}

model Ingredient {
  id      String             @id @default(uuid())
  name    String             @unique
  recipes RecipeIngredient[]
}

model RecipeIngredient {
  recipeId     String
  ingredientId String
  quantity     String   // e.g., "200g" or "2 cups"

  recipe       Recipe     @relation(fields: [recipeId], references: [id])
  ingredient   Ingredient @relation(fields: [ingredientId], references: [id])

  @@id([recipeId, ingredientId])
}

model Variation {
  id              String   @id @default(uuid())
  parentRecipeId  String
  authorId        String
  description     String   // What was changed?
  newInstructions String?
  createdAt       DateTime @default(now())

  parentRecipe    Recipe   @relation(fields: [parentRecipeId], references: [id])
  author          User     @relation(fields: [authorId], references: [id])
}
```

