### 2. The Search Logic (Service)

The core requirement is searching by **Username** or **Ingredient**. We'll use Prisma's deep filtering.

```typescript
// src/recipes/recipes.service.ts

import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class RecipesService {
  constructor(private prisma: PrismaService) {}

  async searchRecipes(query: string) {
    return this.prisma.recipe.findMany({
      where: {
        OR: [
          // Search by Author Name
          {
            author: {
              username: { contains: query, mode: 'insensitive' }
            }
          },
          // Search by Ingredient Name
          {
            ingredients: {
              some: {
                ingredient: {
                  name: { contains: query, mode: 'insensitive' }
                }
              }
            }
          },
          // Search by Title
          {
            title: { contains: query, mode: 'insensitive' }
          }
        ]
      },
      include: {
        author: true,
        ingredients: {
          include: { ingredient: true }
        },
        variations: true
      }
    });
  }

  async createVariation(recipeId: string, userId: string, data: any) {
    return this.prisma.variation.create({
      data: {
        parentRecipeId: recipeId,
        authorId: userId,
        description: data.description,
        newInstructions: data.newInstructions,
      }
    });
  }
}
```

