```typescript
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class RecipesService {
  constructor(private prisma: PrismaService) {}

  async createRecipe(data: any) {
    return this.prisma.recipe.create({ data });
  }

  async createVariation(recipeId: string, data: any) {
    return this.prisma.variation.create({
      data: {
        ...data,
        recipeId,
      },
    });
  }

  async searchRecipes(query: string) {
    return this.prisma.recipe.findMany({
      where: {
        OR: [
          // Search by User Name
          {
            author: {
              name: { contains: query, mode: 'insensitive' }
            }
          },
          // Search by Ingredients
          {
            ingredients: {
              hasSome: [query] // Exact match for an item in the array
            }
          },
          // Partial match for ingredients
          {
            ingredients: {
              path: [],
              array_contains: query // Hypothetical: PostgreSQL FTS is better here
            }
          }
        ]
      },
      include: {
        author: true,
        variations: {
          include: { author: true }
        }
      }
    });
  }
}
