### 4. Implementation

#### A. The API Route (Backend)
This Next.js API route handles the logic. I'm using Prisma's `groupBy` and `findMany` to ensure we get full user objects.

```typescript
// app/api/matches/route.ts
import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(request: Request) {
  // In a real app, get this from your Auth session (e.g., NextAuth)
  const currentUserId = "user_123"; 

  try {
    // 1. Get current user's hobbies
    const user = await prisma.user.findUnique({
      where: { id: currentUserId },
      include: { hobbies: true }
    });

    if (!user || user.hobbies.length < 3) {
      return NextResponse.json({ matches: [], message: "Add more hobbies to find matches!" });
    }

    const hobbyIds = user.hobbies.map(h => h.id);

    // 2. Find users sharing at least 3 hobbies
    // We use a raw query or Prisma's specific filters for performance
    const matchingUsers = await prisma.user.findMany({
      where: {
        id: { not: currentUserId }, // Don't match self
        hobbies: {
          some: {
            id: { in: hobbyIds }
          }
        }
      },
      include: {
        hobbies: {
          where: { id: { in: hobbyIds } } // Only include the shared hobbies in the response
        }
      },
      // We filter the count in the application logic or use a raw SQL for massive datasets
    });

    // 3. Filter for at least 3 matches
    const highQualityMatches = matchingUsers.filter(
      u => u.hobbies.length >= 3
    ).sort((a, b) => b.hobbies.length - a.hobbies.length);

    return NextResponse.json(highQualityMatches);
  } catch (error) {
    return NextResponse.json({ error: "Failed to fetch matches" }, { status: 500 });
  }
}
```

