### 2. The Backend Implementation (NestJS)

#### The Logic (Service Layer)
The core logic resides in a single SQL query. We want to find users who share hobbies with User A, excluding User A themselves, and filter for those who have a count of shared items $\ge 3$.

```typescript
// users.service.ts
import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { User } from './entities/user.entity';

@Injectable()
export class UsersService {
  constructor(
    @InjectRepository(User)
    private userRepository: Repository<User>,
  ) {}

  async findMatches(currentUserId: number) {
    /**
     * SQL Logic:
     * 1. Find all hobby IDs associated with the current user.
     * 2. Find all rows in user_hobbies matching those hobby IDs.
     * 3. Group by user_id and count matches.
     * 4. Filter for counts >= 3.
     */
    return this.userRepository.createQueryBuilder('user')
      .innerJoin('user.hobbies', 'hobby')
      .where((qb) => {
        const subQuery = qb
          .subQuery()
          .select('uh.hobbyId')
          .from('user_hobbies', 'uh')
          .where('uh.userId = :id', { id: currentUserId })
          .getQuery();
        return 'hobby.id IN ' + subQuery;
      })
      .andWhere('user.id != :id', { id: currentUserId })
      .groupBy('user.id')
      .having('COUNT(hobby.id) >= :minCommon', { minCommon: 3 })
      .select(['user.id', 'user.username'])
      .addSelect('COUNT(hobby.id)', 'shared_count')
      .orderBy('shared_count', 'DESC')
      .getRawMany();
  }
}
```

