### 2. The Matching Logic (The "Magic" Query)

To find users with at least 3 shared hobbies, we follow this logic:
1. Identify the hobby IDs of the current user.
2. Join the `user_hobbies` table with itself.
3. Filter out the current user.
4. Group by the `other_user_id`.
5. Use a `HAVING` clause to ensure the count of shared IDs is $\ge 3$.

```typescript
// src/lib/match-service.ts
import { db } from "@/db";
import { userHobbies, users, hobbies } from "@/db/schema";
import { eq, inArray, and, ne, sql, desc } from "drizzle-orm";

export async function getHobbyMatches(currentUserId: number) {
  // 1. Get the current user's hobby IDs
  const myHobbies = await db
    .select({ hobbyId: userHobbies.hobbyId })
    .from(userHobbies)
    .where(eq(userHobbies.userId, currentUserId));

  const hobbyIds = myHobbies.map((h) => h.hobbyId);

  if (hobbyIds.length < 3) return [];

  // 2. Find other users sharing at least 3
  const matches = await db
    .select({
      id: users.id,
      name: users.name,
      sharedCount: sql<number>`count(${userHobbies.hobbyId})::int`,
      // Subquery or aggregation to get the names of shared hobbies
      sharedHobbies: sql<string[]>`array_agg(${hobbies.name})`
    })
    .from(userHobbies)
    .innerJoin(users, eq(users.id, userHobbies.userId))
    .innerJoin(hobbies, eq(hobbies.id, userHobbies.hobbyId))
    .where(
      and(
        ne(userHobbies.userId, currentUserId), // Don't match myself
        inArray(userHobbies.hobbyId, hobbyIds) // Only hobbies I also have
      )
    )
    .groupBy(users.id)
    .having(sql`count(${userHobbies.hobbyId}) >= 3`)
    .orderBy(desc(sql`count(${userHobbies.hobbyId})`))
    .limit(10);

  return matches;
}
```

