### 1. Database Schema (Prisma)

The "Variable Attributes" problem is solved using a `JSONB` column. This allows us to keep the core product data (SKU, price) relational while letting the specific attributes (CPU speed for laptops, Fabric for shirts) remain flexible.

```prisma
// prisma/schema.prisma

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Category {
  id        String     @id @default(uuid())
  name      String
  slug      String     @unique
  parentId  String?
  parent    Category?  @relation("CategoryToCategory", fields: [parentId], references: [id])
  children  Category[] @relation("CategoryToCategory")
  products  Product[]
  createdAt DateTime   @default(now())
  updatedAt DateTime   @updatedAt
}

model Product {
  id          String   @id @default(uuid())
  sku         String   @unique
  name        String
  description String?
  price       Decimal  @db.Decimal(12, 2)

  // The magic for variable attributes:
  // Stores data like {"color": "red", "ram_gb": 16}
  attributes  Json     @default("{}")

  categoryId  String
  category    Category @relation(fields: [categoryId], references: [id])

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([attributes]) // GIN index recommended for JSONB performance
}
```

