### 2. Implementation: Logic Layer

#### Product Service (Handling JSONB)
Filtering by variable attributes requires specific handling in PostgreSQL.

```typescript
// src/products/products.service.ts
import { Injectable } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { Prisma } from '@prisma/client';

@Injectable()
export class ProductsService {
  constructor(private prisma: PrismaService) {}

  async findAll(params: {
    categorySlug?: string;
    attributes?: Record<string, any>;
  }) {
    const { categorySlug, attributes } = params;

    const where: Prisma.ProductWhereInput = {};

    if (categorySlug) {
      where.category = { slug: categorySlug };
    }

    // Dynamic filtering on the JSONB attributes column
    if (attributes) {
      where.attributes = {
        path: [],
        equals: attributes, // Simplified; in production use "contains" for subset matching
      };
    }

    return this.prisma.product.findMany({
      where,
      include: { category: true },
    });
  }

  async create(data: Prisma.ProductCreateInput) {
    return this.prisma.product.create({ data });
  }
}
```

#### Category Service (Handling Recursion)
To fetch a full category tree efficiently, we use a recursive include or a flat-to-tree transformation.

```typescript
// src/categories/categories.service.ts
@Injectable()
export class CategoriesService {
  constructor(private prisma: PrismaService) {}

  async getTree() {
    // Fetch all categories
    const all = await this.prisma.category.findMany();

    // Transform flat list to nested tree
    return this.listToTree(all);
  }

  private listToTree(list: any[], parentId: string | null = null) {
    return list
      .filter(item => item.parentId === parentId)
      .map(item => ({
        ...item,
        children: this.listToTree(list, item.id),
      }));
  }
}
```

