  @ApiProperty() @IsNumber() price: number;
  @ApiProperty() @IsUUID() categoryId: string;

  @ApiProperty({ example: { color: 'blue', size: 'L' } })
  @IsObject()
  attributes: Record<string, any>;
}
```

```typescript
