### 1. The Database Schema (`prisma/schema.prisma`)

We use a self-referencing relation for categories and a `jsonb` field for attributes.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Category {
  id        String     @id @default(uuid())
  name      String
  slug      String     @unique
  parentId  String?
  parent    Category?  @relation("CategoryToCategory", fields: [parentId], references: [id])
  children  Category[] @relation("CategoryToCategory")
  products  Product[]
  createdAt DateTime   @default(now())
}

model Product {
  id          String   @id @default(uuid())
  name        String
  sku         String   @unique
  description String?
  price       Decimal  @db.Decimal(10, 2)

  // Variable attributes stored as JSONB
  // Example: { "color": "red", "size": "XL", "material": "cotton" }
  attributes  Json     @default("{}")

  categoryId  String
  category    Category @relation(fields: [categoryId], references: [id])

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

  @@index([attributes], type: Gin) // Index for fast attribute searching
}
```

