### 2. Implementation: The Fastify Server

We'll focus on the two hardest parts: fetching the category tree and filtering products by dynamic attributes.

#### `src/app.ts` - Setup & Validation
```typescript
import Fastify from 'fastify';
import { PrismaClient } from '@prisma/client';
import { z } from 'zod';

const prisma = new PrismaClient();
const app = Fastify({ logger: true });

// Type definitions for the Product Body
const ProductSchema = z.object({
  name: z.string(),
  sku: z.string(),
  price: z.number(),
  categoryId: z.string(),
  attributes: z.record(z.any()), // This handles the variable attributes
});

/**
 * 1. GET CATEGORY TREE
 * Uses Prisma to fetch categories and nested children
 */
app.get('/categories/tree', async (request, reply) => {
  const categories = await prisma.category.findMany({
    where: { parentId: null },
    include: {
      children: {
        include: { children: true } // Supports 3 levels deep; for infinite, use a recursive function
      }
    }
  });
  return categories;
});

/**
 * 2. SEARCH PRODUCTS
 * Demonstrates filtering by both category and variable attributes
 */
app.get('/products', async (request, reply) => {
  const { categoryId, color, size } = request.query as any;

  const products = await prisma.product.findMany({
    where: {
      AND: [
        categoryId ? { categoryId } : {},
        // Postgres JSONB query: find products where attributes contains specific keys/values
        color ? { attributes: { path: ['color'], equals: color } } : {},
        size ? { attributes: { path: ['size'], equals: size } } : {},
      ]
    },
    include: { category: true }
  });

  return products;
});

/**
 * 3. CREATE PRODUCT
 */
app.post('/products', async (request, reply) => {
  const data = ProductSchema.parse(request.body);
  const product = await prisma.product.create({ data });
  return product;
});

const start = async () => {
  try {
    await app.listen({ port: 3000 });
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
};
start();
```

