### 2. The Interaction Service

This service handles saving data and the logic for deleting old records.

```typescript
// src/services/interaction.service.ts

import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export class InteractionService {
  /**
   * Saves a new AI interaction to the database
   */
  static async saveInteraction(userId: string, prompt: string, response: string) {
    return prisma.interaction.create({
      data: { userId, prompt, response },
    });
  }

  /**
   * Deletes all records older than 30 days
   * This is the core "Purge" logic
   */
  static async purgeOldInteractions() {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const deleted = await prisma.interaction.deleteMany({
      where: {
        createdAt: {
          lt: thirtyDaysAgo,
        },
      },
    });

    console.log(`[Cleanup] Successfully purged ${deleted.count} old interactions.`);
    return deleted.count;
  }
}
```

