### 3. The Purge Logic (API Route)

Create a dedicated endpoint for the cleanup. We protect this endpoint using an Authorization header (CRON_SECRET) to prevent unauthorized users from triggering a mass deletion.

**File:** `app/api/cron/purge-interactions/route.ts`

```typescript
import { NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function GET(request: Request) {
  // 1. Verify Authorization (Vercel automatically sends this secret)
  const authHeader = request.headers.get('authorization');
  if (authHeader !== `Bearer ${process.env.CRON_SECRET}`) {
    return new Response('Unauthorized', { status: 401 });
  }

  try {
    // 2. Calculate the "Cutoff Date" (30 days ago)
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    // 3. Perform the deletion
    const result = await prisma.interaction.deleteMany({
      where: {
        createdAt: {
          lt: thirtyDaysAgo,
        },
      },
    });

    return NextResponse.json({
      success: true,
      deletedCount: result.count,
      cutoffDate: thirtyDaysAgo.toISOString(),
    });
  } catch (error) {
    console.error('Purge Job Failed:', error);
    return NextResponse.json({ success: false, error: 'Internal Server Error' }, { status: 500 });
  }
}
```

