Run this in your Supabase SQL Editor. This sets up the PostGIS extension and the tables.

```sql
-- Enable PostGIS extension for spatial queries
create extension if not exists postgis;

-- Pins Table
create table pins (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default now(),
  user_id uuid references auth.users not null,
  message text,
  image_url text,
  -- 'geography' type allows for distance measurements in meters
  location geography(POINT) not null
);

-- Comments Table
create table comments (
  id uuid default gen_random_uuid() primary key,
  pin_id uuid references pins on delete cascade not null,
  user_id uuid references auth.users not null,
  content text not null,
  created_at timestamp with time zone default now()
);

-- Spatial function to find pins within X meters
create or replace function get_pins_nearby(user_lat float, user_lng float, radius_meters float)
returns setof pins as $$
begin
  return query
  select * from pins
  where ST_DWithin(
    location,
    ST_SetSRID(ST_MakePoint(user_lng, user_lat), 4326)::geography,
    radius_meters
  );
end;
$$ language plpgsql;
