### 1. The Database Schema (`schema.prisma`)

This schema supports the "Specific Item Group" promotion requirement by linking promo codes to categories.

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model Product {
  id          String   @id @default(cuid())
  name        String
  price       Decimal
  categoryId  String
  category    Category @relation(fields: [categoryId], references: [id])
  cartItems   CartItem[]
}

model Category {
  id         String      @id @default(cuid())
  name       String      @unique
  products   Product[]
  promoCodes PromoCode[]
}

model Cart {
  id        String     @id @default(cuid())
  userId    String     @unique // Linked to Clerk User ID
  items     CartItem[]
  updatedAt DateTime   @updatedAt
}

model CartItem {
  id        String  @id @default(cuid())
