### 2. The Promotion Engine Logic

The core logic resides in a utility function that calculates the discount based on the specific items in the cart that match the promo code's category.

```typescript
// lib/calculations.ts
import { Product, PromoCode } from "@prisma/client";

export type CartItemWithProduct = {
  product: Product;
  quantity: number;
};

export function calculateTotals(items: CartItemWithProduct[], promo: PromoCode | null) {
  const subtotal = items.reduce((acc, item) => {
    return acc + Number(item.product.price) * item.quantity;
  }, 0);

  let discount = 0;

  if (promo) {
    // Check if promo is restricted to a category
    if (promo.categoryId) {
      const eligibleItems = items.filter(
        (item) => item.product.categoryId === promo.categoryId
      );

      const eligibleSum = eligibleItems.reduce((acc, item) => {
        return acc + Number(item.product.price) * item.quantity;
      }, 0);

      discount = eligibleSum * (promo.discountPercent / 100);
    } else {
      // Universal discount
      discount = subtotal * (promo.discountPercent / 100);
    }
  }

  return {
    subtotal,
    discount,
    total: subtotal - discount,
  };
}
```

