### 3. Server Action for Persistence

Next.js Server Actions allow us to update the database directly from the UI. This ensures that when a user adds an item on their desktop, it's immediately available on their mobile app.

```typescript
// app/actions/cart.ts
'use server'

import { db } from "@/lib/db";
import { auth } from "@clerk/nextjs";
import { revalidatePath } from "next/cache";

export async function addToCart(productId: string) {
  const { userId } = auth();
  if (!userId) throw new Error("Unauthorized");

  // 1. Find or create the cart for this user
  let cart = await db.cart.findUnique({
    where: { userId },
  });

  if (!cart) {
    cart = await db.cart.create({ data: { userId } });
  }

  // 2. Check if item exists, increment quantity if it does
  const existingItem = await db.cartItem.findFirst({
    where: { cartId: cart.id, productId },
  });

  if (existingItem) {
    await db.cartItem.update({
      where: { id: existingItem.id },
      data: { quantity: existingItem.quantity + 1 },
    });
  } else {
    await db.cartItem.create({
      data: { cartId: cart.id, productId, quantity: 1 },
    });
  }

  revalidatePath('/cart');
}
```

