### 2. The Promo Logic (Business Logic)

A core requirement is applying codes to specific groups. Here is the logic we will use in our API and Frontend.

```typescript
// src/lib/promoLogic.ts

export type CartWithItems = {
  items: {
    product: { price: number; category: string };
    quantity: number;
  }[];
};

export function calculateDiscount(cart: CartWithItems, promo: { code: string, discountPercent: number, targetCategory: string | null }) {
  let totalDiscount = 0;

  cart.items.forEach((item) => {
    const itemTotal = item.product.price * item.quantity;

    // Apply if global (targetCategory is null) OR matches category
    if (!promo.targetCategory || promo.targetCategory === item.product.category) {
      totalDiscount += (itemTotal * (promo.discountPercent / 100));
    }
  });

  return totalDiscount;
}
```

