### 3. API Routes for Cart Management

We'll use a `sessionId` stored in an HTTP-only cookie to identify the user's cart across sessions without requiring a full login system.

```typescript
// src/app/api/cart/route.ts
import { prisma } from "@/lib/db";
import { cookies } from "next/headers";
import { NextResponse } from "next/server";

async function getOrCreateCartId() {
  const cookieStore = await cookies();
  let sessionId = cookieStore.get("cart_session")?.value;

  if (!sessionId) {
    sessionId = crypto.randomUUID();
    cookieStore.set("cart_session", sessionId, { httpOnly: true, path: "/" });
  }

  const cart = await prisma.cart.upsert({
    where: { sessionId },
    update: {},
    create: { sessionId },
  });

  return cart.id;
}

export async function POST(req: Request) {
  const { productId, action } = await req.json(); // action: 'add' | 'remove' | 'decrement'
  const cartId = await getOrCreateCartId();

  if (action === 'add') {
    await prisma.cartItem.upsert({
      where: { /* Unique constraint logic here */ id: '...' }, 
      // Simplified for brevity:
      create: { cartId, productId, quantity: 1 },
      update: { quantity: { increment: 1 } }
    });
  }

  return NextResponse.json({ success: true });
}
```

