### 2. The Store (Logic & Persistence)
This is the heart of the app. It handles adding items, calculating totals, and applying category-specific promo codes.

Create `store/useCartStore.ts`:
```typescript
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
  image: string;
}

export interface CartItem extends Product {
  quantity: number;
}

interface PromoCode {
  code: string;
  discount: number; // e.g., 0.2 for 20%
  targetCategory: string | 'all';
}

interface CartState {
  items: CartItem[];
  promoCode: PromoCode | null;
  addItem: (product: Product) => void;
  removeItem: (productId: number) => void;
  updateQuantity: (productId: number, delta: number) => void;
  applyPromo: (code: string) => string | null; // returns error message or null
  clearCart: () => void;
}

const VALID_PROMOS: PromoCode[] = [
  { code: 'TECH20', discount: 0.2, targetCategory: 'Electronics' },
  { code: 'FASHION10', discount: 0.1, targetCategory: 'Apparel' },
  { code: 'SAVE5', discount: 0.05, targetCategory: 'all' },
];

export const useCartStore = create<CartState>()(
  persist(
    (set, get) => ({
      items: [],
      promoCode: null,

      addItem: (product) => {
        const items = get().items;
        const existingItem = items.find((i) => i.id === product.id);
        if (existingItem) {
          set({
            items: items.map((i) =>
              i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i
            ),
          });
        } else {
          set({ items: [...items, { ...product, quantity: 1 }] });
        }
      },

      removeItem: (productId) => {
        set({ items: get().items.filter((i) => i.id !== productId) });
      },

      updateQuantity: (productId, delta) => {
        set({
          items: get().items
            .map((i) =>
              i.id === productId ? { ...i, quantity: Math.max(0, i.quantity + delta) } : i
            )
            .filter((i) => i.quantity > 0),
        });
      },

      applyPromo: (code) => {
        const promo = VALID_PROMOS.find((p) => p.code === code.toUpperCase());
        if (promo) {
          set({ promoCode: promo });
          return null;
        }
        return "Invalid promotional code";
      },

      clearCart: () => set({ items: [], promoCode: null }),
    }),
    { name: 'shopping-cart-storage' } // This key saves data in LocalStorage
  )
);
```

