  const [promoInput, setPromoInput] = useState("");
  const [error, setError] = useState("");

  const subtotal = items.reduce((acc, item) => acc + item.price * item.quantity, 0);

  // Apply discounts based on targetCategory
  const discountTotal = items.reduce((acc, item) => {
    if (promoCode && (promoCode.targetCategory === 'all' || promoCode.targetCategory === item.category)) {
      return acc + (item.price * item.quantity * promoCode.discount);
    }
    return acc;
  }, 0);

  const handlePromoApply = () => {
