// src/models/ContentType.ts
import { Schema, model } from 'mongoose';

const ContentTypeSchema = new Schema({
  name: { type: String, required: true, unique: true }, // e.g., "Blog Post"
  slug: { type: String, required: true, unique: true }, // e.g., "blog-post"
  fields: [{
