#### The Dynamic Content Entry
This model stores the actual content based on the types defined above.

```typescript
// src/models/ContentEntry.ts
import { Schema, model } from 'mongoose';

const ContentEntrySchema = new Schema({
  contentTypeId: { type: Schema.Types.ObjectId, ref: 'ContentType', required: true },
  data: { type: Map, of: Schema.Types.Mixed }, // Flexible JSON payload
  status: { type: String, enum: ['draft', 'published'], default: 'draft' },
  author: { type: Schema.Types.ObjectId, ref: 'User' }
}, { timestamps: true, strict: false }); // strict: false allows dynamic fields

