#### Core Logic: Content Controller
This handles creating content entries while validating them against the dynamic schema.

```typescript
// src/controllers/content.controller.ts
import { Request, Response } from 'express';
import { ContentType } from '../models/ContentType';
import { ContentEntry } from '../models/ContentEntry';

export const createEntry = async (req: Request, res: Response) => {
  try {
    const { contentTypeSlug } = req.params;
    const contentData = req.body;

    // 1. Find the definition
    const typeDef = await ContentType.findOne({ slug: contentTypeSlug });
    if (!typeDef) return res.status(404).json({ error: "Type not found" });

    // 2. Simple validation (In production, use a library like Zod or Joi)
    for (const field of typeDef.fields) {
      if (field.required && !contentData[field.name]) {
        return res.status(400).json({ error: `${field.name} is required` });
      }
    }

    // 3. Save Entry
    const entry = new ContentEntry({
      contentTypeId: typeDef._id,
      data: contentData,
      author: (req as any).user.id // From Auth Middleware
    });

    await entry.save();
    res.status(201).json(entry);
  } catch (err: any) {
    res.status(500).json({ error: err.message });
  }
};
```

