### 2. Core Implementation: Content Service

This service handles the dynamic creation of content while ensuring the data matches the defined schema.

```typescript
// src/content/content.service.ts
import { Injectable, BadRequestException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';

@Injectable()
export class ContentService {
  constructor(private prisma: PrismaService) {}

  async createItem(contentTypeSlug: string, data: any) {
    // 1. Fetch the definition
    const type = await this.prisma.contentType.findUnique({
      where: { slug: contentTypeSlug },
    });

    if (!type) throw new BadRequestException('Invalid content type');

    // 2. Simple Validation Logic
    // In production, use a library like 'ajv' to validate 'data' against 'type.fields'
    this.validateData(type.fields, data);

    // 3. Persist
    return this.prisma.contentItem.create({
      data: {
        contentTypeId: type.id,
        data: data,
        status: 'published',
      },
    });
  }

  private validateData(schema: any, data: any) {
    // Basic logic: Ensure required fields in schema exist in data
    const schemaFields = schema as Array<{ name: string; type: string }>;
    for (const field of schemaFields) {
      if (!data[field.name]) {
        throw new BadRequestException(`Missing required field: ${field.name}`);
      }
    }
  }

  async getItemsByType(slug: string) {
    return this.prisma.contentItem.findMany({
      where: { contentType: { slug } },
      orderBy: { createdAt: 'desc' },
    });
  }
}
```

